{
  "name": "Industrial Maintenance Failure Analysis Pro",
  "description": "A high-performance web application for industrial failure analysis using PDCA, 5W2H, 5 Whys, and Ishikawa diagrams, featuring AI-powered insights."
}

export type Status = 'Aberta' | 'Em andamento' | 'Concluída';
export type FailureFrequency = 'Eventual' | 'Recorrente' | 'Crônica';
export type ActionType = 'Corretiva' | 'Preventiva' | 'Melhoria';

export interface Action {
  id: string;
  description: string;
  type: ActionType;
  responsible: string;
  dueDate: string;
  status: Status;
}

export interface IshikawaCategory {
  causes: string[];
}

export interface Ishikawa {
  machine: IshikawaCategory;
  method: IshikawaCategory;
  material: IshikawaCategory;
  manpower: IshikawaCategory;
  measurement: IshikawaCategory;
  environment: IshikawaCategory;
}

export interface Analysis {
  id: string;
  // Step 1
  area: string;
  equipment: string;
  tag: string;
  failureDate: string;
  shift: string;
  responsible: string;
  description: string;
  // Step 2 (5W1H)
  what: string;
  where: string;
  when: string;
  who: string;
  howMuch: string;
  how: string;
  // Step 3
  symptom: string;
  condition: string;
  history: string;
  frequency: FailureFrequency;
  // Step 4 (5 Whys)
  whys: string[];
  rootCause: string;
  // Step 5 (Ishikawa)
  ishikawa: Ishikawa;
  // Step 6 (Actions)
  actions: Action[];
  // Step 7
  reoccurred: boolean | null;
  effectivenessEvidence: string;
  needsRevison: boolean;
  needsTraining: boolean;
  // Meta
  summary?: string;
}

export enum StepId {
  IDENTIFICATION = 0,
  W5H1 = 1,
  DETAILS = 2,
  FIVE_WHYS = 3,
  ISHIKAWA = 4,
  ACTIONS = 5,
  VERIFICATION = 6,
  DASHBOARD = 7
}

import React from 'react';
import { StepId } from './types';

export const STEPS = [
  { id: StepId.IDENTIFICATION, label: 'Identificação', icon: <i className="fas fa-id-card"></i> },
  { id: StepId.W5H1, label: '5W1H', icon: <i className="fas fa-question-circle"></i> },
  { id: StepId.DETAILS, label: 'Detalhamento', icon: <i className="fas fa-search-plus"></i> },
  { id: StepId.FIVE_WHYS, label: '5 Porquês', icon: <i className="fas fa-list-ol"></i> },
  { id: StepId.ISHIKAWA, label: 'Ishikawa', icon: <i className="fas fa-fish"></i> },
  { id: StepId.ACTIONS, label: 'Plano de Ação', icon: <i className="fas fa-tasks"></i> },
  { id: StepId.VERIFICATION, label: 'Verificação', icon: <i className="fas fa-check-double"></i> }
];

export const TIPS = {
  what: "O que aconteceu exatamente? Seja específico sobre a falha técnica.",
  where: "Onde no equipamento ocorreu a falha? (Ex: Rolamento do motor principal)",
  when: "Qual o momento exato? Início do turno, durante a rampa de carga?",
  howMuch: "Qual o impacto em horas paradas, custo de peças ou perda de produção?",
  how: "Como a falha foi detectada? Alarme, ruído, inspeção visual, parada súbita?",
  why: "Tente aprofundar a cada nível. Evite respostas como 'quebrou' sem explicar a causa física imediata."
};

export const ISHIKAWA_QUESTIONS = {
  machine: "O equipamento estava em dia com a manutenção? Houve desgaste natural?",
  method: "O procedimento de operação foi seguido? Existe um padrão escrito?",
  material: "A matéria-prima estava conforme? As peças de reposição eram originais?",
  manpower: "A equipe está treinada? Houve falta de atenção ou cansaço?",
  measurement: "Os sensores estão calibrados? A leitura dos instrumentos é confiável?",
  environment: "A temperatura, umidade ou iluminação afetaram o desempenho?"
};

import { GoogleGenAI, Type } from "@google/genai";
import { Analysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function generateSummary(analysis: Analysis): Promise<string> {
  const model = 'gemini-3-flash-preview';
  const prompt = `
    Como um especialista em confiabilidade industrial, analise os seguintes dados de uma falha e gere um resumo executivo técnico e conciso (máximo 150 palavras).
    Destaque a causa raiz e a ação principal recomendada.

    DADOS:
    Equipamento: ${analysis.equipment} (${analysis.tag})
    Descrição: ${analysis.description}
    5 Porquês: ${analysis.whys.filter(w => w).join(' -> ')}
    Causa Raiz: ${analysis.rootCause}
    Ishikawa (Máquina): ${analysis.ishikawa.machine.causes.join(', ')}
    Plano de Ação: ${analysis.actions.map(a => a.description).join('; ')}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { temperature: 0.7 }
    });
    return response.text || "Não foi possível gerar o resumo automático.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar resumo com IA.";
  }
}

export async function suggestRootCause(analysis: Analysis): Promise<string> {
  const model = 'gemini-3-flash-preview';
  const prompt = `
    Com base na descrição da falha e no detalhamento fornecido, sugira uma possível causa raiz técnica.
    Descrição: ${analysis.description}
    Sintoma: ${analysis.symptom}
    Histórico: ${analysis.history}
    Responda apenas com a sugestão curta da causa raiz.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { temperature: 0.5 }
    });
    return response.text?.trim() || "Análise necessária";
  } catch (error) {
    return "Falha na sugestão automática.";
  }
}

import React from 'react';
import { Analysis, IshikawaCategory } from '../types';
import { ISHIKAWA_QUESTIONS } from '../constants';

interface Props {
  analysis: Analysis;
  updateAnalysis: (data: Partial<Analysis>) => void;
}

const IshikawaComponent: React.FC<Props> = ({ analysis, updateAnalysis }) => {
  const handleCauseChange = (category: keyof Analysis['ishikawa'], index: number, value: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes[index] = value;
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const addCause = (category: keyof Analysis['ishikawa']) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.push("");
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const removeCause = (category: keyof Analysis['ishikawa'], index: number) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.splice(index, 1);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const renderCategory = (category: keyof Analysis['ishikawa'], label: string, icon: string) => (
    <div className="bg-white p-4 rounded-lg shadow-sm border border-slate-200 hover:border-blue-300 transition-colors">
      <div className="flex items-center gap-2 mb-3 border-b pb-2">
        <i className={`fas ${icon} text-blue-600`}></i>
        <h3 className="font-bold text-slate-700 uppercase tracking-tight">{label}</h3>
      </div>
      <p className="text-xs text-slate-500 mb-4 italic">{ISHIKAWA_QUESTIONS[category]}</p>

      <div className="space-y-2">
        {analysis.ishikawa[category].causes.map((cause, idx) => (
          <div key={idx} className="flex gap-2">
            <input
              type="text"
              value={cause}
              onChange={(e) => handleCauseChange(category, idx, e.target.value)}
              placeholder="Digite uma causa..."
              className="flex-1 text-sm border-slate-200 rounded p-2 focus:ring-1 focus:ring-blue-500 outline-none"
            />
            <button 
              onClick={() => removeCause(category, idx)}
              className="text-slate-400 hover:text-red-500"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>
        ))}
        <button 
          onClick={() => addCause(category)}
          className="text-xs text-blue-600 font-medium hover:underline flex items-center gap-1"
        >
          <i className="fas fa-plus"></i> Adicionar Causa
        </button>
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
      {renderCategory('machine', 'Máquina', 'fa-cogs')}
      {renderCategory('method', 'Método', 'fa-book')}
      {renderCategory('manpower', 'Mão de Obra', 'fa-users')}
      {renderCategory('material', 'Material', 'fa-box-open')}
      {renderCategory('measurement', 'Medição', 'fa-ruler-combined')}
      {renderCategory('environment', 'Meio Ambiente', 'fa-leaf')}
    </div>
  );
};

export default IshikawaComponent;

import React, { useState, useEffect, useCallback } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [] },
  method: { causes: [] },
  material: { causes: [] },
  manpower: { causes: [] },
  measurement: { causes: [] },
  environment: { causes: [] },
};

const INITIAL_STATE: Analysis = {
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevison: false,
  needsTraining: false,
};

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(INITIAL_STATE);
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  // Auto-save simulation
  useEffect(() => {
    localStorage.setItem('current_analysis', JSON.stringify(analysis));
  }, [analysis]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const addAction = () => {
    const newAction: Action = {
      id: Date.now().toString(),
      description: '',
      type: 'Corretiva',
      responsible: '',
      dueDate: '',
      status: 'Aberta'
    };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input 
                  type="text" 
                  value={analysis.area}
                  onChange={e => updateAnalysis({ area: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: Refino de Papel"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input 
                  type="text" 
                  value={analysis.equipment}
                  onChange={e => updateAnalysis({ equipment: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: Motor Refinador MP3"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input 
                  type="text" 
                  value={analysis.tag}
                  onChange={e => updateAnalysis({ tag: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: MOT-301-A"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input 
                  type="date" 
                  value={analysis.failureDate}
                  onChange={e => updateAnalysis({ failureDate: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Descrição Breve do Problema</label>
              <textarea 
                value={analysis.description}
                onChange={e => updateAnalysis({ description: e.target.value })}
                className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border h-32" 
                placeholder="Descreva o que houve de forma clara e técnica..."
              />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when },
                { field: 'who', label: 'QUEM identificou?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">{item.label}</label>
                  <textarea 
                    value={(analysis as any)[item.field]}
                    onChange={e => updateAnalysis({ [item.field]: e.target.value })}
                    className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border h-24" 
                  />
                  {item.tip && <p className="text-xs text-slate-400 mt-1 italic">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Sintoma Observado</label>
                <input 
                  type="text" 
                  value={analysis.symptom}
                  onChange={e => updateAnalysis({ symptom: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 border outline-none focus:ring-2 focus:ring-blue-500" 
                  placeholder="Ex: Vibração excessiva, fumaça, desligamento súbito..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Frequência da Falha</label>
                <div className="flex gap-4">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-3 rounded-lg border cursor-pointer transition-all ${analysis.frequency === f ? 'bg-blue-50 border-blue-600 text-blue-700 font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input 
                        type="radio" 
                        className="hidden" 
                        checked={analysis.frequency === f} 
                        onChange={() => updateAnalysis({ frequency: f as any })}
                      />
                      {f}
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Histórico Recente de Intervenções</label>
                <textarea 
                  value={analysis.history}
                  onChange={e => updateAnalysis({ history: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 border outline-none focus:ring-2 focus:ring-blue-500 h-32" 
                  placeholder="Houve manutenção preventiva recente? Houve troca de peças?"
                />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button 
                onClick={handleSuggestCause}
                className="text-xs bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold py-1 px-3 rounded-full border border-slate-300 transition-colors"
              >
