                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Por que aconteceu o nível {idx}?</label>
                    <textarea 
                      value={why}
                      onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }}
                      className="w-full border-slate-200 rounded-lg p-4 border outline-none focus:ring-2 focus:ring-blue-500 h-20 shadow-sm" 
                      placeholder={idx === 0 ? "A falha ocorreu devido a..." : "E por que isso ocorreu?"}
                    />
