              ))}
            </div>
            <div className="mt-8 p-6 bg-blue-600 rounded-xl text-white shadow-xl transform hover:scale-[1.01] transition-transform">
              <label className="block text-sm font-bold uppercase mb-2 opacity-80">Causa Raiz Identificada</label>
              <input 
                type="text" 
                value={analysis.rootCause}
                onChange={e => updateAnalysis({ rootCause: e.target.value })}
                className="w-full bg-white text-slate-900 rounded-lg p-4 font-bold border-none outline-none text-lg shadow-inner" 
                placeholder="A causa fundamental da falha é..."
              />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button 
                onClick={addAction}
                className="bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-2 px-4 rounded-lg flex items-center gap-2 shadow-lg transition-colors"
