                          rows={2}
                          placeholder="Ex: Substituir rolamento por modelo selado"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <select 
                          value={action.type}
                          onChange={e => updateAction(action.id, { type: e.target.value as any })}
                          className="text-xs border rounded p-1 bg-white outline-none"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={action.responsible}
                          onChange={e => updateAction(action.id, { responsible: e.target.value })}
                          className="text-xs border rounded p-1 w-full"
                          placeholder="Nome"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="date" 
                          value={action.dueDate}
                          onChange={e => updateAction(action.id, { dueDate: e.target.value })}
                          className="text-xs border rounded p-1 w-full"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${
                          action.status === 'Concluída' ? 'bg-green-100 text-green-700' :
                          action.status === 'Em andamento' ? 'bg-blue-100 text-blue-700' :
                          'bg-amber-100 text-amber-700'
                        }`}>
                          {action.status}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500">
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                  {analysis.actions.length === 0 && (
                    <tr>
                      <td colSpan={6} className="text-center py-10 text-slate-400 italic text-sm">Nenhuma ação definida ainda. Clique em "Nova Ação" para começar.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Eficácia das Ações</h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-2">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: true })}
                      className={`flex-1 py-3 border rounded-lg font-bold transition-all ${analysis.reoccurred === true ? 'bg-red-50 border-red-600 text-red-600' : 'hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      SIM
                    </button>
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: false })}
                      className={`flex-1 py-3 border rounded-lg font-bold transition-all ${analysis.reoccurred === false ? 'bg-green-50 border-green-600 text-green-600' : 'hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      NÃO
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-slate-600 mb-2">Evidências da Eficácia</label>
                  <textarea 
                    value={analysis.effectivenessEvidence}
                    onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })}
                    className="w-full border rounded-lg p-3 h-24 outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="Ex: Redução de vibração de 8mm/s para 1.2mm/s após troca..."
                  />
                </div>
              </div>

              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Ações de Padronização</h3>
                <div className="space-y-3">
                  <label className="flex items-center gap-3 p-3 border rounded-lg cursor-pointer hover:bg-slate-50 transition-colors">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsRevison}
                      onChange={e => updateAnalysis({ needsRevison: e.target.checked })}
                    />
                    <span className="text-sm text-slate-700">Necessita revisão de procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-3 p-3 border rounded-lg cursor-pointer hover:bg-slate-50 transition-colors">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsTraining}
                      onChange={e => updateAnalysis({ needsTraining: e.target.checked })}
                    />
                    <span className="text-sm text-slate-700">Necessita treinamento da equipe?</span>
                  </label>
                </div>
                <div className="pt-4 border-t">
                  <button 
                    onClick={handleGenerateSummary}
                    disabled={isGeneratingSummary}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2"
                  >
                    {isGeneratingSummary ? (
                      <><i className="fas fa-spinner fa-spin"></i> Gerando Resumo Inteligente...</>
                    ) : (
                      <><i className="fas fa-robot"></i> Gerar Resumo e Finalizar Análise</>
                    )}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-slate-900 text-white p-8 rounded-2xl shadow-2xl mt-12">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-2">
                    <i className="fas fa-file-alt text-blue-400"></i> Resumo Executivo da Falha
                  </h2>
                  <span className="bg-blue-500/20 text-blue-400 text-xs px-2 py-1 rounded uppercase tracking-widest font-bold">Gerado por IA</span>
                </div>
                <p className="text-slate-300 leading-relaxed text-lg">
                  {analysis.summary}
                </p>
                <div className="mt-8 flex gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-print"></i> Imprimir PDF
                  </button>
                  <button className="bg-green-500 hover:bg-green-600 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-share-alt"></i> Compartilhar
                  </button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <i className="fas fa-industry text-xl"></i>
            </div>
            <div>
              <h1 className="font-black text-lg tracking-tight uppercase leading-none">Maintenance Pro</h1>
              <p className="text-[10px] text-blue-400 font-bold tracking-widest uppercase">Reliability Analysis System</p>
            </div>
          </div>
          <nav className="hidden md:flex gap-6 text-sm font-bold uppercase tracking-wider">
            <button 
              onClick={() => setCurrentStep(StepId.IDENTIFICATION)} 
              className={`hover:text-blue-400 transition-colors ${currentStep !== StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Nova Análise
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              className={`hover:text-blue-400 transition-colors ${currentStep === StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Dashboard
            </button>
            <button className="text-slate-400 hover:text-white">Relatórios</button>
          </nav>
          <div className="flex items-center gap-4">
             <div className="hidden lg:block text-right">
                <p className="text-xs font-bold text-slate-300">Eng. Roberto Silva</p>
                <p className="text-[10px] text-slate-500 uppercase">Supervisor de Confiabilidade</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-700 border border-slate-600 flex items-center justify-center overflow-hidden">
                <img src="https://picsum.photos/40/40" alt="Avatar" />
             </div>
          </div>
        </div>
      </header>

      {/* PDCA Progress Bar */}
      {currentStep !== StepId.DASHBOARD && (
        <div className="bg-white border-b sticky top-16 z-40 overflow-x-auto no-scrollbar">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-2 min-w-[800px]">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  className={`flex flex-col items-center gap-1 group relative ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-100 text-green-600 border border-green-200' : 
                    'bg-slate-50 text-slate-400 border border-slate-200'
                  }`}>
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-bold uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                  {currentStep === step.id && (
                    <div className="absolute -bottom-4 w-full h-1 bg-blue-600 rounded-t"></div>
                  )}
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-200' : 'bg-slate-100'}`}></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden min-h-[600px] flex flex-col">
          <div className="p-6 md:p-10 flex-1">
             {renderStepContent()}
          </div>

          {/* Controls */}
          {currentStep !== StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-6 flex justify-between items-center">
              <button 
                onClick={handleBack}
                disabled={currentStep === StepId.IDENTIFICATION}
                className="flex items-center gap-2 text-slate-500 font-bold hover:text-slate-800 disabled:opacity-30 px-4 py-2"
              >
                <i className="fas fa-arrow-left"></i> Voltar
              </button>

              <div className="flex gap-4">
                <button 
                  className="hidden md:flex items-center gap-2 bg-white text-slate-600 border border-slate-200 px-6 py-2 rounded-lg font-bold hover:bg-slate-50 transition-all shadow-sm"
                >
                  <i className="fas fa-save"></i> Salvar Rascunho
                </button>
                {currentStep < StepId.VERIFICATION ? (
                  <button 
                    onClick={handleNext}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg shadow-blue-200 transition-all flex items-center gap-2"
                  >
                    Próxima Etapa <i className="fas fa-arrow-right text-xs"></i>
                  </button>
                ) : (
                  <button 
                    onClick={() => setCurrentStep(StepId.DASHBOARD)}
                    className="bg-slate-900 hover:bg-black text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg transition-all"
                  >
                    Finalizar e Ir ao Dashboard
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t py-6 mt-12">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
          <p className="text-slate-400 text-xs font-medium">© 2024 Industrial Maintenance Reliability System. Todos os direitos reservados.</p>
          <div className="flex gap-6">
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Suporte Técnico</button>
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Base de Conhecimento</button>
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Privacidade</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
