{
  "name": "Análise de Falhas SWM Brasil",
  "description": "A high-performance web application for industrial failure analysis using PDCA, 5W2H, 5 Whys, and Ishikawa diagrams, featuring AI-powered insights.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useCallback } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [] },
  method: { causes: [] },
  material: { causes: [] },
  manpower: { causes: [] },
  measurement: { causes: [] },
  environment: { causes: [] },
};

const INITIAL_STATE: Analysis = {
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevison: false,
  needsTraining: false,
};

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(INITIAL_STATE);
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  // Auto-save simulation
  useEffect(() => {
    localStorage.setItem('current_analysis', JSON.stringify(analysis));
  }, [analysis]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const addAction = () => {
    const newAction: Action = {
      id: Date.now().toString(),
      description: '',
      type: 'Corretiva',
      responsible: '',
      dueDate: '',
      status: 'Aberta'
    };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input 
                  type="text" 
                  value={analysis.area}
                  onChange={e => updateAnalysis({ area: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: Refino de Papel"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input 
                  type="text" 
                  value={analysis.equipment}
                  onChange={e => updateAnalysis({ equipment: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: Motor Refinador MP3"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input 
                  type="text" 
                  value={analysis.tag}
                  onChange={e => updateAnalysis({ tag: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                  placeholder="Ex: MOT-301-A"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input 
                  type="date" 
                  value={analysis.failureDate}
                  onChange={e => updateAnalysis({ failureDate: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border" 
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Descrição Breve do Problema</label>
              <textarea 
                value={analysis.description}
                onChange={e => updateAnalysis({ description: e.target.value })}
                className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border h-32" 
                placeholder="Descreva o que houve de forma clara e técnica..."
              />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when },
                { field: 'who', label: 'QUEM identificou?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">{item.label}</label>
                  <textarea 
                    value={(analysis as any)[item.field]}
                    onChange={e => updateAnalysis({ [item.field]: e.target.value })}
                    className="w-full border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border h-24" 
                  />
                  {item.tip && <p className="text-xs text-slate-400 mt-1 italic">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Sintoma Observado</label>
                <input 
                  type="text" 
                  value={analysis.symptom}
                  onChange={e => updateAnalysis({ symptom: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 border outline-none focus:ring-2 focus:ring-blue-500" 
                  placeholder="Ex: Vibração excessiva, fumaça, desligamento súbito..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Frequência da Falha</label>
                <div className="flex gap-4">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-3 rounded-lg border cursor-pointer transition-all ${analysis.frequency === f ? 'bg-blue-50 border-blue-600 text-blue-700 font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input 
                        type="radio" 
                        className="hidden" 
                        checked={analysis.frequency === f} 
                        onChange={() => updateAnalysis({ frequency: f as any })}
                      />
                      {f}
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Histórico Recente de Intervenções</label>
                <textarea 
                  value={analysis.history}
                  onChange={e => updateAnalysis({ history: e.target.value })}
                  className="w-full border-slate-300 rounded-lg p-3 border outline-none focus:ring-2 focus:ring-blue-500 h-32" 
                  placeholder="Houve manutenção preventiva recente? Houve troca de peças?"
                />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button 
                onClick={handleSuggestCause}
                className="text-xs bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold py-1 px-3 rounded-full border border-slate-300 transition-colors"
              >
                <i className="fas fa-robot mr-1 text-blue-500"></i> Sugerir com IA
              </button>
            </div>
            <div className="space-y-4 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden md:block"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-4 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30 pointer-events-none' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Por que aconteceu o nível {idx}?</label>
                    <textarea 
                      value={why}
                      onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }}
                      className="w-full border-slate-200 rounded-lg p-4 border outline-none focus:ring-2 focus:ring-blue-500 h-20 shadow-sm" 
                      placeholder={idx === 0 ? "A falha ocorreu devido a..." : "E por que isso ocorreu?"}
                    />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-8 p-6 bg-blue-600 rounded-xl text-white shadow-xl transform hover:scale-[1.01] transition-transform">
              <label className="block text-sm font-bold uppercase mb-2 opacity-80">Causa Raiz Identificada</label>
              <input 
                type="text" 
                value={analysis.rootCause}
                onChange={e => updateAnalysis({ rootCause: e.target.value })}
                className="w-full bg-white text-slate-900 rounded-lg p-4 font-bold border-none outline-none text-lg shadow-inner" 
                placeholder="A causa fundamental da falha é..."
              />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button 
                onClick={addAction}
                className="bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-2 px-4 rounded-lg flex items-center gap-2 shadow-lg transition-colors"
              >
                <i className="fas fa-plus"></i> Nova Ação
              </button>
            </div>
            <div className="overflow-x-auto rounded-xl border border-slate-200 shadow-sm">
              <table className="w-full text-left bg-white">
                <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-bold border-b">
                  <tr>
                    <th className="px-4 py-3">Ação Recomendada</th>
                    <th className="px-4 py-3">Tipo</th>
                    <th className="px-4 py-3">Responsável</th>
                    <th className="px-4 py-3">Prazo</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysis.actions.map(action => (
                    <tr key={action.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3">
                        <textarea 
                          value={action.description}
                          onChange={e => updateAction(action.id, { description: e.target.value })}
                          className="w-full border-none bg-transparent outline-none focus:ring-1 focus:ring-blue-300 rounded p-1 text-sm"
                          rows={2}
                          placeholder="Ex: Substituir rolamento por modelo selado"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <select 
                          value={action.type}
                          onChange={e => updateAction(action.id, { type: e.target.value as any })}
                          className="text-xs border rounded p-1 bg-white outline-none"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={action.responsible}
                          onChange={e => updateAction(action.id, { responsible: e.target.value })}
                          className="text-xs border rounded p-1 w-full"
                          placeholder="Nome"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="date" 
                          value={action.dueDate}
                          onChange={e => updateAction(action.id, { dueDate: e.target.value })}
                          className="text-xs border rounded p-1 w-full"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${
                          action.status === 'Concluída' ? 'bg-green-100 text-green-700' :
                          action.status === 'Em andamento' ? 'bg-blue-100 text-blue-700' :
                          'bg-amber-100 text-amber-700'
                        }`}>
                          {action.status}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500">
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                  {analysis.actions.length === 0 && (
                    <tr>
                      <td colSpan={6} className="text-center py-10 text-slate-400 italic text-sm">Nenhuma ação definida ainda. Clique em "Nova Ação" para começar.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Eficácia das Ações</h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-2">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: true })}
                      className={`flex-1 py-3 border rounded-lg font-bold transition-all ${analysis.reoccurred === true ? 'bg-red-50 border-red-600 text-red-600' : 'hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      SIM
                    </button>
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: false })}
                      className={`flex-1 py-3 border rounded-lg font-bold transition-all ${analysis.reoccurred === false ? 'bg-green-50 border-green-600 text-green-600' : 'hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      NÃO
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-slate-600 mb-2">Evidências da Eficácia</label>
                  <textarea 
                    value={analysis.effectivenessEvidence}
                    onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })}
                    className="w-full border rounded-lg p-3 h-24 outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="Ex: Redução de vibração de 8mm/s para 1.2mm/s após troca..."
                  />
                </div>
              </div>

              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Ações de Padronização</h3>
                <div className="space-y-3">
                  <label className="flex items-center gap-3 p-3 border rounded-lg cursor-pointer hover:bg-slate-50 transition-colors">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsRevison}
                      onChange={e => updateAnalysis({ needsRevison: e.target.checked })}
                    />
                    <span className="text-sm text-slate-700">Necessita revisão de procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-3 p-3 border rounded-lg cursor-pointer hover:bg-slate-50 transition-colors">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsTraining}
                      onChange={e => updateAnalysis({ needsTraining: e.target.checked })}
                    />
                    <span className="text-sm text-slate-700">Necessita treinamento da equipe?</span>
                  </label>
                </div>
                <div className="pt-4 border-t">
                  <button 
                    onClick={handleGenerateSummary}
                    disabled={isGeneratingSummary}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2"
                  >
                    {isGeneratingSummary ? (
                      <><i className="fas fa-spinner fa-spin"></i> Gerando Resumo Inteligente...</>
                    ) : (
                      <><i className="fas fa-robot"></i> Gerar Resumo e Finalizar Análise</>
                    )}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-slate-900 text-white p-8 rounded-2xl shadow-2xl mt-12">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-2">
                    <i className="fas fa-file-alt text-blue-400"></i> Resumo Executivo da Falha
                  </h2>
                  <span className="bg-blue-500/20 text-blue-400 text-xs px-2 py-1 rounded uppercase tracking-widest font-bold">Gerado por IA</span>
                </div>
                <p className="text-slate-300 leading-relaxed text-lg">
                  {analysis.summary}
                </p>
                <div className="mt-8 flex gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-print"></i> Imprimir PDF
                  </button>
                  <button className="bg-green-500 hover:bg-green-600 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-share-alt"></i> Compartilhar
                  </button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <i className="fas fa-industry text-xl"></i>
            </div>
            <div>
              <h1 className="font-black text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[10px] text-blue-400 font-bold tracking-widest uppercase">Análise de Falhas Industrial</p>
            </div>
          </div>
          <nav className="hidden md:flex gap-6 text-sm font-bold uppercase tracking-wider">
            <button 
              onClick={() => setCurrentStep(StepId.IDENTIFICATION)} 
              className={`hover:text-blue-400 transition-colors ${currentStep !== StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Nova Análise
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              className={`hover:text-blue-400 transition-colors ${currentStep === StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Dashboard
            </button>
            <button className="text-slate-400 hover:text-white">Relatórios</button>
          </nav>
          <div className="flex items-center gap-4">
             <div className="hidden lg:block text-right">
                <p className="text-xs font-bold text-slate-300">Eng. Roberto Silva</p>
                <p className="text-[10px] text-slate-500 uppercase">Supervisor de Confiabilidade</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-700 border border-slate-600 flex items-center justify-center overflow-hidden">
                <img src="https://picsum.photos/40/40" alt="Avatar" />
             </div>
          </div>
        </div>
      </header>

      {/* PDCA Progress Bar */}
      {currentStep !== StepId.DASHBOARD && (
        <div className="bg-white border-b sticky top-16 z-40 overflow-x-auto no-scrollbar">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-2 min-w-[800px]">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  className={`flex flex-col items-center gap-1 group relative ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-100 text-green-600 border border-green-200' : 
                    'bg-slate-50 text-slate-400 border border-slate-200'
                  }`}>
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-bold uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                  {currentStep === step.id && (
                    <div className="absolute -bottom-4 w-full h-1 bg-blue-600 rounded-t"></div>
                  )}
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-200' : 'bg-slate-100'}`}></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden min-h-[600px] flex flex-col">
          <div className="p-6 md:p-10 flex-1">
             {renderStepContent()}
          </div>

          {/* Controls */}
          {currentStep !== StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-6 flex justify-between items-center">
              <button 
                onClick={handleBack}
                disabled={currentStep === StepId.IDENTIFICATION}
                className="flex items-center gap-2 text-slate-500 font-bold hover:text-slate-800 disabled:opacity-30 px-4 py-2"
              >
                <i className="fas fa-arrow-left"></i> Voltar
              </button>

              <div className="flex gap-4">
                <button 
                  className="hidden md:flex items-center gap-2 bg-white text-slate-600 border border-slate-200 px-6 py-2 rounded-lg font-bold hover:bg-slate-50 transition-all shadow-sm"
                >
                  <i className="fas fa-save"></i> Salvar Rascunho
                </button>
                {currentStep < StepId.VERIFICATION ? (
                  <button 
                    onClick={handleNext}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg shadow-blue-200 transition-all flex items-center gap-2"
                  >
                    Próxima Etapa <i className="fas fa-arrow-right text-xs"></i>
                  </button>
                ) : (
                  <button 
                    onClick={() => setCurrentStep(StepId.DASHBOARD)}
                    className="bg-slate-900 hover:bg-black text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg transition-all"
                  >
                    Finalizar e Ir ao Dashboard
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t py-6 mt-12">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
          <p className="text-slate-400 text-xs font-medium">© 2024 Industrial Maintenance Reliability System. Todos os direitos reservados.</p>
          <div className="flex gap-6">
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Suporte Técnico</button>
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Base de Conhecimento</button>
             <button className="text-slate-400 hover:text-blue-600 text-xs font-bold uppercase">Privacidade</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [] },
  method: { causes: [] },
  material: { causes: [] },
  manpower: { causes: [] },
  measurement: { causes: [] },
  environment: { causes: [] },
};

const INITIAL_STATE: Analysis = {
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevison: false,
  needsTraining: false,
};

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(INITIAL_STATE);
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  // Auto-save simulation
  useEffect(() => {
    localStorage.setItem('current_analysis', JSON.stringify(analysis));
  }, [analysis]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const addAction = () => {
    const newAction: Action = {
      id: Date.now().toString(),
      description: '',
      type: 'Corretiva',
      responsible: '',
      dueDate: '',
      status: 'Aberta'
    };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-300 bg-white text-slate-900 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none border shadow-sm placeholder:text-slate-400";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input 
                  type="text" 
                  value={analysis.area}
                  onChange={e => updateAnalysis({ area: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Refino de Papel"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input 
                  type="text" 
                  value={analysis.equipment}
                  onChange={e => updateAnalysis({ equipment: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Motor Refinador MP3"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input 
                  type="text" 
                  value={analysis.tag}
                  onChange={e => updateAnalysis({ tag: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: MOT-301-A"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input 
                  type="date" 
                  value={analysis.failureDate}
                  onChange={e => updateAnalysis({ failureDate: e.target.value })}
                  className={inputClasses} 
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Descrição Breve do Problema</label>
              <textarea 
                value={analysis.description}
                onChange={e => updateAnalysis({ description: e.target.value })}
                className={`${inputClasses} h-32 resize-none`} 
                placeholder="Descreva o que houve de forma clara e técnica..."
              />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when },
                { field: 'who', label: 'QUEM identificou?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">{item.label}</label>
                  <textarea 
                    value={(analysis as any)[item.field]}
                    onChange={e => updateAnalysis({ [item.field]: e.target.value })}
                    className={`${inputClasses} h-24 resize-none`} 
                  />
                  {item.tip && <p className="text-xs text-slate-500 mt-1 italic">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Sintoma Observado</label>
                <input 
                  type="text" 
                  value={analysis.symptom}
                  onChange={e => updateAnalysis({ symptom: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Vibração excessiva, fumaça, desligamento súbito..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Frequência da Falha</label>
                <div className="flex gap-4">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-3 rounded-lg border cursor-pointer transition-all shadow-sm ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input 
                        type="radio" 
                        className="hidden" 
                        checked={analysis.frequency === f} 
                        onChange={() => updateAnalysis({ frequency: f as any })}
                      />
                      {f}
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Histórico Recente de Intervenções</label>
                <textarea 
                  value={analysis.history}
                  onChange={e => updateAnalysis({ history: e.target.value })}
                  className={`${inputClasses} h-32 resize-none`} 
                  placeholder="Houve manutenção preventiva recente? Houve troca de peças?"
                />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button 
                onClick={handleSuggestCause}
                className="text-xs bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-1.5 px-4 rounded-full border border-slate-300 transition-colors flex items-center gap-2"
              >
                <i className="fas fa-robot text-blue-600"></i> Sugerir com IA
              </button>
            </div>
            <div className="space-y-4 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden md:block"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-4 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30 pointer-events-none' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nível {idx + 1}</label>
                    <textarea 
                      value={why}
                      onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }}
                      className={`${inputClasses} h-20 resize-none`} 
                      placeholder={idx === 0 ? "Por que a falha ocorreu inicialmente?" : "E por que isso aconteceu?"}
                    />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-8 p-6 bg-blue-700 rounded-xl text-white shadow-xl transform hover:scale-[1.01] transition-transform">
              <label className="block text-sm font-bold uppercase mb-2 opacity-90">Causa Raiz Identificada</label>
              <input 
                type="text" 
                value={analysis.rootCause}
                onChange={e => updateAnalysis({ rootCause: e.target.value })}
