                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nível {idx + 1}</label>
                    <textarea 
                      value={why}
                      onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }}
                      className={`${inputClasses} h-20 resize-none`} 
                      placeholder={idx === 0 ? "Por que a falha ocorreu inicialmente?" : "E por que isso aconteceu?"}
                    />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-8 p-6 bg-blue-700 rounded-xl text-white shadow-xl transform hover:scale-[1.01] transition-transform">
              <label className="block text-sm font-bold uppercase mb-2 opacity-90">Causa Raiz Identificada</label>
              <input 
                type="text" 
                value={analysis.rootCause}
                onChange={e => updateAnalysis({ rootCause: e.target.value })}
                className="w-full bg-white text-slate-900 rounded-lg p-4 font-black border-none outline-none text-lg shadow-inner placeholder:text-slate-300" 
                placeholder="A causa fundamental da falha é..."
              />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex justify-between items-center border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button 
                onClick={addAction}
                className="bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-2.5 px-5 rounded-lg flex items-center gap-2 shadow-lg transition-colors"
              >
                <i className="fas fa-plus"></i> Nova Ação
              </button>
            </div>
            <div className="overflow-x-auto rounded-xl border border-slate-200 shadow-sm">
              <table className="w-full text-left bg-white">
                <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-bold border-b">
                  <tr>
                    <th className="px-4 py-3">Ação Recomendada</th>
                    <th className="px-4 py-3">Tipo</th>
                    <th className="px-4 py-3">Responsável</th>
                    <th className="px-4 py-3">Prazo</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysis.actions.map(action => (
                    <tr key={action.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3">
                        <textarea 
                          value={action.description}
                          onChange={e => updateAction(action.id, { description: e.target.value })}
                          className="w-full border border-slate-200 bg-white text-slate-900 outline-none focus:ring-1 focus:ring-blue-500 rounded p-2 text-sm shadow-sm"
                          rows={2}
                          placeholder="Ex: Substituir rolamento..."
                        />
                      </td>
                      <td className="px-4 py-3">
                        <select 
                          value={action.type}
                          onChange={e => updateAction(action.id, { type: e.target.value as any })}
                          className="text-xs border border-slate-200 rounded p-2 bg-white text-slate-900 outline-none shadow-sm font-medium"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={action.responsible}
                          onChange={e => updateAction(action.id, { responsible: e.target.value })}
                          className="text-xs border border-slate-200 rounded p-2 w-full bg-white text-slate-900 shadow-sm"
                          placeholder="Nome"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="date" 
                          value={action.dueDate}
                          onChange={e => updateAction(action.id, { dueDate: e.target.value })}
                          className="text-xs border border-slate-200 rounded p-2 w-full bg-white text-slate-900 shadow-sm"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[10px] font-black px-2 py-1 rounded-full uppercase ${
                          action.status === 'Concluída' ? 'bg-green-100 text-green-800' :
                          action.status === 'Em andamento' ? 'bg-blue-100 text-blue-800' :
                          'bg-amber-100 text-amber-800'
                        }`}>
                          {action.status}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 transition-colors">
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                  {analysis.actions.length === 0 && (
                    <tr>
                      <td colSpan={6} className="text-center py-12 text-slate-400 italic text-sm">Nenhuma ação definida ainda. Clique em "Nova Ação" para começar.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Eficácia das Ações</h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-2 font-medium">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: true })}
                      className={`flex-1 py-3 border rounded-lg font-black transition-all shadow-sm ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white' : 'bg-white hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      SIM
                    </button>
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: false })}
                      className={`flex-1 py-3 border rounded-lg font-black transition-all shadow-sm ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white' : 'bg-white hover:bg-slate-50 border-slate-200 text-slate-400'}`}
                    >
                      NÃO
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-slate-600 mb-2 font-medium">Evidências da Eficácia</label>
                  <textarea 
                    value={analysis.effectivenessEvidence}
                    onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })}
                    className={inputClasses + " h-24 resize-none"}
                    placeholder="Ex: Redução de vibração medida após intervenção..."
                  />
                </div>
              </div>

              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-700">Ações de Padronização</h3>
                <div className="space-y-3">
                  <label className="flex items-center gap-3 p-3 border border-slate-200 rounded-lg cursor-pointer bg-white hover:bg-slate-50 transition-colors shadow-sm">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsRevision}
                      onChange={e => updateAnalysis({ needsRevision: e.target.checked })}
                    />
                    <span className="text-sm text-slate-800 font-medium">Necessita revisão de procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-3 p-3 border border-slate-200 rounded-lg cursor-pointer bg-white hover:bg-slate-50 transition-colors shadow-sm">
                    <input 
                      type="checkbox" 
                      className="w-5 h-5 accent-blue-600"
                      checked={analysis.needsTraining}
                      onChange={e => updateAnalysis({ needsTraining: e.target.checked })}
                    />
                    <span className="text-sm text-slate-800 font-medium">Necessita treinamento da equipe?</span>
                  </label>
                </div>
                <div className="pt-4 border-t">
                  <button 
                    onClick={handleGenerateSummary}
                    disabled={isGeneratingSummary}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-black py-4 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 uppercase tracking-wider"
                  >
                    {isGeneratingSummary ? (
                      <><i className="fas fa-spinner fa-spin"></i> Gerando Resumo Inteligente...</>
                    ) : (
                      <><i className="fas fa-robot"></i> Gerar Resumo e Finalizar Análise</>
                    )}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-slate-900 text-white p-8 rounded-2xl shadow-2xl mt-12">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-2">
                    <i className="fas fa-file-alt text-blue-400"></i> Resumo Executivo da Falha
                  </h2>
                  <span className="bg-blue-500/20 text-blue-400 text-xs px-2 py-1 rounded uppercase tracking-widest font-bold">Gerado por IA</span>
                </div>
                <p className="text-slate-200 leading-relaxed text-lg">
                  {analysis.summary}
                </p>
                <div className="mt-8 flex gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-print"></i> Imprimir PDF
                  </button>
                  <button className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold transition-all flex items-center gap-2">
                    <i className="fas fa-share-alt"></i> Compartilhar
                  </button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <i className="fas fa-industry text-xl"></i>
            </div>
            <div>
              <h1 className="font-black text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[10px] text-blue-400 font-bold tracking-widest uppercase">Análise de Falhas Industrial</p>
            </div>
          </div>
          <nav className="flex gap-6 text-sm font-bold uppercase tracking-wider">
            <button 
              onClick={() => setCurrentStep(StepId.IDENTIFICATION)} 
              className={`hover:text-blue-400 transition-colors ${currentStep !== StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Nova Análise
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              className={`hover:text-blue-400 transition-colors ${currentStep === StepId.DASHBOARD ? 'text-blue-400' : 'text-slate-400'}`}
            >
              Dashboard
            </button>
          </nav>
        </div>
      </header>

      {/* PDCA Progress Bar */}
      {currentStep !== StepId.DASHBOARD && (
        <div className="bg-white border-b sticky top-16 z-40 overflow-x-auto no-scrollbar shadow-sm">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-2 min-w-[800px]">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  className={`flex flex-col items-center gap-1 group relative ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-600 text-white border border-green-600' : 
                    'bg-slate-100 text-slate-400 border border-slate-200'
                  }`}>
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                  {currentStep === step.id && (
                    <div className="absolute -bottom-4 w-full h-1 bg-blue-600 rounded-t"></div>
                  )}
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-600' : 'bg-slate-100'}`}></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
        <div className="bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden min-h-[600px] flex flex-col">
          <div className="p-6 md:p-10 flex-1">
             {renderStepContent()}
          </div>

          {/* Controls */}
          {currentStep !== StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-6 flex justify-between items-center">
              <button 
                onClick={handleBack}
                disabled={currentStep === StepId.IDENTIFICATION}
                className="flex items-center gap-2 text-slate-500 font-black uppercase tracking-wider hover:text-slate-900 disabled:opacity-30 px-4 py-2 transition-colors"
              >
                <i className="fas fa-arrow-left"></i> Voltar
              </button>

              <div className="flex gap-4">
                <button 
                  className="hidden md:flex items-center gap-2 bg-white text-slate-700 border border-slate-300 px-6 py-2.5 rounded-lg font-bold hover:bg-slate-50 transition-all shadow-sm"
                >
                  <i className="fas fa-save text-blue-600"></i> Salvar Rascunho
                </button>
                {currentStep < StepId.VERIFICATION ? (
                  <button 
                    onClick={handleNext}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg shadow-blue-200 transition-all flex items-center gap-2"
                  >
                    Próxima Etapa <i className="fas fa-arrow-right text-xs"></i>
                  </button>
                ) : (
                  <button 
                    onClick={() => setCurrentStep(StepId.DASHBOARD)}
                    className="bg-slate-900 hover:bg-black text-white px-8 py-3 rounded-xl font-black uppercase tracking-wider shadow-lg transition-all"
                  >
                    Finalizar e Ir ao Dashboard
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t py-6 mt-12">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-tight italic">SWM Brasil - Excelência em Confiabilidade Industrial</p>
          <div className="flex gap-6">
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest">Suporte</button>
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest">Procedimentos</button>
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest">Sair</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { Analysis } from "../types";

// Corrected: Initialize with apiKey as a named property.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateSummary(analysis: Analysis): Promise<string> {
  const prompt = `
    Como um especialista em confiabilidade industrial, analise os seguintes dados de uma falha e gere um resumo executivo técnico e conciso (máximo 150 palavras).
    Destaque a causa raiz e a ação principal recomendada.

    DADOS:
    Equipamento: ${analysis.equipment} (${analysis.tag})
    Descrição: ${analysis.description}
    5 Porquês: ${analysis.whys.filter(w => w).join(' -> ')}
    Causa Raiz: ${analysis.rootCause}
    Ishikawa (Máquina): ${analysis.ishikawa.machine.causes.join(', ')}
    Plano de Ação: ${analysis.actions.map(a => a.description).join('; ')}
  `;

  try {
    // Corrected: Use ai.models.generateContent with model and contents together.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { temperature: 0.7 }
    });
    // Corrected: Access response text as a property.
    return response.text || "Não foi possível gerar o resumo automático.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar resumo com IA.";
  }
}

export async function suggestRootCause(analysis: Analysis): Promise<string> {
  const prompt = `
    Com base na descrição da falha e no detalhamento fornecido, sugira uma possível causa raiz técnica.
    Descrição: ${analysis.description}
    Sintoma: ${analysis.symptom}
    Histórico: ${analysis.history}
    Responda apenas com a sugestão curta da causa raiz.
  `;

  try {
    // Corrected: Use ai.models.generateContent with model and contents together.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { temperature: 0.5 }
    });
    // Corrected: Access response text as a property.
    return response.text?.trim() || "Análise necessária";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Falha na sugestão automática.";
  }
}

export type Status = 'Aberta' | 'Em andamento' | 'Concluída';
export type FailureFrequency = 'Eventual' | 'Recorrente' | 'Crônica';
export type ActionType = 'Corretiva' | 'Preventiva' | 'Melhoria';

export interface Attachment {
  id: string;
  name: string;
  type: string;
  size: number;
  dataUrl?: string;
}

export interface Action {
  id: string;
  description: string;
  type: ActionType;
  responsible: string;
  dueDate: string;
  status: Status;
}

export interface IshikawaCategory {
  causes: string[];
  attachments: Attachment[];
}

export interface Ishikawa {
  machine: IshikawaCategory;
  method: IshikawaCategory;
  material: IshikawaCategory;
  manpower: IshikawaCategory;
  measurement: IshikawaCategory;
  environment: IshikawaCategory;
}

export interface Analysis {
  id: string;
  // Step 1
  area: string;
  equipment: string;
  tag: string;
  failureDate: string;
  shift: string;
  responsible: string;
  description: string;
  // Step 2 (5W1H)
  what: string;
  where: string;
  when: string;
  who: string;
  howMuch: string;
  how: string;
  // Step 3
  symptom: string;
  condition: string;
  history: string;
  frequency: FailureFrequency;
  // Step 4 (5 Whys)
  whys: string[];
  rootCause: string;
  // Step 5 (Ishikawa)
  ishikawa: Ishikawa;
  // Step 6 (Actions)
  actions: Action[];
  // Step 7
  reoccurred: boolean | null;
  effectivenessEvidence: string;
  needsRevision: boolean;
  needsTraining: boolean;
  // Meta
  summary?: string;
}

export enum StepId {
  IDENTIFICATION = 0,
  W5H1 = 1,
  DETAILS = 2,
  FIVE_WHYS = 3,
  ISHIKAWA = 4,
  ACTIONS = 5,
  VERIFICATION = 6,
  DASHBOARD = 7
}

import React, { useState, useEffect, useCallback } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
