          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input 
                  type="text" 
                  value={analysis.area}
                  onChange={e => updateAnalysis({ area: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Refino de Papel"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input 
                  type="text" 
                  value={analysis.equipment}
                  onChange={e => updateAnalysis({ equipment: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Motor Refinador MP3"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input 
                  type="text" 
                  value={analysis.tag}
                  onChange={e => updateAnalysis({ tag: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: MOT-301-A"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input 
                  type="date" 
                  value={analysis.failureDate}
                  onChange={e => updateAnalysis({ failureDate: e.target.value })}
