import React, { useRef } from 'react';
import { Analysis, IshikawaCategory, Attachment } from '../types';
import { ISHIKAWA_QUESTIONS } from '../constants';

interface Props {
  analysis: Analysis;
  updateAnalysis: (data: Partial<Analysis>) => void;
}

const IshikawaComponent: React.FC<Props> = ({ analysis, updateAnalysis }) => {
  const fileInputRefs = {
    machine: useRef<HTMLInputElement>(null),
    method: useRef<HTMLInputElement>(null),
    material: useRef<HTMLInputElement>(null),
    manpower: useRef<HTMLInputElement>(null),
    measurement: useRef<HTMLInputElement>(null),
    environment: useRef<HTMLInputElement>(null),
  };

  const handleCauseChange = (category: keyof Analysis['ishikawa'], index: number, value: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes[index] = value;
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const addCause = (category: keyof Analysis['ishikawa']) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.push("");
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const removeCause = (category: keyof Analysis['ishikawa'], index: number) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.splice(index, 1);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const handleFileUpload = (category: keyof Analysis['ishikawa'], e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();
    reader.onload = (event) => {
      const newAttachment: Attachment = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        type: file.type,
        size: file.size,
        dataUrl: event.target?.result as string,
      };

      const newIshikawa = { ...analysis.ishikawa };
      newIshikawa[category].attachments = [...(newIshikawa[category].attachments || []), newAttachment];
      updateAnalysis({ ishikawa: newIshikawa });

      if (fileInputRefs[category].current) {
        fileInputRefs[category].current!.value = "";
      }
    };
    reader.readAsDataURL(file);
  };

  const removeAttachment = (category: keyof Analysis['ishikawa'], attachmentId: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].attachments = newIshikawa[category].attachments.filter(a => a.id !== attachmentId);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const renderCategory = (category: keyof Analysis['ishikawa'], label: string, icon: string) => (
    <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-slate-200 hover:border-blue-400 transition-all flex flex-col h-full">
      <div className="flex items-center gap-3 mb-4 border-b border-slate-100 pb-3">
        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center border border-slate-100 shadow-inner">
          <i className={`fas ${icon} text-blue-600`}></i>
        </div>
        <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs md:text-sm">{label}</h3>
      </div>
      <p className="text-[11px] text-slate-500 mb-5 italic leading-snug">{ISHIKAWA_QUESTIONS[category]}</p>

      <div className="space-y-3 flex-1">
        {analysis.ishikawa[category].causes.map((cause, idx) => (
          <div key={idx} className="flex gap-2 animate-fadeIn">
            <input
              type="text"
              value={cause}
              onChange={(e) => handleCauseChange(category, idx, e.target.value)}
              placeholder="Descreva a causa..."
              className="flex-1 text-sm bg-slate-50 border-slate-200 text-slate-900 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none border shadow-inner font-medium placeholder:text-slate-400"
            />
            <button 
              onClick={() => removeCause(category, idx)}
              className="text-slate-300 hover:text-red-500 transition-colors p-2"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>
        ))}

        {analysis.ishikawa[category].attachments && analysis.ishikawa[category].attachments.length > 0 && (
          <div className="mt-6 pt-4 border-t border-dashed border-slate-200 space-y-3">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Evidências Anexadas</p>
            <div className="grid grid-cols-1 gap-2">
              {analysis.ishikawa[category].attachments.map((file) => (
                <div key={file.id} className="bg-blue-50/50 border border-blue-100 rounded-xl px-3 py-2 flex items-center gap-3 group">
                  <i className={`fas ${file.type.startsWith('image/') ? 'fa-image' : 'fa-file-alt'} text-blue-500`}></i>
                  <span className="text-[11px] font-bold text-slate-700 truncate flex-1">{file.name}</span>
                  <button 
                    onClick={() => removeAttachment(category, file.id)}
                    className="text-slate-400 hover:text-red-500 transition-colors p-1"
                  >
                    <i className="fas fa-trash-alt text-[10px]"></i>
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-3 pt-5 border-t border-slate-100">
        <button 
          onClick={() => addCause(category)}
          className="flex-1 text-[10px] text-blue-700 font-black bg-blue-50 hover:bg-blue-100 rounded-xl py-3 flex items-center justify-center gap-2 uppercase tracking-widest transition-all"
        >
          <i className="fas fa-plus-circle"></i> Causa
        </button>

        <button 
          onClick={() => fileInputRefs[category].current?.click()}
          className="flex-1 text-[10px] text-slate-600 font-black bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl py-3 flex items-center justify-center gap-2 uppercase tracking-widest transition-all"
        >
          <i className="fas fa-paperclip"></i> Anexar
        </button>

        <input 
          type="file" 
          ref={fileInputRefs[category]}
          onChange={(e) => handleFileUpload(category, e)}
          className="hidden"
          accept="image/*,.pdf,.doc,.docx,.xls,.xlsx"
        />
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
      {renderCategory('machine', 'Máquina', 'fa-cogs')}
      {renderCategory('method', 'Método', 'fa-book')}
      {renderCategory('manpower', 'Mão de Obra', 'fa-users')}
      {renderCategory('material', 'Material', 'fa-box-open')}
      {renderCategory('measurement', 'Medição', 'fa-ruler-combined')}
      {renderCategory('environment', 'Meio Ambiente', 'fa-leaf')}
    </div>
  );
};

export default IshikawaComponent;

export type Status = 'Aberta' | 'Em andamento' | 'Concluída';
export type FailureFrequency = 'Eventual' | 'Recorrente' | 'Crônica';
export type ActionType = 'Corretiva' | 'Preventiva' | 'Melhoria';

export interface Attachment {
  id: string;
  name: string;
  type: string;
  size: number;
  dataUrl?: string;
}

export interface Action {
  id: string;
  description: string;
  type: ActionType;
  responsible: string;
  dueDate: string;
  status: Status;
}

export interface IshikawaCategory {
  causes: string[];
  attachments: Attachment[];
}

export interface Ishikawa {
  machine: IshikawaCategory;
  method: IshikawaCategory;
  material: IshikawaCategory;
  manpower: IshikawaCategory;
  measurement: IshikawaCategory;
  environment: IshikawaCategory;
}

export interface Analysis {
  id: string;
  // Step 1
  area: string;
  equipment: string;
  tag: string;
  failureDate: string;
  shift: string;
  responsible: string;
  description: string;
  // Step 2 (5W1H)
  what: string;
  where: string;
  when: string;
  who: string;
  howMuch: string;
  how: string;
  // Step 3
  symptom: string;
  condition: string;
  history: string;
  frequency: FailureFrequency;
  // Step 4 (5 Whys)
  whys: string[];
  rootCause: string;
  // Step 5 (Ishikawa)
  ishikawa: Ishikawa;
  // Step 6 (Actions)
  actions: Action[];
  // Step 7
  reoccurred: boolean | null;
  effectivenessEvidence: string;
  needsRevision: boolean;
  needsTraining: boolean;
  // Meta
  summary?: string;
  lastUpdated?: string;
}

export enum StepId {
  IDENTIFICATION = 0,
  W5H1 = 1,
  DETAILS = 2,
  FIVE_WHYS = 3,
  ISHIKAWA = 4,
  ACTIONS = 5,
  VERIFICATION = 6,
  DASHBOARD = 7,
  HISTORY = 8
}

import React, { useState, useMemo } from 'react';
import { Analysis } from '../types';

interface Props {
  onLoad: (analysis: Analysis) => void;
  onDelete: (id: string) => void;
}

const HistoryView: React.FC<Props> = ({ onLoad, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [areaFilter, setAreaFilter] = useState('Todas');

  const history: Analysis[] = useMemo(() => {
    const saved = localStorage.getItem('analysis_history');
    return saved ? JSON.parse(saved) : [];
  }, []);

  const areas = useMemo(() => {
    const uniqueAreas = new Set(history.map(a => a.area).filter(Boolean));
    return ['Todas', ...Array.from(uniqueAreas)];
  }, [history]);

  const filteredHistory = useMemo(() => {
    return history.filter(item => {
      const matchesSearch = 
        item.equipment.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.tag.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesArea = areaFilter === 'Todas' || item.area === areaFilter;

      return matchesSearch && matchesArea;
    }).sort((a, b) => new Date(b.failureDate).getTime() - new Date(a.failureDate).getTime());
  }, [history, searchTerm, areaFilter]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Histórico de Análises</h2>
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          <div className="relative flex-1 sm:w-64">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
            <input 
              type="text"
              placeholder="Buscar por tag, nome ou ID..."
              className="w-full pl-10 pr-4 py-2 bg-slate-100 border-none rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="bg-slate-100 border-none rounded-xl px-4 py-2 text-sm font-bold text-slate-600 outline-none focus:ring-2 focus:ring-blue-500"
            value={areaFilter}
            onChange={e => setAreaFilter(e.target.value)}
          >
            {areas.map(area => <option key={area} value={area}>{area}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filteredHistory.length > 0 ? (
          filteredHistory.map(item => (
            <div key={item.id} className="bg-white border border-slate-200 rounded-2xl p-5 md:p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-4 hover:shadow-md transition-shadow group">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0">
                  <i className="fas fa-file-invoice text-xl"></i>
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{item.id}</span>
                    <span className="text-[10px] font-bold text-slate-400">•</span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(item.failureDate).toLocaleDateString('pt-BR')}</span>
                  </div>
                  <h3 className="text-lg font-black text-slate-800 leading-tight group-hover:text-blue-600 transition-colors">{item.equipment || "Sem Nome"}</h3>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-tighter">{item.area} — <span className="text-slate-400">{item.tag}</span></p>
                </div>
              </div>

              <div className="flex items-center gap-3 w-full md:w-auto mt-2 md:mt-0 pt-4 md:pt-0 border-t md:border-t-0 border-slate-100">
                <button 
                  onClick={() => onLoad(item)}
                  className="flex-1 md:flex-initial bg-slate-900 text-white text-xs font-black uppercase tracking-widest px-6 py-3 rounded-xl hover:bg-black transition-colors"
                >
                  Abrir Relatório
                </button>
                <button 
                  onClick={() => onDelete(item.id)}
                  className="p-3 text-slate-300 hover:text-red-500 transition-colors"
                  title="Excluir"
                >
                  <i className="fas fa-trash-alt"></i>
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
            <i className="fas fa-folder-open text-4xl text-slate-200 mb-4"></i>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Nenhuma análise encontrada</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryView;

import React, { useState, useEffect, useCallback } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  // Auto-save current active session simulation
  useEffect(() => {
    if (currentStep !== StepId.HISTORY && currentStep !== StepId.DASHBOARD) {
      localStorage.setItem('current_active_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const startNewAnalysis = () => {
    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];

    // Check if updating or creating new
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };

    if (existingIndex > -1) {
      history[existingIndex] = updatedAnalysis;
    } else {
      history.push(updatedAnalysis);
    }

    localStorage.setItem('analysis_history', JSON.stringify(history));
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    // Trigger re-render by staying on History
    setCurrentStep(StepId.DASHBOARD);
    setTimeout(() => setCurrentStep(StepId.HISTORY), 10);
  };

  const addAction = () => {
    const newAction: Action = {
      id: Date.now().toString(),
      description: '',
      type: 'Corretiva',
      responsible: '',
      dueDate: '',
      status: 'Aberta'
    };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-300 bg-white text-slate-900 rounded-lg p-3 md:p-4 text-base focus:ring-2 focus:ring-blue-500 outline-none border shadow-sm placeholder:text-slate-400 appearance-none";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input 
                  type="text" 
                  value={analysis.area}
                  onChange={e => updateAnalysis({ area: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Refino de Papel"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input 
                  type="text" 
                  value={analysis.equipment}
                  onChange={e => updateAnalysis({ equipment: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Motor Refinador MP3"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input 
                  type="text" 
                  value={analysis.tag}
                  onChange={e => updateAnalysis({ tag: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: MOT-301-A"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input 
                  type="date" 
                  value={analysis.failureDate}
                  onChange={e => updateAnalysis({ failureDate: e.target.value })}
                  className={inputClasses} 
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Descrição Breve do Problema</label>
              <textarea 
                value={analysis.description}
                onChange={e => updateAnalysis({ description: e.target.value })}
                className={`${inputClasses} h-32 md:h-40 resize-none`} 
                placeholder="Descreva o que houve de forma clara e técnica..."
              />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when },
                { field: 'who', label: 'QUEM identificou?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">{item.label}</label>
                  <textarea 
                    value={(analysis as any)[item.field]}
                    onChange={e => updateAnalysis({ [item.field]: e.target.value })}
                    className={`${inputClasses} h-24 resize-none`} 
                  />
                  {item.tip && <p className="text-xs text-slate-500 mt-1 italic leading-tight">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Sintoma Observado</label>
                <input 
                  type="text" 
                  value={analysis.symptom}
                  onChange={e => updateAnalysis({ symptom: e.target.value })}
                  className={inputClasses} 
                  placeholder="Ex: Vibração excessiva, fumaça..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Frequência da Falha</label>
                <div className="flex flex-col sm:flex-row gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-4 rounded-xl border cursor-pointer transition-all shadow-sm ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input 
                        type="radio" 
                        className="hidden" 
                        checked={analysis.frequency === f} 
                        onChange={() => updateAnalysis({ frequency: f as any })}
                      />
                      {f}
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Histórico Recente de Intervenções</label>
                <textarea 
                  value={analysis.history}
                  onChange={e => updateAnalysis({ history: e.target.value })}
                  className={`${inputClasses} h-32 md:h-40 resize-none`} 
                  placeholder="Houve manutenção preventiva recente?"
                />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn px-2 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button 
                onClick={handleSuggestCause}
                className="w-full sm:w-auto text-xs bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-2 px-4 rounded-full border border-slate-300 transition-colors flex items-center justify-center gap-2"
              >
                <i className="fas fa-robot text-blue-600"></i> Sugerir com IA
              </button>
            </div>
            <div className="space-y-6 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden sm:block"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-4 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30 pointer-events-none' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nível {idx + 1}</label>
                    <textarea 
                      value={why}
                      onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }}
                      className={`${inputClasses} h-20 resize-none`} 
                      placeholder={idx === 0 ? "Por que a falha ocorreu inicialmente?" : "E por que isso aconteceu?"}
                    />
                  </div>
