              ))}
            </div>
            <div className="mt-8 p-5 md:p-8 bg-blue-700 rounded-2xl text-white shadow-xl">
              <label className="block text-sm font-bold uppercase mb-2 opacity-90">Causa Raiz Identificada</label>
              <input 
                type="text" 
                value={analysis.rootCause}
                onChange={e => updateAnalysis({ rootCause: e.target.value })}
                className="w-full bg-white text-slate-900 rounded-xl p-4 font-black border-none outline-none text-lg shadow-inner placeholder:text-slate-300" 
                placeholder="A causa fundamental é..."
              />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button 
                onClick={addAction}
                className="w-full sm:w-auto bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-3 px-6 rounded-xl flex items-center justify-center gap-2 shadow-lg transition-colors"
              >
                <i className="fas fa-plus"></i> Nova Ação
              </button>
            </div>
            <div className="overflow-x-auto -mx-6 md:mx-0 rounded-xl border border-slate-200 shadow-sm">
              <table className="w-full text-left bg-white min-w-[700px]">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] md:text-xs font-bold border-b">
                  <tr>
                    <th className="px-4 py-4">Ação</th>
                    <th className="px-4 py-4">Tipo</th>
                    <th className="px-4 py-4">Responsável</th>
                    <th className="px-4 py-4">Prazo</th>
                    <th className="px-4 py-4">Status</th>
                    <th className="px-4 py-4"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysis.actions.map(action => (
                    <tr key={action.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3">
                        <textarea 
                          value={action.description}
                          onChange={e => updateAction(action.id, { description: e.target.value })}
                          className="w-full border border-slate-200 bg-white text-slate-900 outline-none focus:ring-1 focus:ring-blue-500 rounded p-2 text-sm shadow-sm"
                          rows={2}
                        />
                      </td>
                      <td className="px-4 py-3">
                        <select 
                          value={action.type}
                          onChange={e => updateAction(action.id, { type: e.target.value as any })}
                          className="text-xs border border-slate-200 rounded p-2 bg-white text-slate-900 shadow-sm font-medium"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={action.responsible}
                          onChange={e => updateAction(action.id, { responsible: e.target.value })}
                          className="text-xs border border-slate-200 rounded p-2 w-full bg-white text-slate-900"
                          placeholder="Nome"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="date" 
                          value={action.dueDate}
                          onChange={e => updateAction(action.id, { dueDate: e.target.value })}
                          className="text-xs border border-slate-200 rounded p-2 w-full bg-white text-slate-900"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[9px] md:text-[10px] font-black px-2 py-1 rounded-full uppercase ${
                          action.status === 'Concluída' ? 'bg-green-100 text-green-800' :
                          action.status === 'Em andamento' ? 'bg-blue-100 text-blue-800' :
                          'bg-amber-100 text-amber-800'
                        }`}>
                          {action.status}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 p-2">
                          <i className="fas fa-trash"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <p className="md:hidden text-center text-xs text-slate-400 font-medium animate-pulse italic">Deslize a tabela para o lado para ver mais campos <i className="fas fa-arrows-left-right ml-1"></i></p>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-2 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2">
                   <i className="fas fa-shield-check text-green-600"></i> Eficácia das Ações
                </h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-3 font-medium">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: true })}
                      className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}
                    >
                      SIM
                    </button>
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: false })}
                      className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}
                    >
                      NÃO
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-slate-600 mb-2 font-medium">Evidências da Eficácia</label>
                  <textarea 
                    value={analysis.effectivenessEvidence}
                    onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })}
                    className={inputClasses + " h-32 resize-none"}
                    placeholder="Resultados medidos..."
                  />
                </div>
              </div>

              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2">
                  <i className="fas fa-sync text-blue-600"></i> Padronização
                </h3>
                <div className="space-y-4">
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm">
                    <input 
                      type="checkbox" 
                      className="w-6 h-6 accent-blue-600"
                      checked={analysis.needsRevision}
                      onChange={e => updateAnalysis({ needsRevision: e.target.checked })}
                    />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Revisar procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm">
                    <input 
                      type="checkbox" 
                      className="w-6 h-6 accent-blue-600"
                      checked={analysis.needsTraining}
                      onChange={e => updateAnalysis({ needsTraining: e.target.checked })}
                    />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Treinar a equipe operacional?</span>
                  </label>
                </div>
                <div className="pt-4">
                  <button 
                    onClick={handleGenerateSummary}
                    disabled={isGeneratingSummary}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 uppercase tracking-wider text-sm"
                  >
                    {isGeneratingSummary ? (
                      <><i className="fas fa-spinner fa-spin"></i> Processando...</>
                    ) : (
                      <><i className="fas fa-robot"></i> Gerar Resumo Inteligente</>
                    )}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-slate-900 text-white p-6 md:p-10 rounded-3xl shadow-2xl mt-12">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-3">
                    <i className="fas fa-file-alt text-blue-400"></i> Resumo Executivo
                  </h2>
                  <span className="bg-blue-500/20 text-blue-400 text-[10px] px-3 py-1 rounded-full uppercase tracking-widest font-black">IA Report</span>
                </div>
                <div className="bg-white/5 p-5 md:p-8 rounded-2xl border border-white/10">
                    <p className="text-slate-200 leading-relaxed text-base md:text-lg">
                      {analysis.summary}
                    </p>
                </div>
                <div className="mt-8 flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2">
                    <i className="fas fa-print"></i> PDF
                  </button>
                  <button className="bg-green-600 hover:bg-green-700 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2">
                    <i className="fas fa-share-alt"></i> Compartilhar
                  </button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      case StepId.HISTORY:
        return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 md:h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/50">
              <i className="fas fa-industry text-lg md:text-xl"></i>
            </div>
            <div className="hidden sm:block">
              <h1 className="font-black text-base md:text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[10px] text-blue-400 font-black tracking-widest uppercase">Confiabilidade</p>
            </div>
          </div>
          <nav className="flex gap-1 md:gap-4 text-xs md:text-sm font-bold uppercase tracking-wider">
            <button 
              onClick={startNewAnalysis}
              className={`px-3 py-2 rounded-lg transition-all ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <span className="sm:hidden"><i className="fas fa-plus"></i></span>
              <span className="hidden sm:inline">Nova Análise</span>
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.HISTORY)} 
              className={`px-3 py-2 rounded-lg transition-all ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <span className="sm:hidden"><i className="fas fa-history"></i></span>
              <span className="hidden sm:inline">Histórico</span>
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              className={`px-3 py-2 rounded-lg transition-all ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <span className="sm:hidden"><i className="fas fa-chart-line"></i></span>
              <span className="hidden sm:inline">Dashboard</span>
            </button>
          </nav>
        </div>
      </header>

      {/* PDCA Progress Bar - Scrollable on mobile */}
      {currentStep < StepId.DASHBOARD && (
        <div className="bg-white border-b sticky top-16 md:top-20 z-40 overflow-x-auto no-scrollbar shadow-sm">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-3 min-w-[700px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  className={`flex flex-col items-center gap-1.5 transition-all flex-shrink-0 ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-9 h-9 md:w-10 md:h-10 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-600 text-white' : 
                    'bg-slate-100 text-slate-400 border border-slate-200'
                  }`}>
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-600' : 'bg-slate-100'}`}></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-6 md:py-10">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden min-h-[500px] flex flex-col">
          <div className="p-4 md:p-12 flex-1">
             {renderStepContent()}
          </div>

          {/* Controls - Fixed at bottom on mobile for better reachability */}
          {currentStep < StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-4 md:p-8 flex items-center justify-between gap-4">
              <button 
                onClick={handleBack}
                disabled={currentStep === StepId.IDENTIFICATION}
                className="flex items-center gap-2 text-slate-500 font-black uppercase tracking-widest hover:text-slate-900 disabled:opacity-30 p-3 md:px-6 transition-colors"
              >
                <i className="fas fa-arrow-left"></i> <span className="hidden sm:inline">Voltar</span>
              </button>

              <div className="flex gap-2 sm:gap-4 flex-1 sm:flex-initial">
                <button 
                  onClick={finalizeAnalysis}
                  className="hidden sm:flex items-center gap-2 bg-white text-slate-700 border border-slate-300 px-6 py-3 rounded-xl font-bold hover:bg-slate-50 transition-all"
                >
                  <i className="fas fa-save text-blue-600"></i> Salvar e Sair
                </button>

                {currentStep < StepId.VERIFICATION ? (
                  <button 
                    onClick={handleNext}
                    className="flex-1 sm:flex-initial bg-blue-600 hover:bg-blue-700 text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-200 transition-all flex items-center justify-center gap-3 text-sm"
                  >
                    <span>Próximo</span> <i className="fas fa-arrow-right text-xs"></i>
                  </button>
                ) : (
                  <button 
                    onClick={finalizeAnalysis}
                    className="flex-1 sm:flex-initial bg-slate-900 hover:bg-black text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all text-sm"
                  >
                    Finalizar Análise
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t py-8 px-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 text-center md:text-left">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest italic">SWM Brasil - Industrial Intelligence</p>
          <div className="flex gap-8">
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Suporte</button>
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Termos</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  useEffect(() => {
    if (currentStep !== StepId.HISTORY && currentStep !== StepId.DASHBOARD) {
      localStorage.setItem('current_active_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    if (confirm("Deseja iniciar uma nova análise? Os dados não salvos da sessão atual serão perdidos.")) {
      setAnalysis(getInitialState());
      setCurrentStep(StepId.IDENTIFICATION);
      setShowSummary(false);
    }
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];

    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };

    if (existingIndex > -1) {
      history[existingIndex] = updatedAnalysis;
    } else {
      history.push(updatedAnalysis);
    }

    localStorage.setItem('analysis_history', JSON.stringify(history));
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Tem certeza que deseja excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.DASHBOARD);
    setTimeout(() => setCurrentStep(StepId.HISTORY), 10);
  };

  const addAction = () => {
    const newAction: Action = {
      id: Date.now().toString(),
      description: '',
      type: 'Corretiva',
      responsible: '',
      dueDate: '',
      status: 'Aberta'
    };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-300 bg-white text-slate-900 rounded-lg p-4 text-base focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none border shadow-sm placeholder:text-slate-400 appearance-none min-h-[44px]";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">1. Identificação Geral</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label htmlFor="area" className="block text-sm font-semibold text-slate-700 mb-1">Área / Setor</label>
                <input id="area" type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Refino de Papel" />
              </div>
              <div>
                <label htmlFor="equipment" className="block text-sm font-semibold text-slate-700 mb-1">Equipamento</label>
                <input id="equipment" type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Motor Refinador MP3" />
              </div>
              <div>
                <label htmlFor="tag" className="block text-sm font-semibold text-slate-700 mb-1">Tag / Código</label>
                <input id="tag" type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: MOT-301-A" />
              </div>
              <div>
                <label htmlFor="failureDate" className="block text-sm font-semibold text-slate-700 mb-1">Data da Falha</label>
                <input id="failureDate" type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={inputClasses} />
              </div>
            </div>
            <div>
              <label htmlFor="description" className="block text-sm font-semibold text-slate-700 mb-1">Descrição Breve do Problema</label>
              <textarea id="description" value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Descreva o que houve de forma clara e técnica..." />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what, id: 'w5h1_what' },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where, id: 'w5h1_where' },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when, id: 'w5h1_when' },
                { field: 'who', label: 'QUEM identificou?', tip: '', id: 'w5h1_who' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch, id: 'w5h1_impact' },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how, id: 'w5h1_how' },
              ].map((item) => (
                <div key={item.field}>
                  <label htmlFor={item.id} className="block text-sm font-semibold text-slate-700 mb-1">{item.label}</label>
                  <textarea id={item.id} value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-24 resize-none`} />
                  {item.tip && <p className="text-xs text-slate-500 mt-1 italic leading-tight">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label htmlFor="symptom" className="block text-sm font-semibold text-slate-700 mb-1">Sintoma Observado</label>
                <input id="symptom" type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração excessiva, fumaça..." />
              </div>
              <fieldset>
                <legend className="block text-sm font-semibold text-slate-700 mb-2">Frequência da Falha</legend>
                <div className="flex flex-col sm:flex-row gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-4 rounded-xl border cursor-pointer transition-all shadow-sm ring-offset-2 focus-within:ring-2 focus-within:ring-blue-500 ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      {f}
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label htmlFor="history_det" className="block text-sm font-semibold text-slate-700 mb-1">Histórico Recente de Intervenções</label>
                <textarea id="history_det" value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Houve manutenção preventiva recente?" />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button onClick={handleSuggestCause} aria-label="Sugerir causa raiz usando Inteligência Artificial" className="w-full sm:w-auto text-xs bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-3 px-6 rounded-full border border-slate-300 transition-colors flex items-center justify-center gap-2 min-h-[44px]">
                <i className="fas fa-robot text-blue-600" aria-hidden="true"></i> Sugerir com IA
              </button>
            </div>
            <div className="space-y-6 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden sm:block"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-4 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30 pointer-events-none' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1" aria-hidden="true">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label htmlFor={`why_${idx}`} className="block text-xs font-bold text-slate-500 uppercase mb-1">Por quê {idx + 1}</label>
                    <textarea id={`why_${idx}`} value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-20 resize-none`} placeholder={idx === 0 ? "Por que a falha ocorreu inicialmente?" : "E por que isso aconteceu?"} />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-8 p-5 md:p-8 bg-blue-700 rounded-2xl text-white shadow-xl">
              <label htmlFor="root_cause_field" className="block text-sm font-bold uppercase mb-2 opacity-90">Causa Raiz Identificada</label>
              <input id="root_cause_field" type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white text-slate-900 rounded-xl p-4 font-black border-none outline-none text-lg shadow-inner placeholder:text-slate-300 min-h-[50px]" placeholder="A causa fundamental é..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button onClick={addAction} aria-label="Adicionar nova ação ao plano" className="w-full sm:w-auto bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-3 px-6 rounded-xl flex items-center justify-center gap-2 shadow-lg transition-colors min-h-[48px]">
                <i className="fas fa-plus" aria-hidden="true"></i> Nova Ação
              </button>
            </div>

            {/* Mobile Cards for Actions */}
            <div className="md:hidden space-y-4">
              {analysis.actions.length > 0 ? (
                analysis.actions.map(action => (
                  <div key={action.id} className="bg-white border border-slate-200 rounded-2xl p-4 shadow-sm space-y-3">
                    <div>
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Ação</label>
                      <textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full border-slate-200 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 mt-1" rows={2} />
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo</label>
                        <select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="w-full border-slate-200 rounded-lg p-2 text-xs mt-1">
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </div>
                      <div>
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Responsável</label>
                        <input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="w-full border-slate-200 rounded-lg p-2 text-xs mt-1" />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-3 items-center">
                      <div>
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Prazo</label>
                        <input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="w-full border-slate-200 rounded-lg p-2 text-xs mt-1" />
                      </div>
                      <div className="flex justify-end pt-4">
                        <button onClick={() => removeAction(action.id)} aria-label="Remover ação" className="text-red-500 p-2"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-10 text-slate-400 italic">Nenhuma ação cadastrada.</div>
              )}
            </div>

            {/* Desktop Table */}
            <div className="hidden md:block overflow-x-auto rounded-xl border border-slate-200 shadow-sm">
              <table className="w-full text-left bg-white min-w-[700px]">
                <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-bold border-b">
                  <tr>
                    <th className="px-4 py-4">Ação</th>
                    <th className="px-4 py-4">Tipo</th>
                    <th className="px-4 py-4">Responsável</th>
                    <th className="px-4 py-4">Prazo</th>
                    <th className="px-4 py-4">Status</th>
                    <th className="px-4 py-4"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysis.actions.map(action => (
                    <tr key={action.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3"><textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full border border-slate-200 bg-white text-slate-900 rounded p-2 text-sm" rows={2} /></td>
                      <td className="px-4 py-3"><select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="text-xs border border-slate-200 rounded p-2 bg-white"><option>Corretiva</option><option>Preventiva</option><option>Melhoria</option></select></td>
                      <td className="px-4 py-3"><input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="text-xs border border-slate-200 rounded p-2 w-full" /></td>
                      <td className="px-4 py-3"><input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="text-xs border border-slate-200 rounded p-2 w-full" /></td>
                      <td className="px-4 py-3"><span className={`text-[10px] font-black px-2 py-1 rounded-full uppercase ${action.status === 'Concluída' ? 'bg-green-100 text-green-800' : action.status === 'Em andamento' ? 'bg-blue-100 text-blue-800' : 'bg-amber-100 text-amber-800'}`}>{action.status}</span></td>
                      <td className="px-4 py-3"><button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 p-2"><i className="fas fa-trash"></i></button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2"><i className="fas fa-shield-check text-green-600" aria-hidden="true"></i> Eficácia das Ações</h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-3 font-medium">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}>SIM</button>
                    <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}>NÃO</button>
                  </div>
                </div>
                <div>
                  <label htmlFor="effectiveness_evid" className="block text-sm text-slate-600 mb-2 font-medium">Evidências da Eficácia</label>
                  <textarea id="effectiveness_evid" value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-32 resize-none"} placeholder="Resultados medidos..." />
                </div>
              </div>

              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2"><i className="fas fa-sync text-blue-600" aria-hidden="true"></i> Padronização</h3>
                <div className="space-y-4">
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm focus-within:ring-2 focus-within:ring-blue-500">
                    <input type="checkbox" className="w-6 h-6 accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Revisar procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm focus-within:ring-2 focus-within:ring-blue-500">
                    <input type="checkbox" className="w-6 h-6 accent-blue-600" checked={analysis.needsTraining} onChange={e => updateAnalysis({ needsTraining: e.target.checked })} />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Treinar a equipe operacional?</span>
                  </label>
                </div>
                <div className="pt-4">
                  <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 uppercase tracking-wider text-sm min-h-[56px]">
                    {isGeneratingSummary ? (<><i className="fas fa-spinner fa-spin" aria-hidden="true"></i> Processando...</>) : (<><i className="fas fa-robot" aria-hidden="true"></i> Gerar Resumo Inteligente</>)}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div aria-live="polite" className="animate-slideUp bg-slate-900 text-white p-6 md:p-10 rounded-3xl shadow-2xl mt-12">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-3"><i className="fas fa-file-alt text-blue-400" aria-hidden="true"></i> Resumo Executivo</h2>
                  <span className="bg-blue-500/20 text-blue-400 text-[10px] px-3 py-1 rounded-full uppercase tracking-widest font-black">IA Report</span>
                </div>
                <div className="bg-white/5 p-5 md:p-8 rounded-2xl border border-white/10">
                    <p className="text-slate-200 leading-relaxed text-base md:text-lg">{analysis.summary}</p>
                </div>
                <div className="mt-8 flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 min-h-[50px]"><i className="fas fa-print"></i> PDF</button>
                  <button className="bg-green-600 hover:bg-green-700 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 min-h-[50px]"><i className="fas fa-share-alt"></i> Compartilhar</button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      case StepId.HISTORY:
        return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 md:h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/50" aria-hidden="true">
              <i className="fas fa-industry text-lg md:text-xl"></i>
            </div>
            <div className="hidden sm:block">
              <h1 className="font-black text-base md:text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[10px] text-blue-400 font-black tracking-widest uppercase">Confiabilidade</p>
            </div>
          </div>
          <nav aria-label="Navegação Principal" className="flex gap-1 md:gap-4 text-xs md:text-sm font-bold uppercase tracking-wider">
            <button onClick={startNewAnalysis} className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}>
              <i className="fas fa-plus" aria-hidden="true"></i>
              <span className="hidden sm:inline">Nova Análise</span>
            </button>
            <button onClick={() => setCurrentStep(StepId.HISTORY)} className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}>
              <i className="fas fa-history" aria-hidden="true"></i>
              <span className="hidden sm:inline">Histórico</span>
            </button>
            <button onClick={() => setCurrentStep(StepId.DASHBOARD)} className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}>
              <i className="fas fa-chart-line" aria-hidden="true"></i>
              <span className="hidden sm:inline">Dashboard</span>
            </button>
          </nav>
        </div>
      </header>

      {currentStep < StepId.DASHBOARD && (
        <nav aria-label="Progresso da Análise" className="bg-white border-b sticky top-16 md:top-20 z-40 overflow-x-auto no-scrollbar shadow-sm">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-3 min-w-[700px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  aria-current={currentStep === step.id ? "step" : undefined}
                  aria-label={`Ir para etapa: ${step.label}`}
                  className={`flex flex-col items-center gap-1.5 transition-all flex-shrink-0 ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-9 h-9 md:w-10 md:h-10 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-600 text-white' : 
                    'bg-slate-100 text-slate-400 border border-slate-200'
                  }`} aria-hidden="true">
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-600' : 'bg-slate-100'}`} aria-hidden="true"></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </nav>
      )}

      <main id="main-content" className="flex-1 max-w-7xl mx-auto w-full px-4 py-6 md:py-10">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden min-h-[500px] flex flex-col">
          <div className="p-4 md:p-12 flex-1">
             {renderStepContent()}
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-4 md:p-8 flex items-center justify-between gap-4">
              <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center gap-2 text-slate-500 font-black uppercase tracking-widest hover:text-slate-900 disabled:opacity-30 p-4 transition-colors min-h-[48px]">
                <i className="fas fa-arrow-left" aria-hidden="true"></i> <span className="hidden sm:inline">Voltar</span>
              </button>

              <div className="flex gap-2 sm:gap-4 flex-1 sm:flex-initial">
                <button onClick={finalizeAnalysis} className="hidden sm:flex items-center gap-2 bg-white text-slate-700 border border-slate-300 px-6 py-4 rounded-2xl font-bold hover:bg-slate-50 transition-all min-h-[48px]">
                  <i className="fas fa-save text-blue-600" aria-hidden="true"></i> Salvar e Sair
                </button>

                {currentStep < StepId.VERIFICATION ? (
                  <button onClick={handleNext} className="flex-1 sm:flex-initial bg-blue-600 hover:bg-blue-700 text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-200 transition-all flex items-center justify-center gap-3 text-sm min-h-[56px]">
                    <span>Próximo</span> <i className="fas fa-arrow-right text-xs" aria-hidden="true"></i>
                  </button>
                ) : (
                  <button onClick={finalizeAnalysis} className="flex-1 sm:flex-initial bg-slate-900 hover:bg-black text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all text-sm min-h-[56px]">
                    Finalizar Análise
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t py-8 px-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 text-center md:text-left">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest italic">SWM Brasil - Industrial Intelligence & Reliability</p>
          <div className="flex gap-8">
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Suporte</button>
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Acessibilidade</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Analysis, IshikawaCategory, Attachment } from '../types';
import { ISHIKAWA_QUESTIONS } from '../constants';

interface Props {
  analysis: Analysis;
  updateAnalysis: (data: Partial<Analysis>) => void;
}

const IshikawaComponent: React.FC<Props> = ({ analysis, updateAnalysis }) => {
  const fileInputRefs = {
    machine: useRef<HTMLInputElement>(null),
    method: useRef<HTMLInputElement>(null),
    material: useRef<HTMLInputElement>(null),
    manpower: useRef<HTMLInputElement>(null),
    measurement: useRef<HTMLInputElement>(null),
    environment: useRef<HTMLInputElement>(null),
  };

  const handleCauseChange = (category: keyof Analysis['ishikawa'], index: number, value: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes[index] = value;
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const addCause = (category: keyof Analysis['ishikawa']) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.push("");
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const removeCause = (category: keyof Analysis['ishikawa'], index: number) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.splice(index, 1);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const handleFileUpload = (category: keyof Analysis['ishikawa'], e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();
    reader.onload = (event) => {
      const newAttachment: Attachment = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        type: file.type,
        size: file.size,
        dataUrl: event.target?.result as string,
      };

      const newIshikawa = { ...analysis.ishikawa };
      newIshikawa[category].attachments = [...(newIshikawa[category].attachments || []), newAttachment];
      updateAnalysis({ ishikawa: newIshikawa });

      if (fileInputRefs[category].current) {
        fileInputRefs[category].current!.value = "";
      }
    };
    reader.readAsDataURL(file);
  };

  const removeAttachment = (category: keyof Analysis['ishikawa'], attachmentId: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].attachments = newIshikawa[category].attachments.filter(a => a.id !== attachmentId);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const renderCategory = (category: keyof Analysis['ishikawa'], label: string, icon: string) => (
    <section className="bg-white p-5 md:p-6 rounded-2xl shadow-sm border border-slate-200 hover:border-blue-400 transition-all flex flex-col h-full" aria-labelledby={`title-${category}`}>
      <div className="flex items-center gap-3 mb-4 border-b border-slate-100 pb-3">
        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center border border-slate-100 shadow-inner" aria-hidden="true">
          <i className={`fas ${icon} text-blue-600`}></i>
        </div>
        <h3 id={`title-${category}`} className="font-black text-slate-800 uppercase tracking-widest text-xs md:text-sm">{label}</h3>
      </div>
      <p className="text-[11px] text-slate-500 mb-5 italic leading-snug">{ISHIKAWA_QUESTIONS[category]}</p>

      <div className="space-y-3 flex-1">
        {analysis.ishikawa[category].causes.map((cause, idx) => (
          <div key={idx} className="flex gap-2 animate-fadeIn items-center">
            <input
              type="text"
              value={cause}
              onChange={(e) => handleCauseChange(category, idx, e.target.value)}
              placeholder="Descreva a causa..."
              aria-label={`Causa ${idx + 1} para ${label}`}
              className="flex-1 text-sm bg-slate-50 border-slate-200 text-slate-900 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none border shadow-inner font-medium placeholder:text-slate-400 min-h-[44px]"
            />
            <button 
              onClick={() => removeCause(category, idx)}
              className="text-slate-300 hover:text-red-500 transition-colors p-3 min-h-[44px] min-w-[44px]"
              aria-label={`Remover causa ${idx + 1} de ${label}`}
            >
              <i className="fas fa-times" aria-hidden="true"></i>
            </button>
          </div>
        ))}

        {analysis.ishikawa[category].attachments && analysis.ishikawa[category].attachments.length > 0 && (
          <div className="mt-6 pt-4 border-t border-dashed border-slate-200 space-y-3">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Evidências Anexadas</p>
            <ul className="grid grid-cols-1 gap-2">
              {analysis.ishikawa[category].attachments.map((file) => (
                <li key={file.id} className="bg-blue-50/50 border border-blue-100 rounded-xl px-3 py-2 flex items-center gap-3 group">
                  <i className={`fas ${file.type.startsWith('image/') ? 'fa-image' : 'fa-file-alt'} text-blue-500`} aria-hidden="true"></i>
                  <span className="text-[11px] font-bold text-slate-700 truncate flex-1">{file.name}</span>
                  <button 
                    onClick={() => removeAttachment(category, file.id)}
                    className="text-slate-400 hover:text-red-500 transition-colors p-2 min-h-[40px] min-w-[40px]"
                    aria-label={`Remover anexo ${file.name}`}
                  >
                    <i className="fas fa-trash-alt text-[10px]" aria-hidden="true"></i>
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-3 pt-5 border-t border-slate-100">
        <button 
          onClick={() => addCause(category)}
          className="flex-1 text-[10px] text-blue-700 font-black bg-blue-50 hover:bg-blue-100 rounded-xl py-4 flex items-center justify-center gap-2 uppercase tracking-widest transition-all min-h-[44px]"
        >
          <i className="fas fa-plus-circle" aria-hidden="true"></i> Causa
        </button>

        <button 
          onClick={() => fileInputRefs[category].current?.click()}
          className="flex-1 text-[10px] text-slate-600 font-black bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl py-4 flex items-center justify-center gap-2 uppercase tracking-widest transition-all min-h-[44px]"
          aria-label={`Anexar evidência para ${label}`}
        >
          <i className="fas fa-paperclip" aria-hidden="true"></i> Anexar
        </button>

        <input 
          type="file" 
          ref={fileInputRefs[category]}
          onChange={(e) => handleFileUpload(category, e)}
          className="hidden"
          accept="image/*,.pdf,.doc,.docx,.xls,.xlsx"
        />
      </div>
    </section>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
      {renderCategory('machine', 'Máquina', 'fa-cogs')}
      {renderCategory('method', 'Método', 'fa-book')}
      {renderCategory('manpower', 'Mão de Obra', 'fa-users')}
      {renderCategory('material', 'Material', 'fa-box-open')}
      {renderCategory('measurement', 'Medição', 'fa-ruler-combined')}
      {renderCategory('environment', 'Meio Ambiente', 'fa-leaf')}
    </div>
  );
};

