        measurement: { causes: ["Termopar de proteção não atuou a tempo (ponto de leitura distante do calor)"], attachments: [] },
        environment: { causes: ["Alta temperatura ambiente no local (42°C)"], attachments: [] },
      },
      actions: [
        { id: "1", description: "Realizar alinhamento a laser de precisão no conjunto motor-refinador", type: "Corretiva", responsible: "Equipe Mecânica", dueDate: "2024-05-20", status: "Concluída" },
        { id: "2", description: "Revisar plano de manutenção preditiva (vibração) para frequência quinzenal", type: "Melhoria", responsible: "Eng. Confiabilidade", dueDate: "2024-06-01", status: "Em andamento" },
        { id: "3", description: "Treinar equipe sobre uso de alinhadores laser e tolerâncias técnicas", type: "Preventiva", responsible: "Supervisor Manut.", dueDate: "2024-06-15", status: "Aberta" }
      ],
      reoccurred: false,
      effectivenessEvidence: "MTBF do ativo subiu de 400h para 2200h após alinhamento laser.",
      needsRevision: true,
      needsTraining: true,
    };
    setAnalysis(demoData);
    alert("Simulação concluída! Todos os campos foram preenchidos com um caso real de Refinador Industrial. Você pode navegar pelas etapas ou ir direto para 'Verificação' para gerar o resumo IA.");
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [...analysis.actions, newAction] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-300 bg-white text-slate-900 rounded-lg p-4 text-base focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none border shadow-sm placeholder:text-slate-400 appearance-none min-h-[44px]";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <header className="border-b pb-4 mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
               <div>
                  <h2 className="text-xl font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-xs text-slate-500 font-medium">Preencha os dados básicos ou use a simulação rápida.</p>
               </div>
               <button 
                  onClick={simulateFullAnalysis}
                  className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-lg border border-amber-200 transition-all flex items-center gap-2"
               >
                  <i className="fas fa-magic"></i> Simular Caso Real
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label htmlFor="area" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Área / Setor</label>
                <input id="area" type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Refino de Papel" />
              </div>
              <div>
                <label htmlFor="equipment" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Equipamento</label>
                <input id="equipment" type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Motor Refinador MP3" />
              </div>
              <div>
                <label htmlFor="tag" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Tag / Código</label>
                <input id="tag" type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: MOT-301-A" />
              </div>
              <div>
                <label htmlFor="failureDate" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Data da Falha</label>
                <input id="failureDate" type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={inputClasses} />
              </div>
            </div>
            <div>
              <label htmlFor="description" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Descrição Breve do Problema</label>
              <textarea id="description" value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="O que aconteceu de forma clara e técnica..." />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what, id: 'w5h1_what' },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where, id: 'w5h1_where' },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when, id: 'w5h1_when' },
                { field: 'who', label: 'QUEM identificou?', tip: '', id: 'w5h1_who' },
                { field: 'howMuch', label: 'QUANTO impacto gerou?', tip: TIPS.howMuch, id: 'w5h1_impact' },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how, id: 'w5h1_how' },
              ].map((item) => (
                <div key={item.field}>
                  <label htmlFor={item.id} className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">{item.label}</label>
                  <textarea id={item.id} value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-24 resize-none`} />
                  {item.tip && <p className="text-[10px] text-slate-400 mt-1 italic leading-tight">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label htmlFor="symptom" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Sintoma Observado</label>
                <input id="symptom" type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração excessiva, fumaça..." />
              </div>
              <fieldset>
                <legend className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Frequência da Falha</legend>
                <div className="flex flex-col sm:flex-row gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-4 rounded-xl border cursor-pointer transition-all shadow-sm ring-offset-2 focus-within:ring-2 focus-within:ring-blue-500 ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      {f}
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label htmlFor="history_det" className="block text-xs font-bold text-slate-500 uppercase mb-1 tracking-wider">Histórico Recente de Intervenções</label>
                <textarea id="history_det" value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Houve manutenção preventiva recente?" />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button onClick={handleSuggestCause} className="w-full sm:w-auto text-xs bg-blue-50 hover:bg-blue-100 text-blue-700 font-bold py-3 px-6 rounded-full border border-blue-200 transition-colors flex items-center justify-center gap-2 min-h-[44px]">
                <i className="fas fa-robot"></i> Sugerir com IA
              </button>
            </div>
            <div className="space-y-6 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden sm:block"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-4 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30 pointer-events-none' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold shadow-md z-10 flex-shrink-0 mt-1">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label htmlFor={`why_${idx}`} className="block text-xs font-bold text-slate-500 uppercase mb-1">Por quê {idx + 1}</label>
                    <textarea id={`why_${idx}`} value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-20 resize-none`} placeholder={idx === 0 ? "Por que ocorreu?" : "E por que isso?"} />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-8 p-5 md:p-8 bg-slate-900 rounded-2xl text-white shadow-xl">
              <label htmlFor="root_cause_field" className="block text-xs font-bold uppercase mb-2 opacity-70 tracking-widest">Causa Raiz Identificada</label>
              <input id="root_cause_field" type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-xl p-4 font-black border border-white/20 outline-none text-lg shadow-inner placeholder:text-white/20" placeholder="A causa fundamental é..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
             <h2 className="text-xl font-bold border-b pb-2 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 border-b pb-2">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
              <button onClick={addAction} className="w-full sm:w-auto bg-green-600 hover:bg-green-700 text-white text-sm font-bold py-3 px-6 rounded-xl flex items-center justify-center gap-2 shadow-lg transition-colors min-h-[48px]">
                <i className="fas fa-plus"></i> Nova Ação
              </button>
            </div>

            <div className="md:hidden space-y-4">
              {analysis.actions.length > 0 ? (
                analysis.actions.map(action => (
                  <div key={action.id} className="bg-white border border-slate-200 rounded-2xl p-4 shadow-sm space-y-3">
                    <div>
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Ação</label>
                      <textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full border-slate-200 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 mt-1" rows={2} />
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo</label>
                        <select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="w-full border-slate-200 rounded-lg p-2 text-xs mt-1">
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </div>
                      <div>
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Responsável</label>
                        <input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="w-full border-slate-200 rounded-lg p-2 text-xs mt-1" />
                      </div>
                    </div>
                    <div className="flex justify-end pt-2">
                      <button onClick={() => removeAction(action.id)} className="text-red-500 p-2"><i className="fas fa-trash-alt"></i></button>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-10 text-slate-400 italic">Nenhuma ação cadastrada.</div>
              )}
            </div>

            <div className="hidden md:block overflow-x-auto rounded-xl border border-slate-200 shadow-sm">
              <table className="w-full text-left bg-white min-w-[700px]">
                <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold border-b">
                  <tr>
                    <th className="px-4 py-4">Ação</th>
                    <th className="px-4 py-4">Tipo</th>
                    <th className="px-4 py-4">Responsável</th>
                    <th className="px-4 py-4">Prazo</th>
                    <th className="px-4 py-4">Status</th>
                    <th className="px-4 py-4"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysis.actions.map(action => (
                    <tr key={action.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3"><textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full border border-slate-200 bg-white text-slate-900 rounded p-2 text-sm" rows={2} /></td>
                      <td className="px-4 py-3"><select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="text-xs border border-slate-200 rounded p-2 bg-white"><option>Corretiva</option><option>Preventiva</option><option>Melhoria</option></select></td>
                      <td className="px-4 py-3"><input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="text-xs border border-slate-200 rounded p-2 w-full" /></td>
                      <td className="px-4 py-3"><input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="text-xs border border-slate-200 rounded p-2 w-full" /></td>
                      <td className="px-4 py-3"><span className={`text-[10px] font-black px-2 py-1 rounded-full uppercase ${action.status === 'Concluída' ? 'bg-green-100 text-green-800' : action.status === 'Em andamento' ? 'bg-blue-100 text-blue-800' : 'bg-amber-100 text-amber-800'}`}>{action.status}</span></td>
                      <td className="px-4 py-3"><button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 p-2"><i className="fas fa-trash"></i></button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-2 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2"><i className="fas fa-shield-check text-green-600"></i> Eficácia das Ações</h3>
                <div>
                  <label className="block text-sm text-slate-600 mb-3 font-medium">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}>SIM</button>
                    <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-4 border rounded-xl font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'}`}>NÃO</button>
                  </div>
                </div>
                <div>
                  <label htmlFor="effectiveness_evid" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Evidências da Eficácia</label>
                  <textarea id="effectiveness_evid" value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-32 resize-none"} placeholder="Resultados medidos..." />
                </div>
              </div>

              <div className="bg-white p-5 md:p-8 rounded-2xl border border-slate-200 shadow-sm space-y-5">
                <h3 className="font-bold text-slate-700 flex items-center gap-2"><i className="fas fa-sync text-blue-600"></i> Padronização</h3>
                <div className="space-y-4">
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm">
                    <input type="checkbox" className="w-6 h-6 accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Revisar procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-4 p-4 border border-slate-200 rounded-xl cursor-pointer bg-white hover:bg-slate-50 shadow-sm">
                    <input type="checkbox" className="w-6 h-6 accent-blue-600" checked={analysis.needsTraining} onChange={e => updateAnalysis({ needsTraining: e.target.checked })} />
                    <span className="text-sm text-slate-800 font-semibold leading-tight">Treinar a equipe operacional?</span>
                  </label>
                </div>
                <div className="pt-4">
                  <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 uppercase tracking-wider text-sm min-h-[56px]">
                    {isGeneratingSummary ? (<><i className="fas fa-spinner fa-spin"></i> Processando...</>) : (<><i className="fas fa-robot"></i> Gerar Resumo Inteligente</>)}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-slate-900 text-white p-6 md:p-10 rounded-3xl shadow-2xl mt-12">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold flex items-center gap-3"><i className="fas fa-file-alt text-blue-400"></i> Resumo Executivo</h2>
                  <span className="bg-blue-500/20 text-blue-400 text-[10px] px-3 py-1 rounded-full uppercase tracking-widest font-black">IA Report</span>
                </div>
                <div className="bg-white/5 p-5 md:p-8 rounded-2xl border border-white/10">
                    <p className="text-slate-200 leading-relaxed text-base md:text-lg">{analysis.summary}</p>
                </div>
                <div className="mt-8 flex flex-col sm:flex-row gap-4">
                  <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 min-h-[50px]"><i className="fas fa-print"></i> PDF</button>
                  <button className="bg-green-600 hover:bg-green-700 text-white w-full sm:w-auto px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 min-h-[50px]"><i className="fas fa-share-alt"></i> Compartilhar</button>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      case StepId.HISTORY:
        return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 md:h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/50">
              <i className="fas fa-industry text-lg md:text-xl"></i>
            </div>
            <div className="hidden sm:block">
              <h1 className="font-black text-base md:text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[10px] text-blue-400 font-black tracking-widest uppercase">Confiabilidade</p>
            </div>
          </div>
          <nav className="flex gap-1 md:gap-4 text-xs md:text-sm font-bold uppercase tracking-wider">
            <button 
              onClick={startNewAnalysis} 
              className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <i className="fas fa-plus"></i>
              <span className="hidden sm:inline">Nova Análise</span>
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.HISTORY)} 
              className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <i className="fas fa-history"></i>
              <span className="hidden sm:inline">Histórico</span>
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              className={`px-4 py-2.5 rounded-xl transition-all flex items-center gap-2 min-h-[44px] ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-400 hover:text-white'}`}
            >
              <i className="fas fa-chart-line"></i>
              <span className="hidden sm:inline">Dashboard</span>
            </button>
          </nav>
        </div>
      </header>

      {currentStep < StepId.DASHBOARD && (
        <nav className="bg-white border-b sticky top-16 md:top-20 z-40 overflow-x-auto no-scrollbar shadow-sm">
          <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-3 min-w-[700px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)}
                  className={`flex flex-col items-center gap-1.5 transition-all flex-shrink-0 ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}
                >
                  <div className={`w-9 h-9 md:w-10 md:h-10 rounded-full flex items-center justify-center transition-all ${
                    currentStep === step.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 
                    currentStep > step.id ? 'bg-green-600 text-white' : 
                    'bg-slate-100 text-slate-400 border border-slate-200'
                  }`}>
                    {currentStep > step.id ? <i className="fas fa-check text-xs"></i> : step.icon}
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-tighter ${currentStep === step.id ? 'text-blue-600' : 'text-slate-500'}`}>
                    {step.label}
                  </span>
                </button>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-green-600' : 'bg-slate-100'}`}></div>
                )}
              </React.Fragment>
            ))}
          </div>
        </nav>
      )}

      <main id="main-content" className="flex-1 max-w-7xl mx-auto w-full px-4 py-6 md:py-10">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden min-h-[500px] flex flex-col">
          <div className="p-4 md:p-12 flex-1">
             {renderStepContent()}
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="bg-slate-50 border-t p-4 md:p-8 flex items-center justify-between gap-4">
              <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center gap-2 text-slate-500 font-black uppercase tracking-widest hover:text-slate-900 disabled:opacity-30 p-4 transition-colors min-h-[48px]">
                <i className="fas fa-arrow-left"></i> <span className="hidden sm:inline">Voltar</span>
              </button>

              <div className="flex gap-2 sm:gap-4 flex-1 sm:flex-initial">
                <button onClick={finalizeAnalysis} className="hidden sm:flex items-center gap-2 bg-white text-slate-700 border border-slate-300 px-6 py-4 rounded-2xl font-bold hover:bg-slate-50 transition-all min-h-[48px]">
                  <i className="fas fa-save text-blue-600"></i> Finalizar e Sair
                </button>

                {currentStep < StepId.VERIFICATION ? (
                  <button onClick={handleNext} className="flex-1 sm:flex-initial bg-blue-600 hover:bg-blue-700 text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-200 transition-all flex items-center justify-center gap-3 text-sm min-h-[56px]">
                    <span>Próximo</span> <i className="fas fa-arrow-right text-xs"></i>
                  </button>
                ) : (
                  <button onClick={finalizeAnalysis} className="flex-1 sm:flex-initial bg-slate-900 hover:bg-black text-white px-8 md:px-12 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all text-sm min-h-[56px]">
                    Finalizar Análise
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t py-8 px-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 text-center md:text-left">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest italic">SWM Brasil - Industrial Intelligence & Reliability</p>
          <div className="flex gap-8">
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Suporte</button>
             <button className="text-slate-400 hover:text-blue-600 text-[10px] font-black uppercase tracking-widest transition-colors">Acessibilidade</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasData = analysis.equipment || analysis.description || analysis.area;
    if (hasData) {
      if (!confirm("Deseja iniciar uma NOVA análise? Os dados atuais não finalizados serão perdidos.")) {
        return;
      }
    }
    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const simulateFullAnalysis = () => {
    const demoData: Analysis = {
      ...getInitialState(),
      area: "Produção / Celulose",
      equipment: "Refinador de Ajuste MP3",
      tag: "REF-302-B",
      failureDate: new Date().toISOString().split('T')[0],
      shift: "B - Noturno",
      responsible: "Eng. Ricardo Silva",
      description: "Parada súbita do motor principal do refinador durante a rampa de carga, ocasionando desarme do disjuntor de proteção térmica por sobrecarga.",
      what: "Desarme do motor principal por sobrecorrente.",
      where: "Mancal traseiro do motor de 500cv.",
      when: "Durante o aumento de pressão na câmara de refino (85% de carga).",
      who: "Operador de Painel Sr. João Santos.",
      howMuch: "4 horas de produção perdida (aprox. 120 toneladas de polpa).",
      how: "Alarme sonoro seguido de parada instantânea e sinalização de falha elétrica no supervisório.",
      symptom: "Fumaça leve e cheiro de queimado no compartimento do motor.",
      condition: "Equipamento operando em regime estável há 12 horas.",
      history: "Troca de rolamentos realizada há 6 meses em parada geral.",
      frequency: "Eventual",
      whys: [
        "O motor parou por desarme de proteção térmica (Sobrecarga).",
        "Houve um aumento drástico do torque resistente no eixo.",
        "O rolamento traseiro sofreu superaquecimento e travamento parcial.",
        "Houve perda total de lubrificação por rompimento do selo de vedação.",
        "Fadiga térmica prematura do retentor devido a desalinhamento residual não detectado na montagem."
      ],
      rootCause: "Desalinhamento residual entre motor e acoplamento, excedendo a tolerância térmica do retentor.",
      ishikawa: {
        machine: { causes: ["Desalinhamento motor/refinador", "Fadiga do retentor"], attachments: [] },
        method: { causes: ["Plano de medição de vibração a cada 30 dias (insuficiente para este ativo)"], attachments: [] },
        material: { causes: ["Graxa utilizada estava correta, porém contaminada após ruptura do selo"], attachments: [] },
        manpower: { causes: ["Equipe de manutenção não utilizou alinhador a laser na última intervenção"], attachments: [] },
        measurement: { causes: ["Termopar de proteção não atuou a tempo (ponto de leitura distante do calor)"], attachments: [] },
        environment: { causes: ["Alta temperatura ambiente no local (42°C)"], attachments: [] },
      },
      actions: [
        { id: "1", description: "Realizar alinhamento a laser de precisão no conjunto motor-refinador", type: "Corretiva", responsible: "Equipe Mecânica", dueDate: "2024-05-20", status: "Concluída" },
        { id: "2", description: "Revisar plano de manutenção preditiva (vibração) para frequência quinzenal", type: "Melhoria", responsible: "Eng. Confiabilidade", dueDate: "2024-06-01", status: "Em andamento" },
        { id: "3", description: "Treinar equipe sobre uso de alinhadores laser e tolerâncias técnicas", type: "Preventiva", responsible: "Supervisor Manut.", dueDate: "2024-06-15", status: "Aberta" }
      ],
      reoccurred: false,
      effectivenessEvidence: "MTBF do ativo subiu de 400h para 2200h após alinhamento laser.",
      needsRevision: true,
      needsTraining: true,
    };
    setAnalysis(demoData);
    alert("Simulação concluída!");
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl p-4 text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <header className="border-b pb-4 mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
               <div>
                  <h2 className="text-xl font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Ativo e Contexto</p>
               </div>
               <button 
                  onClick={simulateFullAnalysis}
                  className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-5 py-3 rounded-xl border border-amber-200 transition-all flex items-center gap-2 shadow-sm"
               >
                  <i className="fas fa-bolt"></i> Preencher Demo
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Área / Setor</label>
                <input type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Refino de Papel" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Equipamento</label>
                <input type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Motor Refinador MP3" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Tag / Código</label>
                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: MOT-301-A" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Data da Falha</label>
                <input type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={inputClasses} />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Descrição Breve do Problema</label>
              <textarea value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="O que aconteceu de forma clara e técnica..." />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when },
                { field: 'who', label: 'QUEM identificou?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">{item.label}</label>
                  <textarea value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-24 resize-none`} />
                  {item.tip && <p className="text-[10px] text-slate-400 mt-1 italic">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Sintoma Observado</label>
                <input type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração excessiva, fumaça..." />
              </div>
              <fieldset>
                <legend className="block text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Frequência da Falha</legend>
                <div className="flex flex-col sm:flex-row gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex-1 flex items-center justify-center p-5 rounded-2xl border cursor-pointer transition-all shadow-sm ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-black scale-[1.02]' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      {f}
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Histórico Recente</label>
                <textarea value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Houve manutenção recente?" />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 border-b pb-4">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button onClick={handleSuggestCause} className="w-full sm:w-auto text-xs bg-slate-900 text-white font-black py-3 px-6 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg">
                <i className="fas fa-microchip"></i> Inteligência Artificial
              </button>
            </div>
            <div className="space-y-6 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden sm:block"></div>
