              <input type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-2xl p-5 font-bold border border-white/20 outline-none text-xl shadow-inner placeholder:text-white/20" placeholder="Defina a causa raiz aqui..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
             <h2 className="text-xl font-bold border-b pb-4 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
