      case StepId.ACTIONS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <header className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 border-b pb-4">
              <div>
                <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
                <p className="text-xs text-slate-500 font-medium mt-1 uppercase tracking-widest">Medidas Corretivas e Preventivas</p>
