              <button 
                onClick={addAction} 
                className="w-full sm:w-auto bg-blue-600 hover:bg-blue-700 text-white text-xs font-black py-4 px-8 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-blue-200 transition-all uppercase tracking-widest"
              >
                <i className="fas fa-plus-circle"></i> Adicionar Ação
              </button>
            </header>

            <div className="space-y-6">
              {analysis.actions.length > 0 ? (
                analysis.actions.map((action, index) => (
                  <div 
                    key={action.id} 
                    className="bg-white border-2 border-slate-100 rounded-[28px] p-6 md:p-8 shadow-sm hover:shadow-md hover:border-blue-200 transition-all group relative animate-slideUp"
                    style={{ animationDelay: `${index * 0.05}s` }}
                  >
                    {/* Header do Cartão */}
