                      <div className="flex items-center gap-3">
                        <span className="w-8 h-8 bg-slate-100 text-slate-500 rounded-full flex items-center justify-center font-black text-xs">#{analysis.actions.length - index}</span>
                        <select 
                          value={action.type} 
                          onChange={e => updateAction(action.id, { type: e.target.value as any })} 
                          className="bg-blue-50 text-blue-700 text-[10px] font-black uppercase px-4 py-2 rounded-full border-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </div>

                      <div className="flex items-center gap-4">
                         <div className="flex items-center gap-2">
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status:</span>
                           <select 
                             value={action.status} 
                             onChange={e => updateAction(action.id, { status: e.target.value as any })} 
                             className={`text-[10px] font-black uppercase px-4 py-2 rounded-full border-none focus:ring-2 outline-none cursor-pointer ${
                               action.status === 'Concluída' ? 'bg-green-100 text-green-700' : 
                               action.status === 'Em andamento' ? 'bg-blue-100 text-blue-700' : 
                               'bg-amber-100 text-amber-700'
                             }`}
                           >
                             <option>Aberta</option>
                             <option>Em andamento</option>
                             <option>Concluída</option>
                           </select>
                         </div>
                         <button 
                           onClick={() => removeAction(action.id)} 
                           className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                           title="Excluir Ação"
                         >
                           <i className="fas fa-trash-alt text-sm"></i>
                         </button>
                      </div>
                    </div>

                    {/* Conteúdo do Cartão */}
                    <div className="space-y-6">
                      <div className="w-full">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Descrição da Ação</label>
                        <textarea 
                          value={action.description} 
                          onChange={e => updateAction(action.id, { description: e.target.value })} 
                          className="w-full bg-slate-50 border-none rounded-2xl p-5 text-base text-slate-800 font-medium placeholder:text-slate-300 min-h-[120px] focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none" 
                          placeholder="O que deve ser feito? Seja específico..." 
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="w-full">
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Responsável</label>
                          <div className="relative">
                            <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs"></i>
                            <input 
                              type="text" 
                              value={action.responsible} 
                              onChange={e => updateAction(action.id, { responsible: e.target.value })} 
                              className="w-full bg-slate-50 border-none rounded-2xl pl-10 pr-5 py-4 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none" 
                              placeholder="Nome do responsável" 
                            />
                          </div>
                        </div>
                        <div className="w-full">
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Prazo de Entrega</label>
                          <div className="relative">
                            <i className="fas fa-calendar absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs"></i>
                            <input 
                              type="date" 
                              value={action.dueDate} 
                              onChange={e => updateAction(action.id, { dueDate: e.target.value })} 
                              className="w-full bg-slate-50 border-none rounded-2xl pl-10 pr-5 py-4 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none" 
                            />
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="py-20 text-center border-2 border-dashed border-slate-100 rounded-[32px] bg-slate-50/50">
                  <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm">
                    <i className="fas fa-clipboard-list text-slate-300 text-2xl"></i>
                  </div>
                  <h3 className="text-slate-600 font-black uppercase tracking-widest text-sm">Nenhuma ação definida</h3>
                  <p className="text-slate-400 text-xs mt-2 max-w-xs mx-auto">Clique em "Adicionar Ação" acima para começar a montar o seu plano de contenção e prevenção.</p>
                </div>
              )}
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              <div className="bg-white p-6 md:p-10 rounded-3xl border border-slate-100 shadow-sm space-y-6">
                <h3 className="font-black text-slate-800 flex items-center gap-3 uppercase tracking-widest text-sm"><i className="fas fa-shield-check text-green-600"></i> Eficácia</h3>
                <div>
                  <label className="block text-xs font-bold text-slate-500 mb-4 uppercase tracking-wider">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-5 border-2 rounded-2xl font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}>SIM</button>
                    <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-5 border-2 rounded-2xl font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}>NÃO</button>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 mb-3 uppercase tracking-wider">Evidências</label>
                  <textarea value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-32 resize-none"} placeholder="Resultados numéricos ou qualitativos..." />
                </div>
              </div>

              <div className="bg-white p-6 md:p-10 rounded-3xl border border-slate-100 shadow-sm space-y-6">
                <h3 className="font-black text-slate-800 flex items-center gap-3 uppercase tracking-widest text-sm"><i className="fas fa-sync text-blue-600"></i> Padronização</h3>
                <div className="space-y-4">
                  <label className="flex items-center gap-5 p-5 border-2 border-slate-50 rounded-2xl cursor-pointer bg-slate-50/30 hover:bg-slate-50 transition-all">
                    <input type="checkbox" className="w-6 h-6 rounded-lg accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                    <span className="text-sm text-slate-700 font-bold leading-tight">Revisar procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-5 p-5 border-2 border-slate-50 rounded-2xl cursor-pointer bg-slate-50/30 hover:bg-slate-50 transition-all">
                    <input type="checkbox" className="w-6 h-6 rounded-lg accent-blue-600" checked={analysis.needsTraining} onChange={e => updateAnalysis({ needsTraining: e.target.checked })} />
                    <span className="text-sm text-slate-700 font-bold leading-tight">Treinar a equipe operacional?</span>
                  </label>
                </div>
                <div className="pt-6">
                  <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="w-full bg-slate-900 hover:bg-black disabled:bg-slate-400 text-white font-black py-6 rounded-[24px] shadow-2xl transition-all flex items-center justify-center gap-4 uppercase tracking-widest text-xs">
                    {isGeneratingSummary ? (<><i className="fas fa-cog fa-spin"></i> Analisando...</>) : (<><i className="fas fa-brain"></i> Gerar Resumo Executivo</>)}
                  </button>
                </div>
              </div>
            </div>

            {showSummary && analysis.summary && (
              <div className="animate-slideUp bg-blue-900 text-white p-8 md:p-14 rounded-[40px] shadow-2xl mt-12 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>
                <div className="relative z-10">
                   <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-8">
                     <h2 className="text-2xl md:text-3xl font-black flex items-center gap-4"><i className="fas fa-quote-left text-blue-400 opacity-50"></i> Resumo IA</h2>
                     <div className="flex gap-2">
                       <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-[10px] font-black uppercase tracking-widest px-6 py-3 rounded-full transition-all">PDF</button>
                       <button className="bg-white/10 hover:bg-white/20 text-[10px] font-black uppercase tracking-widest px-6 py-3 rounded-full transition-all">Exportar</button>
                     </div>
                   </div>
                   <div className="bg-white/10 p-8 rounded-[28px] border border-white/10">
                       <p className="text-slate-100 leading-relaxed text-lg font-medium italic">"{analysis.summary}"</p>
                   </div>
                </div>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      case StepId.HISTORY:
        return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F8FAFC]">
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg">
              <i className="fas fa-industry text-lg"></i>
            </div>
            <div>
              <h1 className="font-black text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[9px] text-blue-400 font-black tracking-[0.2em] uppercase mt-1">Industrial Intelligence</p>
            </div>
          </div>
          <nav className="flex gap-2 md:gap-4 font-black uppercase tracking-widest text-[10px]">
            <button onClick={startNewAnalysis} className={`px-5 py-3 rounded-xl transition-all ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-white'}`}>Nova Análise</button>
            <button onClick={() => setCurrentStep(StepId.HISTORY)} className={`px-5 py-3 rounded-xl transition-all ${currentStep === StepId.HISTORY ? 'bg-blue-600 shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-white'}`}>Histórico</button>
            <button onClick={() => setCurrentStep(StepId.DASHBOARD)} className={`px-5 py-3 rounded-xl transition-all ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-white'}`}>Dash</button>
          </nav>
        </div>
      </header>

      {currentStep < StepId.DASHBOARD && (
        <nav className="bg-white border-b sticky top-20 z-40 overflow-x-auto no-scrollbar">
          <div className="max-w-7xl mx-auto px-6 py-6 flex items-center justify-between gap-4 min-w-[800px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button onClick={() => setCurrentStep(step.id)} className={`flex flex-col items-center gap-2 transition-all ${currentStep === step.id ? 'scale-110' : 'opacity-40 hover:opacity-100'}`}>
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs transition-all ${currentStep === step.id ? 'bg-blue-600 text-white shadow-xl ring-4 ring-blue-50' : 'bg-slate-100 text-slate-500'}`}>
                    {currentStep > step.id ? <i className="fas fa-check"></i> : step.icon}
                  </div>
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
                </button>
                {idx < STEPS.length - 1 && <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-blue-600' : 'bg-slate-100'}`}></div>}
              </React.Fragment>
            ))}
          </div>
        </nav>
      )}

      <main className="flex-1 max-w-7xl mx-auto w-full px-6 py-10">
        <div className="bg-white rounded-[40px] shadow-2xl shadow-slate-200/50 border border-slate-100 overflow-hidden flex flex-col min-h-[700px]">
          <div className="p-8 md:p-16 flex-1">
             {renderStepContent()}
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="bg-slate-50/50 border-t border-slate-100 p-8 md:p-12 flex items-center justify-between">
              <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center gap-3 text-slate-400 font-black uppercase tracking-[0.2em] text-[10px] hover:text-slate-900 disabled:opacity-20 transition-all p-4">
                <i className="fas fa-long-arrow-left"></i> Voltar
              </button>

              <div className="flex gap-4">
                {currentStep < StepId.VERIFICATION ? (
                  <button onClick={handleNext} className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] shadow-2xl shadow-blue-200 transition-all flex items-center gap-4">
                    Próximo <i className="fas fa-long-arrow-right"></i>
                  </button>
                ) : (
                  <button onClick={finalizeAnalysis} className="bg-slate-900 hover:bg-black text-white px-12 py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] shadow-2xl transition-all">
                    Finalizar Relatório
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="py-12 px-6">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-8 opacity-40">
          <p className="text-[10px] font-black uppercase tracking-[0.3em]">SWM Brasil &copy; 2024 Reliability Labs</p>
          <div className="flex gap-10 text-[9px] font-black uppercase tracking-widest">
             <button className="hover:text-blue-600">Documentação</button>
             <button className="hover:text-blue-600">Segurança</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasData = analysis.equipment || analysis.description || analysis.area;
    if (hasData) {
      if (!confirm("Deseja iniciar uma NOVA análise? Os dados atuais não finalizados serão perdidos.")) {
        return;
      }
    }
    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const simulateFullAnalysis = () => {
    const demoData: Analysis = {
      ...getInitialState(),
      area: "Produção / Celulose",
      equipment: "Refinador de Ajuste MP3",
      tag: "REF-302-B",
      failureDate: new Date().toISOString().split('T')[0],
      shift: "B - Noturno",
      responsible: "Eng. Ricardo Silva",
      description: "Parada súbita do motor principal do refinador durante a rampa de carga, ocasionando desarme do disjuntor de proteção térmica por sobrecarga.",
      what: "Desarme do motor principal por sobrecorrente.",
      where: "Mancal traseiro do motor de 500cv.",
      when: "Durante o aumento de pressão na câmara de refino (85% de carga).",
      who: "Operador de Painel Sr. João Santos.",
      howMuch: "4 horas de produção perdida (aprox. 120 toneladas de polpa).",
      how: "Alarme sonoro seguido de parada instantânea e sinalização de falha elétrica no supervisório.",
      symptom: "Fumaça leve e cheiro de queimado no compartimento do motor.",
      condition: "Equipamento operando em regime estável há 12 horas.",
      history: "Troca de rolamentos realizada há 6 meses em parada geral.",
      frequency: "Eventual",
      whys: [
        "O motor parou por desarme de proteção térmica (Sobrecarga).",
        "Houve um aumento drástico do torque resistente no eixo.",
        "O rolamento traseiro sofreu superaquecimento e travamento parcial.",
        "Houve perda total de lubrificação por rompimento do selo de vedação.",
        "Fadiga térmica prematura do retentor devido a desalinhamento residual não detectado na montagem."
      ],
      rootCause: "Desalinhamento residual entre motor e acoplamento, excedendo a tolerância térmica do retentor.",
      ishikawa: {
        machine: { causes: ["Desalinhamento motor/refinador", "Fadiga do retentor"], attachments: [] },
        method: { causes: ["Plano de medição de vibração a cada 30 dias (insuficiente para este ativo)"], attachments: [] },
        material: { causes: ["Graxa utilizada estava correta, porém contaminada após ruptura do selo"], attachments: [] },
        manpower: { causes: ["Equipe de manutenção não utilizou alinhador a laser na última intervenção"], attachments: [] },
        measurement: { causes: ["Termopar de proteção não atuou a tempo (ponto de leitura distante do calor)"], attachments: [] },
        environment: { causes: ["Alta temperatura ambiente no local (42°C)"], attachments: [] },
      },
      actions: [
        { id: "1", description: "Realizar alinhamento a laser de precisão no conjunto motor-refinador", type: "Corretiva", responsible: "Equipe Mecânica", dueDate: "2024-05-20", status: "Concluída" },
        { id: "2", description: "Revisar plano de manutenção preditiva (vibração) para frequência quinzenal", type: "Melhoria", responsible: "Eng. Confiabilidade", dueDate: "2024-06-01", status: "Em andamento" },
        { id: "3", description: "Treinar equipe sobre uso de alinhadores laser e tolerâncias técnicas", type: "Preventiva", responsible: "Supervisor Manut.", dueDate: "2024-06-15", status: "Aberta" }
      ],
      reoccurred: false,
      effectivenessEvidence: "MTBF do ativo subiu de 400h para 2200h após alinhamento laser.",
      needsRevision: true,
      needsTraining: true,
    };
    setAnalysis(demoData);
    alert("Simulação concluída!");
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl p-4 text-base focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400 min-h-[44px]";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <header className="border-b pb-4 mb-6 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
               <div>
                  <h2 className="text-xl font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Ativo e Contexto</p>
               </div>
               <button 
                  onClick={simulateFullAnalysis}
                  aria-label="Preencher formulário com dados de exemplo de um caso real"
                  className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-5 py-3 rounded-xl border border-amber-200 transition-all flex items-center gap-2 shadow-sm min-h-[44px]"
               >
                  <i className="fas fa-bolt" aria-hidden="true"></i> Preencher Demo
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label htmlFor="area" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Área / Setor</label>
                <input id="area" type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Refino de Papel" />
              </div>
              <div>
                <label htmlFor="equipment" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Equipamento</label>
                <input id="equipment" type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Motor Refinador MP3" />
              </div>
              <div>
                <label htmlFor="tag" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Tag / Código</label>
                <input id="tag" type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: MOT-301-A" />
              </div>
              <div>
                <label htmlFor="failureDate" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Data da Falha</label>
                <input id="failureDate" type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={inputClasses} />
              </div>
            </div>
            <div>
              <label htmlFor="description" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Descrição Breve do Problema</label>
              <textarea id="description" value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="O que aconteceu de forma clara e técnica..." />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[
                { field: 'what', label: 'O QUE aconteceu?', tip: TIPS.what, id: 'w5h1_what' },
                { field: 'where', label: 'ONDE ocorreu?', tip: TIPS.where, id: 'w5h1_where' },
                { field: 'when', label: 'QUANDO ocorreu?', tip: TIPS.when, id: 'w5h1_when' },
                { field: 'who', label: 'QUEM identificou?', tip: '', id: 'w5h1_who' },
                { field: 'howMuch', label: 'QUANTO impacto?', tip: TIPS.howMuch, id: 'w5h1_howmuch' },
                { field: 'how', label: 'COMO foi percebido?', tip: TIPS.how, id: 'w5h1_how' },
              ].map((item) => (
                <div key={item.field}>
                  <label htmlFor={item.id} className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">{item.label}</label>
                  <textarea id={item.id} value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-24 resize-none`} />
                  {item.tip && <p className="text-[10px] text-slate-400 mt-1 italic">{item.tip}</p>}
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">3. Detalhamento da Falha</h2>
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label htmlFor="symptom" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Sintoma Observado</label>
                <input id="symptom" type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração excessiva, fumaça..." />
              </div>
              <fieldset>
                <legend className="block text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Frequência da Falha</legend>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex items-center justify-center p-5 rounded-2xl border-2 cursor-pointer transition-all shadow-sm min-h-[56px] ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-black scale-[1.02]' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      {f}
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label htmlFor="history_field" className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Histórico Recente</label>
                <textarea id="history_field" value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Houve manutenção recente?" />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 border-b pb-4">
              <h2 className="text-xl font-bold text-slate-800">4. Matriz dos 5 Porquês</h2>
              <button onClick={handleSuggestCause} aria-label="Sugerir causa raiz baseada em IA" className="w-full sm:w-auto text-xs bg-slate-900 text-white font-black py-4 px-6 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg min-h-[48px]">
                <i className="fas fa-microchip" aria-hidden="true"></i> Inteligência Artificial
              </button>
            </div>
            <div className="space-y-6 relative">
              <div className="absolute left-[20px] top-[40px] bottom-[40px] w-0.5 bg-blue-100 hidden sm:block" aria-hidden="true"></div>
              {analysis.whys.map((why, idx) => (
                <div key={idx} className={`flex items-start gap-5 transition-all ${idx > 0 && !analysis.whys[idx-1] ? 'opacity-30' : ''}`}>
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-black shadow-lg z-10 flex-shrink-0" aria-hidden="true">
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                    <label htmlFor={`why_input_${idx}`} className="block text-[10px] font-black text-slate-400 uppercase mb-1">Nível {idx + 1}</label>
                    <textarea id={`why_input_${idx}`} value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-24 resize-none border-slate-100`} placeholder="..." />
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-10 p-6 md:p-10 bg-blue-900 rounded-[32px] text-white shadow-2xl relative overflow-hidden">
              <div className="absolute -right-10 -top-10 opacity-10" aria-hidden="true">
                <i className="fas fa-search-nodes text-[200px]"></i>
              </div>
              <label htmlFor="root_cause_input" className="block text-xs font-black uppercase mb-3 opacity-60 tracking-[0.2em]">Causa Raiz Fundamental</label>
              <input id="root_cause_input" type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-2xl p-5 font-bold border border-white/20 outline-none text-xl shadow-inner placeholder:text-white/20 min-h-[56px]" placeholder="Defina a causa raiz aqui..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
             <h2 className="text-xl font-bold border-b pb-4 text-slate-800">5. Diagrama de Ishikawa (6M)</h2>
             <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />
          </div>
        );

      case StepId.ACTIONS:
        return (
          <div className="space-y-8 animate-fadeIn px-1 md:px-0">
            <header className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 border-b pb-4">
              <div>
                <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação</h2>
                <p className="text-xs text-slate-500 font-medium mt-1 uppercase tracking-widest">Medidas Corretivas e Preventivas</p>
              </div>
              <button 
                onClick={addAction} 
                aria-label="Adicionar nova linha de ação"
                className="w-full sm:w-auto bg-blue-600 hover:bg-blue-700 text-white text-xs font-black py-4 px-8 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-blue-200 transition-all uppercase tracking-widest min-h-[56px]"
              >
                <i className="fas fa-plus-circle" aria-hidden="true"></i> Adicionar Ação
              </button>
            </header>

            <div className="space-y-6" role="list">
              {analysis.actions.length > 0 ? (
                analysis.actions.map((action, index) => (
                  <article 
                    key={action.id} 
                    role="listitem"
                    className="bg-white border-2 border-slate-100 rounded-[28px] p-6 md:p-8 shadow-sm hover:shadow-md hover:border-blue-200 transition-all group relative animate-slideUp"
                    style={{ animationDelay: `${index * 0.05}s` }}
                  >
                    <div className="flex flex-wrap items-center justify-between gap-4 mb-6 pb-4 border-b border-slate-50">
                      <div className="flex items-center gap-3">
                        <span className="w-8 h-8 bg-slate-100 text-slate-500 rounded-full flex items-center justify-center font-black text-xs" aria-hidden="true">#{analysis.actions.length - index}</span>
                        <label htmlFor={`type_${action.id}`} className="sr-only">Tipo de Ação</label>
                        <select 
                          id={`type_${action.id}`}
                          value={action.type} 
                          onChange={e => updateAction(action.id, { type: e.target.value as any })} 
                          className="bg-blue-50 text-blue-700 text-[10px] font-black uppercase px-4 py-3 rounded-full border-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer min-h-[40px]"
                        >
                          <option>Corretiva</option>
                          <option>Preventiva</option>
                          <option>Melhoria</option>
                        </select>
                      </div>

                      <div className="flex items-center gap-4">
                         <div className="flex items-center gap-2">
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest hidden sm:inline">Status:</span>
                           <label htmlFor={`status_${action.id}`} className="sr-only">Status da Ação</label>
                           <select 
                             id={`status_${action.id}`}
                             value={action.status} 
                             onChange={e => updateAction(action.id, { status: e.target.value as any })} 
                             className={`text-[10px] font-black uppercase px-4 py-3 rounded-full border-none focus:ring-2 outline-none cursor-pointer min-h-[40px] ${
                               action.status === 'Concluída' ? 'bg-green-100 text-green-700' : 
                               action.status === 'Em andamento' ? 'bg-blue-100 text-blue-700' : 
                               'bg-amber-100 text-amber-700'
                             }`}
                           >
                             <option>Aberta</option>
                             <option>Em andamento</option>
                             <option>Concluída</option>
                           </select>
                         </div>
                         <button 
                           onClick={() => removeAction(action.id)} 
                           className="w-12 h-12 flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                           aria-label={`Remover ação ${analysis.actions.length - index}`}
                         >
                           <i className="fas fa-trash-alt text-base" aria-hidden="true"></i>
                         </button>
                      </div>
                    </div>

                    <div className="space-y-6">
                      <div className="w-full">
                        <label htmlFor={`desc_${action.id}`} className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Descrição da Ação</label>
                        <textarea 
                          id={`desc_${action.id}`}
                          value={action.description} 
                          onChange={e => updateAction(action.id, { description: e.target.value })} 
                          className="w-full bg-slate-50 border-none rounded-2xl p-5 text-base text-slate-800 font-medium placeholder:text-slate-300 min-h-[120px] focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none" 
                          placeholder="O que deve ser feito? Seja específico..." 
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="w-full">
                          <label htmlFor={`resp_${action.id}`} className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Responsável</label>
                          <div className="relative">
                            <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" aria-hidden="true"></i>
                            <input 
                              id={`resp_${action.id}`}
                              type="text" 
                              value={action.responsible} 
                              onChange={e => updateAction(action.id, { responsible: e.target.value })} 
                              className="w-full bg-slate-50 border-none rounded-2xl pl-10 pr-5 py-5 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none min-h-[56px]" 
                              placeholder="Nome do responsável" 
                            />
                          </div>
                        </div>
                        <div className="w-full">
                          <label htmlFor={`date_${action.id}`} className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Prazo de Entrega</label>
                          <div className="relative">
                            <i className="fas fa-calendar absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 text-xs" aria-hidden="true"></i>
                            <input 
                              id={`date_${action.id}`}
                              type="date" 
                              value={action.dueDate} 
                              onChange={e => updateAction(action.id, { dueDate: e.target.value })} 
                              className="w-full bg-slate-50 border-none rounded-2xl pl-10 pr-5 py-5 text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all outline-none min-h-[56px]" 
                            />
                          </div>
                        </div>
                      </div>
                    </div>
                  </article>
                ))
              ) : (
                <div className="py-20 text-center border-2 border-dashed border-slate-100 rounded-[32px] bg-slate-50/50">
                  <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm" aria-hidden="true">
                    <i className="fas fa-clipboard-list text-slate-300 text-2xl"></i>
                  </div>
                  <h3 className="text-slate-600 font-black uppercase tracking-widest text-sm">Nenhuma ação definida</h3>
                  <p className="text-slate-400 text-xs mt-2 max-w-xs mx-auto">Clique em "Adicionar Ação" acima para começar a montar o seu plano de contenção e prevenção.</p>
                </div>
              )}
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn px-1 md:px-0">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
              <section className="bg-white p-6 md:p-10 rounded-3xl border border-slate-100 shadow-sm space-y-6" aria-labelledby="ef-title">
                <h3 id="ef-title" className="font-black text-slate-800 flex items-center gap-3 uppercase tracking-widest text-sm"><i className="fas fa-shield-check text-green-600" aria-hidden="true"></i> Eficácia</h3>
                <div>
                  <label className="block text-xs font-bold text-slate-500 mb-4 uppercase tracking-wider">A falha voltou a ocorrer?</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: true })} 
                      aria-pressed={analysis.reoccurred === true}
                      className={`flex-1 py-6 border-2 rounded-2xl font-black transition-all min-h-[64px] ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}
                    >
                      SIM
                    </button>
                    <button 
                      onClick={() => updateAnalysis({ reoccurred: false })} 
                      aria-pressed={analysis.reoccurred === false}
                      className={`flex-1 py-6 border-2 rounded-2xl font-black transition-all min-h-[64px] ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}
                    >
                      NÃO
                    </button>
                  </div>
                </div>
                <div>
                  <label htmlFor="effectiveness_evidence_field" className="block text-xs font-bold text-slate-500 mb-3 uppercase tracking-wider">Evidências</label>
                  <textarea id="effectiveness_evidence_field" value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-32 resize-none"} placeholder="Resultados numéricos ou qualitativos..." />
                </div>
              </section>

              <section className="bg-white p-6 md:p-10 rounded-3xl border border-slate-100 shadow-sm space-y-6" aria-labelledby="pad-title">
                <h3 id="pad-title" className="font-black text-slate-800 flex items-center gap-3 uppercase tracking-widest text-sm"><i className="fas fa-sync text-blue-600" aria-hidden="true"></i> Padronização</h3>
                <div className="space-y-4">
                  <label className="flex items-center gap-5 p-6 border-2 border-slate-50 rounded-2xl cursor-pointer bg-slate-50/30 hover:bg-slate-50 transition-all min-h-[64px]">
                    <input type="checkbox" className="w-8 h-8 rounded-lg accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                    <span className="text-sm text-slate-700 font-bold leading-tight">Revisar procedimento técnico?</span>
                  </label>
                  <label className="flex items-center gap-5 p-6 border-2 border-slate-50 rounded-2xl cursor-pointer bg-slate-50/30 hover:bg-slate-50 transition-all min-h-[64px]">
                    <input type="checkbox" className="w-8 h-8 rounded-lg accent-blue-600" checked={analysis.needsTraining} onChange={e => updateAnalysis({ needsTraining: e.target.checked })} />
                    <span className="text-sm text-slate-700 font-bold leading-tight">Treinar a equipe operacional?</span>
                  </label>
                </div>
                <div className="pt-6">
                  <button 
                    onClick={handleGenerateSummary} 
                    disabled={isGeneratingSummary} 
                    className="w-full bg-slate-900 hover:bg-black disabled:bg-slate-400 text-white font-black py-6 rounded-[24px] shadow-2xl transition-all flex items-center justify-center gap-4 uppercase tracking-widest text-xs min-h-[64px]"
                  >
                    {isGeneratingSummary ? (<><i className="fas fa-cog fa-spin" aria-hidden="true"></i> Analisando...</>) : (<><i className="fas fa-brain" aria-hidden="true"></i> Gerar Resumo Executivo</>)}
                  </button>
                </div>
              </section>
            </div>

            {showSummary && analysis.summary && (
              <section className="animate-slideUp bg-blue-900 text-white p-8 md:p-14 rounded-[40px] shadow-2xl mt-12 relative overflow-hidden" aria-live="polite">
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2" aria-hidden="true"></div>
                <div className="relative z-10">
                   <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-8">
                     <h2 className="text-2xl md:text-3xl font-black flex items-center gap-4"><i className="fas fa-quote-left text-blue-400 opacity-50" aria-hidden="true"></i> Resumo IA</h2>
                     <div className="flex gap-2">
                       <button onClick={() => window.print()} className="bg-white/10 hover:bg-white/20 text-[10px] font-black uppercase tracking-widest px-6 py-4 rounded-full transition-all min-h-[44px]">PDF</button>
                       <button className="bg-white/10 hover:bg-white/20 text-[10px] font-black uppercase tracking-widest px-6 py-4 rounded-full transition-all min-h-[44px]">Exportar</button>
                     </div>
                   </div>
                   <div className="bg-white/10 p-8 rounded-[28px] border border-white/10">
                       <p className="text-slate-100 leading-relaxed text-lg font-medium italic">"{analysis.summary}"</p>
                   </div>
                </div>
              </section>
            )}
          </div>
        );

      case StepId.DASHBOARD:
        return <Dashboard />;

      case StepId.HISTORY:
        return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F8FAFC]">
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg" aria-hidden="true">
              <i className="fas fa-industry text-lg"></i>
            </div>
            <div>
              <h1 className="font-black text-lg tracking-tight uppercase leading-none">SWM Brasil</h1>
              <p className="text-[9px] text-blue-400 font-black tracking-[0.2em] uppercase mt-1">Industrial Intelligence</p>
            </div>
          </div>
          <nav className="flex gap-2 md:gap-4 font-black uppercase tracking-widest text-[10px]" aria-label="Navegação Principal">
            <button 
              onClick={startNewAnalysis} 
              aria-label="Iniciar nova análise de falha"
              className={`px-5 py-3 rounded-xl transition-all min-h-[44px] ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 shadow-lg shadow-blue-900/40 text-white' : 'text-slate-500 hover:text-white'}`}
            >
              Nova Análise
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.HISTORY)} 
              aria-label="Ver histórico de análises"
              className={`px-5 py-3 rounded-xl transition-all min-h-[44px] ${currentStep === StepId.HISTORY ? 'bg-blue-600 shadow-lg shadow-blue-900/40 text-white' : 'text-slate-500 hover:text-white'}`}
            >
              Histórico
            </button>
            <button 
              onClick={() => setCurrentStep(StepId.DASHBOARD)} 
              aria-label="Ver painel de indicadores"
              className={`px-5 py-3 rounded-xl transition-all min-h-[44px] ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 shadow-lg shadow-blue-900/40 text-white' : 'text-slate-500 hover:text-white'}`}
            >
              Dash
            </button>
          </nav>
        </div>
      </header>

      {currentStep < StepId.DASHBOARD && (
        <nav className="bg-white border-b sticky top-20 z-40 overflow-x-auto no-scrollbar" aria-label="Progresso do PDCA">
          <div className="max-w-7xl mx-auto px-6 py-6 flex items-center justify-between gap-4 min-w-[800px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button 
                  onClick={() => setCurrentStep(step.id)} 
                  aria-label={`Ir para etapa: ${step.label}`}
                  className={`flex flex-col items-center gap-2 transition-all flex-shrink-0 ${currentStep === step.id ? 'scale-110' : 'opacity-40 hover:opacity-100'}`}
                >
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs transition-all ${currentStep === step.id ? 'bg-blue-600 text-white shadow-xl ring-4 ring-blue-50' : 'bg-slate-100 text-slate-500'}`} aria-hidden="true">
                    {currentStep > step.id ? <i className="fas fa-check"></i> : step.icon}
                  </div>
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
                </button>
                {idx < STEPS.length - 1 && <div className={`flex-1 h-0.5 rounded-full ${currentStep > idx ? 'bg-blue-600' : 'bg-slate-100'}`} aria-hidden="true"></div>}
              </React.Fragment>
            ))}
          </div>
        </nav>
      )}

      <main id="main-content" className="flex-1 max-w-7xl mx-auto w-full px-4 md:px-6 py-6 md:py-10">
        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-2xl shadow-slate-200/50 border border-slate-100 overflow-hidden flex flex-col min-h-[600px] md:min-h-[700px]">
          <div className="p-6 md:p-16 flex-1">
             {renderStepContent()}
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="bg-slate-50/50 border-t border-slate-100 p-6 md:p-12 flex items-center justify-between gap-4">
              <button 
                onClick={handleBack} 
                disabled={currentStep === StepId.IDENTIFICATION} 
                className="flex items-center gap-3 text-slate-400 font-black uppercase tracking-[0.2em] text-[10px] hover:text-slate-900 disabled:opacity-20 transition-all p-4 min-h-[48px]"
              >
                <i className="fas fa-long-arrow-left" aria-hidden="true"></i> <span className="hidden sm:inline">Voltar</span>
              </button>

              <div className="flex gap-4">
                {currentStep < StepId.VERIFICATION ? (
                  <button 
                    onClick={handleNext} 
                    className="bg-blue-600 hover:bg-blue-700 text-white px-8 md:px-12 py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] shadow-2xl shadow-blue-200 transition-all flex items-center gap-4 min-h-[56px]"
                  >
                    Próximo <i className="fas fa-long-arrow-right" aria-hidden="true"></i>
                  </button>
                ) : (
                  <button 
                    onClick={finalizeAnalysis} 
                    className="bg-slate-900 hover:bg-black text-white px-8 md:px-12 py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] shadow-2xl transition-all min-h-[56px]"
                  >
                    Finalizar Relatório
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="py-12 px-6">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-8 opacity-40">
          <p className="text-[10px] font-black uppercase tracking-[0.3em]">SWM Brasil &copy; 2024 Reliability Labs</p>
          <div className="flex gap-10 text-[9px] font-black uppercase tracking-widest" role="navigation" aria-label="Links de Ajuda">
             <button className="hover:text-blue-600 min-h-[44px]">Documentação</button>
             <button className="hover:text-blue-600 min-h-[44px]">Segurança</button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Analysis, IshikawaCategory, Attachment } from '../types';
import { ISHIKAWA_QUESTIONS } from '../constants';

interface Props {
  analysis: Analysis;
  updateAnalysis: (data: Partial<Analysis>) => void;
}

const IshikawaComponent: React.FC<Props> = ({ analysis, updateAnalysis }) => {
  const fileInputRefs = {
    machine: useRef<HTMLInputElement>(null),
    method: useRef<HTMLInputElement>(null),
    material: useRef<HTMLInputElement>(null),
    manpower: useRef<HTMLInputElement>(null),
    measurement: useRef<HTMLInputElement>(null),
    environment: useRef<HTMLInputElement>(null),
  };

  const handleCauseChange = (category: keyof Analysis['ishikawa'], index: number, value: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes[index] = value;
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const addCause = (category: keyof Analysis['ishikawa']) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.push("");
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const removeCause = (category: keyof Analysis['ishikawa'], index: number) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.splice(index, 1);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const handleFileUpload = (category: keyof Analysis['ishikawa'], e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const file = files[0];
    const reader = new FileReader();
    reader.onload = (event) => {
      const newAttachment: Attachment = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        type: file.type,
        size: file.size,
        dataUrl: event.target?.result as string,
      };

      const newIshikawa = { ...analysis.ishikawa };
      newIshikawa[category].attachments = [...(newIshikawa[category].attachments || []), newAttachment];
      updateAnalysis({ ishikawa: newIshikawa });

      if (fileInputRefs[category].current) {
        fileInputRefs[category].current!.value = "";
      }
    };
    reader.readAsDataURL(file);
  };

  const removeAttachment = (category: keyof Analysis['ishikawa'], attachmentId: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].attachments = newIshikawa[category].attachments.filter(a => a.id !== attachmentId);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const renderCategory = (category: keyof Analysis['ishikawa'], label: string, icon: string) => (
    <section className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100 hover:border-blue-400 transition-all flex flex-col h-full" aria-labelledby={`title-${category}`}>
      <div className="flex items-center gap-4 mb-5 border-b border-slate-50 pb-4">
        <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center border border-slate-100 shadow-inner" aria-hidden="true">
          <i className={`fas ${icon} text-blue-600 text-lg`}></i>
        </div>
        <h3 id={`title-${category}`} className="font-black text-slate-800 uppercase tracking-widest text-sm">{label}</h3>
      </div>
      <p className="text-[11px] text-slate-500 mb-6 italic leading-relaxed font-medium">{ISHIKAWA_QUESTIONS[category]}</p>

      <div className="space-y-4 flex-1">
        {analysis.ishikawa[category].causes.map((cause, idx) => (
          <div key={idx} className="flex gap-2 animate-fadeIn items-center">
            <input
              type="text"
              value={cause}
              onChange={(e) => handleCauseChange(category, idx, e.target.value)}
              placeholder="Causa provável..."
              aria-label={`Causa ${idx + 1} para ${label}`}
              className="flex-1 text-sm bg-slate-50 border-transparent text-slate-900 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none border shadow-inner font-medium placeholder:text-slate-300 min-h-[50px]"
            />
            <button 
              onClick={() => removeCause(category, idx)}
              className="w-12 h-12 flex items-center justify-center text-slate-300 hover:text-red-500 transition-colors"
              aria-label={`Remover causa ${idx + 1} de ${label}`}
            >
              <i className="fas fa-times-circle" aria-hidden="true"></i>
            </button>
          </div>
        ))}

        {analysis.ishikawa[category].attachments && analysis.ishikawa[category].attachments.length > 0 && (
          <div className="mt-8 pt-6 border-t border-dashed border-slate-100 space-y-4">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Anexos Técnicos</p>
            <ul className="grid grid-cols-1 gap-3">
              {analysis.ishikawa[category].attachments.map((file) => (
                <li key={file.id} className="bg-blue-50/30 border border-blue-100 rounded-2xl p-4 flex items-center gap-4 group">
                  <i className={`fas ${file.type.startsWith('image/') ? 'fa-image' : 'fa-file-alt'} text-blue-500`} aria-hidden="true"></i>
                  <span className="text-xs font-bold text-slate-700 truncate flex-1">{file.name}</span>
                  <button 
                    onClick={() => removeAttachment(category, file.id)}
                    className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-red-500 transition-colors"
                    aria-label={`Excluir anexo ${file.name}`}
                  >
                    <i className="fas fa-trash-alt text-sm" aria-hidden="true"></i>
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-3 pt-6 border-t border-slate-50">
        <button 
          onClick={() => addCause(category)}
          className="flex-1 text-[10px] text-blue-700 font-black bg-blue-50 hover:bg-blue-100 rounded-2xl py-5 flex items-center justify-center gap-2 uppercase tracking-widest transition-all min-h-[50px]"
        >
          <i className="fas fa-plus" aria-hidden="true"></i> Causa
        </button>

        <button 
          onClick={() => fileInputRefs[category].current?.click()}
          className="flex-1 text-[10px] text-slate-600 font-black bg-slate-50 hover:bg-slate-100 border border-slate-100 rounded-2xl py-5 flex items-center justify-center gap-2 uppercase tracking-widest transition-all min-h-[50px]"
          aria-label={`Anexar evidência fotográfica ou documento para ${label}`}
        >
          <i className="fas fa-paperclip" aria-hidden="true"></i> Anexar
        </button>

        <input 
          type="file" 
          ref={fileInputRefs[category]}
          onChange={(e) => handleFileUpload(category, e)}
          className="hidden"
          accept="image/*,.pdf,.doc,.docx,.xls,.xlsx"
        />
      </div>
    </section>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
      {renderCategory('machine', 'Máquina', 'fa-cogs')}
      {renderCategory('method', 'Método', 'fa-book')}
      {renderCategory('manpower', 'Mão de Obra', 'fa-users')}
      {renderCategory('material', 'Material', 'fa-box-open')}
      {renderCategory('measurement', 'Medição', 'fa-ruler-combined')}
      {renderCategory('environment', 'Meio Ambiente', 'fa-leaf')}
    </div>
  );
};

export default IshikawaComponent;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasData = analysis.equipment || analysis.description || analysis.area;
    if (hasData && !confirm("Deseja iniciar uma NOVA análise? Os dados atuais serão perdidos.")) return;
    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
  };

  const finalizeAnalysis = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl p-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 border-b pb-3">
               <div>
                  <h2 className="text-lg font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-widest">Ativo e Contexto</p>
               </div>
               <button onClick={simulateFullAnalysis} className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-lg border border-amber-200 transition-all shadow-sm">
                  Simular Caso
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Área</label>
                <input type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Equipamento</label>
                <input type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Tag</label>
                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Data</label>
                <input type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={inputClasses} />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Descrição</label>
              <textarea value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-24 md:h-32 resize-none`} />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {[
                { field: 'what', label: 'O QUE?', tip: TIPS.what },
                { field: 'where', label: 'ONDE?', tip: TIPS.where },
                { field: 'when', label: 'QUANDO?', tip: TIPS.when },
                { field: 'who', label: 'QUEM?', tip: '' },
                { field: 'howMuch', label: 'QUANTO impacto?', tip: TIPS.howMuch },
                { field: 'how', label: 'COMO?', tip: TIPS.how },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">{item.label}</label>
                  <textarea value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-20 resize-none`} />
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">3. Detalhamento</h2>
            <div className="grid grid-cols-1 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Sintoma</label>
                <input type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} />
              </div>
              <fieldset>
                <legend className="block text-[10px] font-bold text-slate-500 uppercase mb-2 tracking-wider">Frequência</legend>
                <div className="grid grid-cols-3 gap-2">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex items-center justify-center p-3 rounded-xl border-2 cursor-pointer transition-all ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      <span className="text-xs">{f}</span>
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Histórico Recente</label>
                <textarea value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-24 md:h-32 resize-none`} />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">4. 5 Porquês</h2>
              <button onClick={handleSuggestCause} className="text-[10px] bg-slate-900 text-white font-black px-4 py-2 rounded-lg transition-all shadow-md">
                Sugerir com IA
              </button>
            </header>
            <div className="space-y-4">
              {analysis.whys.map((why, idx) => (
                <div key={idx} className="flex gap-4 items-start">
                  <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center font-black text-xs flex-shrink-0 mt-1">{idx + 1}</div>
                  <div className="flex-1">
                    <textarea value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-16 resize-none`} placeholder="..." />
                  </div>
                </div>
              ))}
            </div>
            <div className="p-5 bg-blue-900 rounded-2xl text-white shadow-lg">
              <label className="block text-[10px] font-black uppercase mb-2 opacity-60">Causa Raiz</label>
              <input type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-xl p-3 font-bold border border-white/20 outline-none text-sm shadow-inner" placeholder="..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />;

      case StepId.ACTIONS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">6. Plano de Ação</h2>
              <button onClick={addAction} className="bg-blue-600 text-white text-[10px] font-black px-5 py-2.5 rounded-xl shadow-lg transition-all uppercase tracking-wider">
                Nova Ação
              </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {analysis.actions.map((action, index) => (
                <div key={action.id} className="bg-slate-50 border border-slate-200 rounded-2xl p-4 space-y-3 relative group">
                  <div className="flex items-center justify-between gap-2">
                    <select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="bg-blue-50 text-blue-700 text-[10px] font-black uppercase px-3 py-1.5 rounded-full border-none outline-none">
                      <option>Corretiva</option>
                      <option>Preventiva</option>
                      <option>Melhoria</option>
                    </select>
                    <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1"><i className="fas fa-trash-alt text-xs"></i></button>
                  </div>
                  <textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full bg-white border border-slate-100 rounded-xl p-3 text-sm font-medium resize-none h-20 outline-none" placeholder="O que fazer?" />
                  <div className="grid grid-cols-2 gap-3">
                    <input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="w-full bg-white border border-slate-100 rounded-lg p-2 text-xs font-bold" placeholder="Quem?" />
                    <input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="w-full bg-white border border-slate-100 rounded-lg p-2 text-xs font-bold" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">7. Verificação</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 uppercase text-xs">Eficácia</h3>
                <div className="flex gap-2">
                  <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-3 border-2 rounded-xl text-xs font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white' : 'bg-white text-slate-300 border-slate-50'}`}>SIM</button>
                  <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-3 border-2 rounded-xl text-xs font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white' : 'bg-white text-slate-300 border-slate-50'}`}>NÃO</button>
                </div>
                <textarea value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-20 resize-none"} placeholder="Evidências..." />
              </div>
              <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 uppercase text-xs">Padronização</h3>
                <label className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-pointer">
                  <input type="checkbox" className="w-5 h-5 accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                  <span className="text-xs font-bold text-slate-700">Revisar procedimento?</span>
                </label>
                <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                  {isGeneratingSummary ? 'Processando...' : 'Gerar Resumo IA'}
                </button>
              </div>
            </div>
            {showSummary && analysis.summary && (
              <div className="p-6 bg-blue-900 text-white rounded-[32px] shadow-xl animate-slideUp">
                <h2 className="text-xl font-black mb-4 flex items-center gap-3"><i className="fas fa-brain text-blue-400"></i> Resumo IA</h2>
                <p className="text-sm italic leading-relaxed opacity-90">"{analysis.summary}"</p>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD: return <Dashboard />;
      case StepId.HISTORY: return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;
      default: return null;
    }
  };

  const simulateFullAnalysis = () => {
