import React, { useRef } from 'react';
import { Analysis, Attachment } from '../types';
import { ISHIKAWA_QUESTIONS } from '../constants';

interface Props {
  analysis: Analysis;
  updateAnalysis: (data: Partial<Analysis>) => void;
}

const IshikawaComponent: React.FC<Props> = ({ analysis, updateAnalysis }) => {
  const fileInputRefs = {
    machine: useRef<HTMLInputElement>(null),
    method: useRef<HTMLInputElement>(null),
    material: useRef<HTMLInputElement>(null),
    manpower: useRef<HTMLInputElement>(null),
    measurement: useRef<HTMLInputElement>(null),
    environment: useRef<HTMLInputElement>(null),
  };

  const handleCauseChange = (category: keyof Analysis['ishikawa'], index: number, value: string) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes[index] = value;
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const addCause = (category: keyof Analysis['ishikawa']) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.push("");
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const removeCause = (category: keyof Analysis['ishikawa'], index: number) => {
    const newIshikawa = { ...analysis.ishikawa };
    newIshikawa[category].causes.splice(index, 1);
    updateAnalysis({ ishikawa: newIshikawa });
  };

  const handleFileUpload = (category: keyof Analysis['ishikawa'], e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const file = files[0];
    const reader = new FileReader();
    reader.onload = (event) => {
      const newAttachment: Attachment = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        type: file.type,
        size: file.size,
        dataUrl: event.target?.result as string,
      };
      const newIshikawa = { ...analysis.ishikawa };
      newIshikawa[category].attachments = [...(newIshikawa[category].attachments || []), newAttachment];
      updateAnalysis({ ishikawa: newIshikawa });
      if (fileInputRefs[category].current) fileInputRefs[category].current!.value = "";
    };
    reader.readAsDataURL(file);
  };

  const renderCategory = (category: keyof Analysis['ishikawa'], label: string, icon: string) => (
    <section className="bg-slate-50 p-4 md:p-5 rounded-2xl border border-slate-100 flex flex-col gap-3">
      <div className="flex items-center gap-3 pb-3 border-b border-white">
        <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-blue-600 shadow-sm"><i className={`fas ${icon} text-xs`}></i></div>
        <h3 className="font-black text-slate-800 uppercase text-[10px] tracking-widest">{label}</h3>
      </div>
      <p className="text-[9px] text-slate-400 italic leading-tight">{ISHIKAWA_QUESTIONS[category]}</p>

      <div className="space-y-2 flex-1">
        {analysis.ishikawa[category].causes.map((cause, idx) => (
          <div key={idx} className="flex gap-1.5 items-center">
            <input
              type="text"
              value={cause}
              onChange={(e) => handleCauseChange(category, idx, e.target.value)}
              className="flex-1 text-xs bg-white border border-slate-100 rounded-lg p-2 focus:ring-1 focus:ring-blue-500 outline-none font-medium placeholder:text-slate-200"
              placeholder="..."
            />
            <button onClick={() => removeCause(category, idx)} className="text-slate-300 hover:text-red-500 transition-colors"><i className="fas fa-times-circle text-xs"></i></button>
          </div>
        ))}
        {analysis.ishikawa[category].attachments?.length > 0 && (
          <div className="pt-2 flex flex-wrap gap-1.5">
            {analysis.ishikawa[category].attachments.map(file => (
              <span key={file.id} className="text-[8px] font-bold bg-blue-100 text-blue-700 px-2 py-1 rounded-md flex items-center gap-1">
                <i className="fas fa-paperclip"></i> {file.name.slice(0, 10)}...
              </span>
            ))}
          </div>
        )}
      </div>

      <div className="flex gap-2 pt-3 border-t border-white">
        <button onClick={() => addCause(category)} className="flex-1 text-[8px] text-blue-700 font-black bg-white border border-blue-50 py-2 rounded-lg hover:bg-blue-50 transition-all uppercase tracking-widest">+ Causa</button>
        <button onClick={() => fileInputRefs[category].current?.click()} className="flex-1 text-[8px] text-slate-500 font-black bg-white border border-slate-100 py-2 rounded-lg hover:bg-slate-50 transition-all uppercase tracking-widest">Anexar</button>
        <input type="file" ref={fileInputRefs[category]} onChange={(e) => handleFileUpload(category, e)} className="hidden" />
      </div>
    </section>
  );

  return (
    <div className="space-y-6">
      <h2 className="text-lg font-bold border-b pb-3 text-slate-800">5. Diagrama de Ishikawa</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {renderCategory('machine', 'Máquina', 'fa-cogs')}
        {renderCategory('method', 'Método', 'fa-book')}
        {renderCategory('manpower', 'Mão de Obra', 'fa-users')}
        {renderCategory('material', 'Material', 'fa-box-open')}
        {renderCategory('measurement', 'Medição', 'fa-ruler-combined')}
        {renderCategory('environment', 'Meio Ambiente', 'fa-leaf')}
      </div>
    </div>
  );
};

export default IshikawaComponent;

{
