                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: B-001" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Data <span className="text-red-500">*</span></label>
