        );

      case StepId.W5H1:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {[
                { field: 'what', label: 'O QUE?', required: true },
                { field: 'where', label: 'ONDE?', required: true },
                { field: 'when', label: 'QUANDO?', required: true },
                { field: 'who', label: 'QUEM?', required: false },
                { field: 'howMuch', label: 'QUANTO impacto?', required: false },
                { field: 'how', label: 'COMO?', required: true },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">{item.label} {item.required && <span className="text-red-500">*</span>}</label>
                  <textarea value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-20 resize-none`} />
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">3. Detalhamento</h2>
            <div className="grid grid-cols-1 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Sintoma Observado <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração intensa" />
              </div>
              <fieldset>
                <legend className="block text-[10px] font-bold text-slate-500 uppercase mb-2 tracking-wider">Frequência</legend>
                <div className="grid grid-cols-3 gap-2">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex items-center justify-center p-3 rounded-xl border-2 cursor-pointer transition-all ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      <span className="text-xs">{f}</span>
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Histórico Recente</label>
                <textarea value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-24 md:h-32 resize-none`} />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">4. 5 Porquês</h2>
              <button onClick={handleSuggestCause} className="text-[10px] bg-slate-900 text-white font-black px-4 py-2 rounded-lg transition-all shadow-md">
                Sugerir com IA
              </button>
            </header>
            <div className="space-y-4">
              {analysis.whys.map((why, idx) => (
                <div key={idx} className="flex gap-4 items-start">
                  <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center font-black text-xs flex-shrink-0 mt-1">{idx + 1}</div>
                  <div className="flex-1">
                    <textarea value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-16 resize-none`} placeholder={idx === 0 ? "Obrigatório..." : "Opcional..."} />
                  </div>
                </div>
              ))}
            </div>
            <div className="p-5 bg-blue-900 rounded-2xl text-white shadow-lg">
              <label className="block text-[10px] font-black uppercase mb-2 opacity-60">Causa Raiz Fundamental <span className="text-blue-400">*</span></label>
              <input type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-xl p-3 font-bold border border-white/20 outline-none text-sm shadow-inner" placeholder="..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />;

      case StepId.ACTIONS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">6. Plano de Ação <span className="text-blue-500 font-normal text-xs">(Mín. 1 ação)</span></h2>
              <button onClick={addAction} className="bg-blue-600 text-white text-[10px] font-black px-5 py-2.5 rounded-xl shadow-lg transition-all uppercase tracking-wider">
                Nova Ação
              </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {analysis.actions.map((action, index) => (
                <div key={action.id} className="bg-slate-50 border border-slate-200 rounded-2xl p-4 space-y-3 relative group">
                  <div className="flex items-center justify-between gap-2">
                    <select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="bg-blue-50 text-blue-700 text-[10px] font-black uppercase px-3 py-1.5 rounded-full border-none outline-none">
                      <option>Corretiva</option>
                      <option>Preventiva</option>
                      <option>Melhoria</option>
                    </select>
                    <button onClick={() => removeAction(action.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1"><i className="fas fa-trash-alt text-xs"></i></button>
                  </div>
                  <textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full bg-white border border-slate-100 rounded-xl p-3 text-sm font-medium resize-none h-20 outline-none" placeholder="Descrição da ação obrigatória..." />
                  <div className="grid grid-cols-2 gap-3">
                    <input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="w-full bg-white border border-slate-100 rounded-lg p-2 text-xs font-bold" placeholder="Responsável *" />
                    <input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="w-full bg-white border border-slate-100 rounded-lg p-2 text-xs font-bold" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">7. Verificação</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 uppercase text-xs">Eficácia <span className="text-red-500">*</span></h3>
                <div className="flex gap-2">
                  <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-3 border-2 rounded-xl text-xs font-black transition-all ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white' : 'bg-white text-slate-300 border-slate-50'}`}>SIM</button>
                  <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-3 border-2 rounded-xl text-xs font-black transition-all ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white' : 'bg-white text-slate-300 border-slate-50'}`}>NÃO</button>
                </div>
                <textarea value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-20 resize-none"} placeholder="Evidências da eficácia..." />
              </div>
              <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 uppercase text-xs">Padronização</h3>
                <label className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-pointer">
                  <input type="checkbox" className="w-5 h-5 accent-blue-600" checked={analysis.needsRevision} onChange={e => updateAnalysis({ needsRevision: e.target.checked })} />
                  <span className="text-xs font-bold text-slate-700">Revisar procedimento?</span>
                </label>
                <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                  {isGeneratingSummary ? 'Processando...' : 'Gerar Resumo IA'}
                </button>
              </div>
            </div>
            {showSummary && analysis.summary && (
              <div className="p-6 bg-blue-900 text-white rounded-[32px] shadow-xl animate-slideUp">
                <h2 className="text-xl font-black mb-4 flex items-center gap-3"><i className="fas fa-brain text-blue-400"></i> Resumo IA</h2>
                <p className="text-sm italic leading-relaxed opacity-90">"{analysis.summary}"</p>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD: return <Dashboard />;
      case StepId.HISTORY: return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} />;
      default: return null;
    }
  };

  return (
    <div className="h-screen flex flex-col bg-[#F8FAFC] overflow-hidden">
      {/* Validation Modal */}
      {showValidationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-slideUp">
            <div className="bg-red-600 p-6 text-white flex items-center gap-4">
              <i className="fas fa-exclamation-triangle text-2xl"></i>
              <h3 className="font-black uppercase tracking-widest text-sm">Dados Incompletos</h3>
            </div>
            <div className="p-8">
              <p className="text-slate-600 text-sm font-medium mb-6">Identificamos campos obrigatórios não preenchidos que impedem a continuidade da análise:</p>
              <ul className="space-y-3 mb-8">
                {validationErrors.map((err, i) => (
                  <li key={i} className="flex items-start gap-3 text-red-600 text-xs font-bold bg-red-50 p-3 rounded-xl border border-red-100">
                    <i className="fas fa-circle-check mt-0.5 opacity-50"></i>
                    {err}
                  </li>
                ))}
              </ul>
              <button onClick={() => setShowValidationModal(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-slate-200 transition-all hover:bg-black">
                Corrigir Agora
              </button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-slate-900 text-white shadow-lg h-16 md:h-20 flex-shrink-0 z-50">
        <div className="max-w-7xl mx-auto px-4 md:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 w-9 h-9 rounded-lg flex items-center justify-center shadow-md">
              <i className="fas fa-industry text-base"></i>
            </div>
            <div>
              <h1 className="font-black text-sm md:text-base tracking-tight uppercase leading-none truncate max-w-[150px] sm:max-w-none">Análise de Falhas SWM Brasil</h1>
              <p className="text-[8px] text-blue-400 font-black tracking-widest uppercase mt-0.5">Engenharia e Confiabilidade</p>
            </div>
          </div>
          <nav className="flex gap-2 font-black uppercase tracking-widest text-[9px] md:text-[10px]">
            <button onClick={startNewAnalysis} className={`px-4 py-2 rounded-xl transition-all ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-white'}`}>Novo</button>
            <button onClick={() => setCurrentStep(StepId.HISTORY)} className={`px-4 py-2 rounded-xl transition-all ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-white'}`}>Histórico</button>
            <button onClick={() => setCurrentStep(StepId.DASHBOARD)} className={`px-4 py-2 rounded-xl transition-all ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-white'}`}>Dashboard</button>
          </nav>
        </div>
      </header>

      {currentStep < StepId.DASHBOARD && (
        <nav className="bg-white border-b flex-shrink-0 z-40 overflow-x-auto no-scrollbar shadow-sm">
          <div className="max-w-7xl mx-auto px-4 md:px-6 py-4 flex items-center justify-between gap-4 min-w-[700px] md:min-w-0">
            {STEPS.map((step, idx) => (
              <React.Fragment key={step.id}>
                <button onClick={() => {
                  const errors = validateStep(step.id - 1);
                  if (errors.length > 0 && step.id > currentStep) {
                    setValidationErrors(errors);
                    setShowValidationModal(true);
                  } else {
                    setCurrentStep(step.id);
                  }
                }} className={`flex flex-col items-center gap-1 transition-all flex-shrink-0 ${currentStep === step.id ? 'opacity-100' : 'opacity-30 hover:opacity-100'}`}>
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-[10px] transition-all ${currentStep === step.id ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500'}`}>
                    {currentStep > step.id ? <i className="fas fa-check"></i> : step.icon}
                  </div>
                  <span className={`text-[8px] font-black uppercase tracking-wider ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
                </button>
                {idx < STEPS.length - 1 && <div className={`flex-1 h-px rounded-full ${currentStep > idx ? 'bg-blue-600' : 'bg-slate-100'}`}></div>}
              </React.Fragment>
            ))}
          </div>
        </nav>
      )}

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <div id="step-scroll-container" className="flex-1 overflow-y-auto px-4 py-6 md:px-8">
          <div className="max-w-7xl mx-auto">
            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 md:p-10 mb-20">
              {renderStepContent()}
            </div>
          </div>
        </div>

        {currentStep < StepId.DASHBOARD && (
          <div className="absolute bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-slate-100 p-4 md:p-6 z-50">
            <div className="max-w-7xl mx-auto flex items-center justify-between">
              <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center gap-2 text-slate-400 font-black uppercase text-[10px] hover:text-slate-900 disabled:opacity-20 transition-all px-4 py-2">
                <i className="fas fa-arrow-left"></i> Voltar
              </button>
              <div className="flex gap-2">
                <button onClick={finalizeAnalysis} className="hidden sm:block text-slate-500 bg-slate-50 hover:bg-slate-100 px-6 py-3 rounded-xl font-bold text-[10px] uppercase tracking-widest border border-slate-200">Salvar Rascunho</button>
                {currentStep < StepId.VERIFICATION ? (
                  <button onClick={handleNext} className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-3.5 rounded-xl font-black uppercase text-[10px] shadow-lg shadow-blue-200 transition-all flex items-center gap-3">
                    Próximo <i className="fas fa-arrow-right"></i>
                  </button>
                ) : (
                  <button onClick={finalizeAnalysis} className="bg-slate-900 hover:bg-black text-white px-10 py-3.5 rounded-xl font-black uppercase text-[10px] shadow-lg transition-all">Finalizar Relatório</button>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [showValidationModal, setShowValidationModal] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const validateStep = (step: StepId): string[] => {
    const errors: string[] = [];

    // Cumulative validation: Check current and previous steps
    if (step >= StepId.IDENTIFICATION) {
      if (!analysis.area.trim()) errors.push("Área / Setor é obrigatória");
      if (!analysis.equipment.trim()) errors.push("Nome do Equipamento é obrigatório");
      if (!analysis.tag.trim()) errors.push("Tag do Ativo é obrigatória");
      if (!analysis.description.trim()) errors.push("Descrição do problema é obrigatória");
    }

    if (step >= StepId.W5H1) {
      if (!analysis.what.trim()) errors.push("O QUE aconteceu deve ser preenchido");
      if (!analysis.where.trim()) errors.push("ONDE ocorreu deve ser preenchido");
      if (!analysis.when.trim()) errors.push("QUANDO ocorreu deve ser preenchido");
      if (!analysis.how.trim()) errors.push("COMO foi percebido deve ser preenchido");
    }

    if (step >= StepId.DETAILS) {
      if (!analysis.symptom.trim()) errors.push("Sintoma observado é obrigatório");
    }

    if (step >= StepId.FIVE_WHYS) {
      if (!analysis.whys[0].trim()) errors.push("Pelo menos o 1º Porquê deve ser preenchido");
      if (!analysis.rootCause.trim()) errors.push("A Causa Raiz fundamental deve ser definida");
    }

    if (step >= StepId.ACTIONS) {
      if (analysis.actions.length === 0) errors.push("Pelo menos uma ação deve ser adicionada ao Plano de Ação");
      else if (analysis.actions.some(a => !a.description.trim() || !a.responsible.trim())) {
        errors.push("Todas as ações devem ter descrição e responsável");
      }
    }

    if (step === StepId.VERIFICATION) {
      if (analysis.reoccurred === null) errors.push("Deve-se informar se a falha voltou a ocorrer na etapa de Verificação");
    }

    return errors;
  };

  const handleNext = () => {
    const errors = validateStep(currentStep);
    if (errors.length > 0) {
      setValidationErrors(errors);
      setShowValidationModal(true);
      return;
    }

    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasData = analysis.equipment || analysis.description || analysis.area;
    if (hasData && !confirm("Deseja iniciar uma NOVA análise? Os dados atuais serão perdidos.")) return;
    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
  };

  const finalizeAnalysis = () => {
    const errors = validateStep(StepId.VERIFICATION);
    if (errors.length > 0) {
      setValidationErrors(errors);
      setShowValidationModal(true);
      return;
    }

    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const simulateFullAnalysis = () => {
    const demoData: Analysis = {
      ...getInitialState(),
      area: "Produção / Celulose",
      equipment: "Refinador de Ajuste MP3",
      tag: "REF-302-B",
      failureDate: new Date().toISOString().split('T')[0],
      shift: "B - Noturno",
      responsible: "Eng. Ricardo Silva",
      description: "Parada súbita do motor principal do refinador durante a rampa de carga, ocasionando desarme do disjuntor de proteção térmica por sobrecarga.",
      what: "Desarme do motor principal por sobrecorrente.",
      where: "Mancal traseiro do motor de 500cv.",
      when: "Durante o aumento de pressão na câmara de refino (85% de carga).",
      who: "Operador de Painel Sr. João Santos.",
      howMuch: "4 horas de produção perdida (aprox. 120 toneladas de polpa).",
      how: "Alarme sonoro seguido de parada instantânea.",
      symptom: "Fumaça leve e cheiro de queimado no compartimento do motor.",
      condition: "Equipamento operando em regime estável há 12 horas.",
      history: "Troca de rolamentos realizada há 6 meses.",
      frequency: "Eventual",
      whys: ["Motor parou por sobrecarga térmica.", "Aumento drástico do torque resistente.", "Rolamento traseiro travou parcialmente.", "Lubrificação insuficiente.", "Desalinhamento residual na montagem."],
      rootCause: "Desalinhamento residual excedendo tolerância térmica do retentor.",
      ishikawa: {
        machine: { causes: ["Desalinhamento motor/refinador"], attachments: [] },
        method: { causes: ["Frequência de inspeção insuficiente"], attachments: [] },
        material: { causes: ["Graxa contaminada"], attachments: [] },
        manpower: { causes: ["Equipe sem alinhador laser"], attachments: [] },
        measurement: { causes: ["Termopar distante do ponto de calor"], attachments: [] },
        environment: { causes: ["Alta temperatura ambiente (42°C)"], attachments: [] },
      },
      actions: [
        { id: "1", description: "Realizar alinhamento a laser de precisão", type: "Corretiva", responsible: "Equipe Mecânica", dueDate: "2024-05-20", status: "Concluída" },
        { id: "2", description: "Revisar plano de manutenção para frequência quinzenal", type: "Melhoria", responsible: "Eng. Confiabilidade", dueDate: "2024-06-01", status: "Em andamento" }
      ],
      reoccurred: false,
      effectivenessEvidence: "MTBF subiu significativamente.",
      needsRevision: true,
      needsTraining: true,
    };
    setAnalysis(demoData);
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl p-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 border-b pb-3">
               <div>
                  <h2 className="text-lg font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-widest">Ativo e Contexto</p>
               </div>
               <button onClick={simulateFullAnalysis} className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-lg border border-amber-200 transition-all shadow-sm">
                  Simular Caso
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Área <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Produção" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Equipamento <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Bomba de recalque" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Tag <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: B-001" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Data da Falha <span className="text-red-500">*</span></label>
                <div className="relative">
                  <input 
                    type="date" 
                    value={analysis.failureDate} 
                    onChange={e => updateAnalysis({ failureDate: e.target.value })} 
                    className={`${inputClasses} pl-10 cursor-pointer`} 
                  />
                  <i className="fas fa-calendar-alt absolute left-3.5 top-1/2 -translate-y-1/2 text-blue-500 text-sm pointer-events-none"></i>
                </div>
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Descrição do Problema <span className="text-red-500">*</span></label>
              <textarea value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-24 md:h-32 resize-none`} placeholder="O que aconteceu de forma técnica..." />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {[
                { field: 'what', label: 'O QUE?', required: true },
                { field: 'where', label: 'ONDE?', required: true },
                { field: 'when', label: 'QUANDO?', required: true },
                { field: 'who', label: 'QUEM?', required: false },
                { field: 'howMuch', label: 'QUANTO impacto?', required: false },
                { field: 'how', label: 'COMO?', required: true },
              ].map((item) => (
                <div key={item.field}>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">{item.label} {item.required && <span className="text-red-500">*</span>}</label>
                  <textarea value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-20 resize-none`} />
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <h2 className="text-lg font-bold border-b pb-3 text-slate-800">3. Detalhamento</h2>
            <div className="grid grid-cols-1 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Sintoma Observado <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração intensa" />
              </div>
              <fieldset>
                <legend className="block text-[10px] font-bold text-slate-500 uppercase mb-2 tracking-wider">Frequência</legend>
                <div className="grid grid-cols-3 gap-2">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <label key={f} className={`flex items-center justify-center p-3 rounded-xl border-2 cursor-pointer transition-all ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white font-bold' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
                      <input type="radio" className="sr-only" checked={analysis.frequency === f} onChange={() => updateAnalysis({ frequency: f as any })} />
                      <span className="text-xs">{f}</span>
                    </label>
                  ))}
                </div>
              </fieldset>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Histórico Recente</label>
                <textarea value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-24 md:h-32 resize-none`} />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">4. 5 Porquês</h2>
              <button onClick={handleSuggestCause} className="text-[10px] bg-slate-900 text-white font-black px-4 py-2 rounded-lg transition-all shadow-md">
                Sugerir com IA
              </button>
            </header>
            <div className="space-y-4">
              {analysis.whys.map((why, idx) => (
                <div key={idx} className="flex gap-4 items-start">
                  <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center font-black text-xs flex-shrink-0 mt-1">{idx + 1}</div>
                  <div className="flex-1">
                    <textarea value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-16 resize-none`} placeholder={idx === 0 ? "Obrigatório..." : "Opcional..."} />
                  </div>
                </div>
              ))}
            </div>
            <div className="p-5 bg-blue-900 rounded-2xl text-white shadow-lg">
              <label className="block text-[10px] font-black uppercase mb-2 opacity-60">Causa Raiz Fundamental <span className="text-blue-400">*</span></label>
              <input type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-xl p-3 font-bold border border-white/20 outline-none text-sm shadow-inner" placeholder="..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />;

      case StepId.ACTIONS:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex justify-between items-center border-b pb-3">
              <h2 className="text-lg font-bold text-slate-800">6. Plano de Ação <span className="text-blue-500 font-normal text-xs">(Mín. 1 ação)</span></h2>
              <button onClick={addAction} className="bg-blue-600 text-white text-[10px] font-black px-5 py-2.5 rounded-xl shadow-lg transition-all uppercase tracking-wider">
                Nova Ação
              </button>
