                <div key={action.id} className="bg-slate-50 border border-slate-200 rounded-2xl p-4 space-y-3 relative group">
                  <div className="flex items-center justify-between gap-2">
                    <select value={action.type} onChange={e => updateAction(action.id, { type: e.target.value as any })} className="bg-blue-50 text-blue-700 text-[10px] font-black uppercase px-3 py-1.5 rounded-full border-none outline-none">
                      <option>Corretiva</option>
                      <option>Preventiva</option>
                      <option>Melhoria</option>
