      who: "Operador de Painel Sr. João Santos.",
      howMuch: "4 horas de produção perdida (aprox. 120 toneladas de polpa).",
      how: "Alarme sonoro seguido de parada instantânea.",
      symptom: "Fumaça leve e cheiro de queimado no compartimento do motor.",
      condition: "Equipamento operando em regime estável há 12 horas.",
      history: "Troca de rolamentos realizada há 6 meses.",
      frequency: "Eventual",
      whys: ["Motor parou por sobrecarga térmica.", "Aumento drástico do torque resistente.", "Rolamento traseiro travou parcialmente.", "Lubrificação insuficiente.", "Desalinhamento residual na montagem."],
      rootCause: "Desalinhamento residual excedendo tolerância térmica do retentor.",
      ishikawa: {
        machine: { causes: ["Desalinhamento motor/refinador"], attachments: [] },
        method: { causes: ["Frequência de inspeção insuficiente"], attachments: [] },
        material: { causes: ["Graxa contaminada"], attachments: [] },
        manpower: { causes: ["Equipe sem alinhador laser"], attachments: [] },
        measurement: { causes: ["Termopar distante do ponto de calor"], attachments: [] },
        environment: { causes: ["Alta temperatura ambiente (42°C)"], attachments: [] },
      },
      actions: [
        { id: "1", description: "Realizar alinhamento a laser de precisão", type: "Corretiva", responsible: "Equipe Mecânica", dueDate: "2024-05-20", status: "Concluída" },
        { id: "2", description: "Revisar plano de manutenção para frequência quinzenal", type: "Melhoria", responsible: "Eng. Confiabilidade", dueDate: "2024-06-01", status: "Em andamento" }
      ],
      reoccurred: false,
      effectivenessEvidence: "MTBF subiu significativamente.",
      needsRevision: true,
      needsTraining: true,
    };
    setAnalysis(demoData);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl p-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-4 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 border-b pb-3">
               <div>
                  <h2 className="text-lg font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-widest">Ativo e Contexto</p>
               </div>
               <button onClick={simulateFullAnalysis} className="bg-amber-100 hover:bg-amber-200 text-amber-800 text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-lg border border-amber-200 transition-all shadow-sm">
                  Simular Caso
               </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Área <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Produção" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Equipamento <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Bomba de recalque" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Tag <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: B-001" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-wider">Data da Falha <span className="text-red-500">*</span></label>
                <div className="relative">
                  <input type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={`${inputClasses} pl-10 cursor-pointer`} />
