            <p className="text-sm italic text-blue-800 leading-relaxed font-medium">"{analysis.summary}"</p>
          </section>
        )}

        <footer className="pt-12 flex justify-between items-end border-t border-slate-100 mt-10">
          <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Gerado em {new Date().toLocaleString()}</div>
          <div className="w-48 border-t border-slate-900 text-center pt-2">
            <p className="text-[9px] font-black uppercase">Responsável pela Análise</p>
            <p className="text-xs font-bold text-slate-500">{analysis.responsible || 'Engenharia de Confiabilidade'}</p>
          </div>
        </footer>
      </div>

      {/* Interface Principal (Oculta em Impressão) */}
      <div className="no-print h-full flex flex-col">
        <header className="bg-slate-900 text-white shadow-lg h-16 md:h-20 flex-shrink-0 z-50">
          <div className="max-w-7xl mx-auto px-4 md:px-6 h-full flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 w-9 h-9 rounded-lg flex items-center justify-center shadow-md">
                <i className="fas fa-industry text-base"></i>
              </div>
              <div>
                <h1 className="font-black text-sm md:text-base tracking-tight uppercase leading-none truncate max-w-[150px] sm:max-w-none">Análise de Falhas SWM Brasil</h1>
                <p className="text-[8px] text-blue-400 font-black tracking-widest uppercase mt-0.5">Engenharia e Confiabilidade</p>
