                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{group.step}</h4>
                    <div className="flex flex-wrap gap-2">
                      {group.errors.map((err, j) => (
                        <span key={j} className="inline-flex items-center gap-2 text-red-600 text-[10px] font-bold bg-red-50 px-3 py-1.5 rounded-full border border-red-100">
                          <i className="fas fa-times-circle text-[8px] opacity-50"></i>
                          {err}
                        </span>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
              <button onClick={() => setShowValidationModal(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-slate-200 transition-all hover:bg-black active:scale-95">
                Voltar e Corrigir
              </button>
            </div>
          </div>
        </div>
