      <div className="print-only p-10 space-y-8 text-slate-900">
        <header className="flex justify-between items-center border-b-4 border-slate-900 pb-6">
          <div>
            <h1 className="text-3xl font-black uppercase tracking-tight">Relatório de Análise de Falhas</h1>
            <p className="text-blue-600 font-bold uppercase tracking-[0.2em] text-sm">SWM Brasil — Engenharia e Confiabilidade</p>
          </div>
          <div className="text-right">
            <p className="text-xs font-black text-slate-400 uppercase">ID do Relatório</p>
            <p className="text-lg font-black">{analysis.id}</p>
          </div>
        </header>

        <section className="grid grid-cols-2 gap-6 bg-slate-50 p-6 rounded-2xl border border-slate-200">
          <div><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Área / Setor</p><p className="font-black">{analysis.area || '—'}</p></div>
          <div><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Equipamento</p><p className="font-black">{analysis.equipment || '—'}</p></div>
          <div><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Tag / Ativo</p><p className="font-black">{analysis.tag || '—'}</p></div>
          <div><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Data da Falha</p><p className="font-black">{analysis.failureDate || '—'}</p></div>
        </section>

        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-100 pb-2">Descrição Técnica</h2>
          <p className="text-sm leading-relaxed">{analysis.description || 'Nenhuma descrição fornecida.'}</p>
        </section>

        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-100 pb-2">Análise 5W1H</h2>
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-slate-50 p-4 rounded-xl"><p className="text-[9px] font-bold text-slate-400 uppercase mb-1">O QUE aconteceu?</p><p className="text-xs font-medium">{analysis.what || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl"><p className="text-[9px] font-bold text-slate-400 uppercase mb-1">ONDE ocorreu?</p><p className="text-xs font-medium">{analysis.where || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl"><p className="text-[9px] font-bold text-slate-400 uppercase mb-1">QUANDO ocorreu?</p><p className="text-xs font-medium">{analysis.when || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl"><p className="text-[9px] font-bold text-slate-400 uppercase mb-1">COMO foi percebido?</p><p className="text-xs font-medium">{analysis.how || '—'}</p></div>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-100 pb-2">5 Porquês e Causa Raiz</h2>
          <div className="space-y-2">
            {analysis.whys.map((w, i) => w && (
              <div key={i} className="flex gap-3 items-center text-xs">
                <span className="w-6 h-6 bg-slate-900 text-white rounded-full flex items-center justify-center font-black">{i+1}</span>
                <p className="font-medium text-slate-700">{w}</p>
              </div>
            ))}
          </div>
          <div className="bg-blue-900 text-white p-6 rounded-2xl mt-4">
            <p className="text-[9px] font-black uppercase mb-1 opacity-60">Causa Raiz Fundamental</p>
            <p className="text-lg font-black">{analysis.rootCause || '—'}</p>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-100 pb-2">Ishikawa (6M)</h2>
          <div className="grid grid-cols-2 gap-4">
            {(Object.entries(analysis.ishikawa) as [string, IshikawaCategory][]).map(([key, cat]) => (
              cat.causes.length > 0 && (
                <div key={key} className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[9px] font-black uppercase mb-2 text-blue-600">{key}</p>
                  <ul className="list-disc list-inside text-[10px] space-y-1 font-medium text-slate-600">
                    {cat.causes.map((c, idx) => <li key={idx}>{c}</li>)}
                  </ul>
                </div>
              )
            ))}
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-100 pb-2">Plano de Ação</h2>
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest">
                <th className="p-3">Ação</th>
                <th className="p-3">Tipo</th>
                <th className="p-3">Responsável</th>
                <th className="p-3">Prazo</th>
                <th className="p-3">Status</th>
              </tr>
            </thead>
            <tbody className="text-[10px] font-medium text-slate-700">
              {analysis.actions.map(a => (
                <tr key={a.id} className="border-b border-slate-100">
                  <td className="p-3 font-bold">{a.description}</td>
                  <td className="p-3">{a.type}</td>
                  <td className="p-3">{a.responsible}</td>
                  <td className="p-3">{a.dueDate}</td>
                  <td className="p-3 font-black text-blue-600">{a.status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        {analysis.summary && (
