import React, { useState, useMemo } from 'react';
import { Analysis } from '../types';

interface Props {
  onLoad: (analysis: Analysis) => void;
  onDelete: (id: string) => void;
  onNew: () => void;
}

const HistoryView: React.FC<Props> = ({ onLoad, onDelete, onNew }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [areaFilter, setAreaFilter] = useState('Todas');

  const history: Analysis[] = useMemo(() => {
    const saved = localStorage.getItem('analysis_history');
    return saved ? JSON.parse(saved) : [];
  }, []);

  const areas = useMemo(() => {
    const uniqueAreas = new Set(history.map(a => a.area).filter(Boolean));
    return ['Todas', ...Array.from(uniqueAreas)];
  }, [history]);

  const filteredHistory = useMemo(() => {
    return history.filter(item => {
      const matchesSearch = 
        item.equipment.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.tag.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesArea = areaFilter === 'Todas' || item.area === areaFilter;

      return matchesSearch && matchesArea;
    }).sort((a, b) => new Date(b.failureDate).getTime() - new Date(a.failureDate).getTime());
  }, [history, searchTerm, areaFilter]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Histórico de Análises</h2>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Gerenciamento de Ativos e Registros</p>
        </div>
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          <button 
            onClick={onNew}
            className="bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest px-6 py-3 rounded-xl hover:bg-blue-700 transition-all shadow-md flex items-center justify-center gap-2"
          >
            <i className="fas fa-plus"></i> Nova Análise
          </button>
          <div className="relative flex-1 sm:w-64">
            <label htmlFor="search-history" className="sr-only">Buscar no histórico</label>
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm" aria-hidden="true"></i>
            <input 
              id="search-history"
              type="text"
              placeholder="Buscar por tag, nome ou ID..."
              className="w-full pl-10 pr-4 py-3 bg-slate-100 border-none rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none min-h-[44px]"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative flex-1 sm:w-48">
            <label htmlFor="area-filter" className="sr-only">Filtrar por área</label>
            <select 
              id="area-filter"
              className="w-full bg-slate-100 border-none rounded-xl px-4 py-3 text-sm font-bold text-slate-600 outline-none focus:ring-2 focus:ring-blue-500 min-h-[44px]"
              value={areaFilter}
              onChange={e => setAreaFilter(e.target.value)}
            >
              {areas.map(area => <option key={area} value={area}>{area}</option>)}
            </select>
          </div>
        </div>
      </div>

      <ul className="grid grid-cols-1 gap-4" role="list">
        {filteredHistory.length > 0 ? (
          filteredHistory.map(item => (
            <li key={item.id} className="bg-white border border-slate-200 rounded-2xl p-5 md:p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-4 hover:shadow-md transition-shadow group">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0" aria-hidden="true">
                  <i className="fas fa-file-invoice text-xl"></i>
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{item.id}</span>
                    <span className="text-[10px] font-bold text-slate-400" aria-hidden="true">•</span>
                    <time dateTime={item.failureDate} className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(item.failureDate).toLocaleDateString('pt-BR')}</time>
                  </div>
                  <h3 className="text-lg font-black text-slate-800 leading-tight group-hover:text-blue-600 transition-colors">{item.equipment || "Sem Nome"}</h3>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-tighter">{item.area} — <span className="text-slate-400">{item.tag}</span></p>
                </div>
              </div>

              <div className="flex items-center gap-3 w-full md:w-auto mt-2 md:mt-0 pt-4 md:pt-0 border-t md:border-t-0 border-slate-100">
                <button 
                  onClick={() => onLoad(item)}
                  className="flex-1 md:flex-initial bg-slate-900 text-white text-xs font-black uppercase tracking-widest px-8 py-4 rounded-xl hover:bg-black transition-colors min-h-[48px]"
                >
                  Abrir Relatório
                </button>
                <button 
                  onClick={() => onDelete(item.id)}
                  className="p-4 text-slate-300 hover:text-red-500 transition-colors min-h-[48px] min-w-[48px] flex items-center justify-center"
                  aria-label={`Excluir análise de ${item.equipment}`}
                >
                  <i className="fas fa-trash-alt" aria-hidden="true"></i>
                </button>
              </div>
            </li>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
            <i className="fas fa-folder-open text-4xl text-slate-200 mb-4" aria-hidden="true"></i>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm mb-6">Nenhuma análise encontrada</p>
            <button 
              onClick={onNew}
              className="bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest px-8 py-4 rounded-2xl hover:bg-blue-700 transition-all shadow-lg"
            >
              Iniciar Primeira Análise
            </button>
          </div>
        )}
      </ul>
    </div>
  );
};

