            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">ONDE ocorreu?</p><p className="text-xs font-bold">{analysis.where || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">QUANDO ocorreu?</p><p className="text-xs font-bold">{analysis.when || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">QUEM estava envolvido?</p><p className="text-xs font-bold">{analysis.who || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">QUANTO impacto gerou?</p><p className="text-xs font-bold">{analysis.howMuch || '—'}</p></div>
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">COMO foi percebido?</p><p className="text-xs font-bold">{analysis.how || '—'}</p></div>
          </div>
        </section>

        {/* 3. Detalhamento */}
        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-900 pb-2 uppercase tracking-wide">3. Detalhamento e Contexto</h2>
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-1 bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Sintoma Observado</p><p className="text-xs font-bold">{analysis.symptom || '—'}</p></div>
            <div className="col-span-1 bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Frequência da Falha</p><p className="text-xs font-bold">{analysis.frequency || '—'}</p></div>
            <div className="col-span-2 bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Condições no Momento da Falha</p><p className="text-xs font-bold">{analysis.condition || '—'}</p></div>
            <div className="col-span-2 bg-slate-50 p-4 rounded-xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Histórico Recente / Manutenções Prévias</p><p className="text-xs font-bold">{analysis.history || '—'}</p></div>
          </div>
        </section>

        {/* 4. 5 Porquês */}
        <section className="space-y-4 page-break-before">
          <h2 className="text-xl font-black border-b-2 border-slate-900 pb-2 uppercase tracking-wide">4. Matriz dos 5 Porquês</h2>
          <div className="space-y-3 bg-white p-6 rounded-2xl border border-slate-200">
            {analysis.whys.map((w, i) => w && (
              <div key={i} className="flex gap-4 items-center">
                <span className="w-8 h-8 bg-slate-900 text-white rounded-full flex items-center justify-center font-black text-xs shrink-0">{i+1}</span>
                <div>
                  <p className="text-[8px] font-black text-slate-400 uppercase">Por quê?</p>
                  <p className="text-sm font-semibold text-slate-800">{w}</p>
                </div>
              </div>
            ))}
          </div>
          <div className="bg-blue-900 text-white p-6 rounded-2xl mt-4 flex justify-between items-center">
            <div>
              <p className="text-[9px] font-black uppercase mb-1 opacity-60">Causa Raiz Fundamental</p>
              <p className="text-xl font-black">{analysis.rootCause || 'NÃO DEFINIDA'}</p>
            </div>
            <i className="fas fa-bullseye text-3xl opacity-20"></i>
          </div>
        </section>

        {/* 5. Ishikawa */}
        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-900 pb-2 uppercase tracking-wide">5. Diagrama de Ishikawa (6M)</h2>
          <div className="grid grid-cols-2 gap-4">
            {(Object.entries(analysis.ishikawa) as [string, IshikawaCategory][]).map(([key, cat]) => (
              cat.causes.length > 0 && (
                <div key={key} className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                  <p className="text-[9px] font-black uppercase mb-2 text-blue-600 flex items-center gap-2">
                    <i className="fas fa-circle text-[6px]"></i> {key === 'machine' ? 'MÁQUINA' : key === 'method' ? 'MÉTODO' : key === 'material' ? 'MATERIAL' : key === 'manpower' ? 'MÃO DE OBRA' : key === 'measurement' ? 'MEDIÇÃO' : 'MEIO AMBIENTE'}
                  </p>
                  <ul className="space-y-1">
                    {cat.causes.map((c, idx) => <li key={idx} className="text-xs font-semibold text-slate-700 flex items-start gap-2">
                      <span className="text-blue-300">•</span> {c}
                    </li>)}
                  </ul>
                </div>
              )
            ))}
          </div>
        </section>

        {/* 6. Plano de Ação */}
        <section className="space-y-4 page-break-before">
          <h2 className="text-xl font-black border-b-2 border-slate-900 pb-2 uppercase tracking-wide">6. Plano de Ação Corretivo/Preventivo</h2>
          <table className="w-full text-left border-collapse rounded-xl overflow-hidden shadow-sm border border-slate-200">
            <thead>
              <tr className="bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest">
                <th className="p-4">Descrição da Ação</th>
                <th className="p-4">Tipo</th>
                <th className="p-4">Responsável</th>
                <th className="p-4">Prazo</th>
                <th className="p-4">Status</th>
              </tr>
            </thead>
            <tbody className="text-xs font-semibold text-slate-700 bg-white">
              {analysis.actions.length > 0 ? (
                analysis.actions.map(a => (
                  <tr key={a.id} className="border-b border-slate-100 last:border-0 hover:bg-slate-50">
                    <td className="p-4 max-w-[250px]">{a.description}</td>
                    <td className="p-4"><span className="px-2 py-1 rounded-full bg-slate-100 text-[9px] font-black">{a.type}</span></td>
                    <td className="p-4">{a.responsible}</td>
                    <td className="p-4">{a.dueDate || '—'}</td>
                    <td className="p-4"><span className="text-blue-600 font-black">{a.status}</span></td>
                  </tr>
                ))
              ) : (
                <tr><td colSpan={5} className="p-8 text-center text-slate-400 italic">Nenhuma ação cadastrada para esta falha.</td></tr>
              )}
            </tbody>
          </table>
        </section>

        {/* 7. Verificação */}
        <section className="space-y-4">
          <h2 className="text-xl font-black border-b-2 border-slate-900 pb-2 uppercase tracking-wide">7. Verificação e Eficácia</h2>
          <div className="grid grid-cols-2 gap-6">
            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
              <p className="text-[10px] font-black text-slate-400 uppercase mb-2">A falha voltou a ocorrer?</p>
              <p className={`text-xl font-black ${analysis.reoccurred ? 'text-red-600' : 'text-green-600'}`}>
                {analysis.reoccurred === true ? 'SIM, RECORRÊNCIA IDENTIFICADA' : analysis.reoccurred === false ? 'NÃO, AÇÕES EFICAZES' : 'AGUARDANDO VERIFICAÇÃO'}
              </p>
              <div className="mt-4">
                <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Evidências de Eficácia</p>
                <p className="text-xs font-semibold text-slate-700 bg-white p-3 rounded-lg border border-slate-100">{analysis.effectivenessEvidence || 'Nenhuma evidência descrita.'}</p>
              </div>
            </div>
            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 flex flex-col justify-center gap-3">
               <div className="flex items-center gap-3">
                  <div className={`w-5 h-5 rounded flex items-center justify-center border-2 ${analysis.needsRevision ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-300 bg-white'}`}>
                    {analysis.needsRevision && <i className="fas fa-check text-[10px]"></i>}
                  </div>
                  <span className="text-xs font-black uppercase text-slate-700">Necessita Revisão de Procedimento</span>
               </div>
               <div className="flex items-center gap-3">
                  <div className={`w-5 h-5 rounded flex items-center justify-center border-2 ${analysis.needsTraining ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-300 bg-white'}`}>
                    {analysis.needsTraining && <i className="fas fa-check text-[10px]"></i>}
                  </div>
                  <span className="text-xs font-black uppercase text-slate-700">Necessita Treinamento da Equipe</span>
               </div>
            </div>
          </div>
        </section>

        {/* IA Summary */}
        {analysis.summary && (
          <section className="bg-blue-50 p-8 rounded-[32px] border border-blue-100 relative overflow-hidden">
            <i className="fas fa-brain absolute -right-6 -bottom-6 text-9xl text-blue-100"></i>
            <h2 className="text-xl font-black text-blue-900 mb-4 flex items-center gap-3 relative z-10"><i className="fas fa-robot"></i> Resumo Executivo da Inteligência Artificial</h2>
            <p className="text-sm italic text-blue-800 leading-relaxed font-semibold relative z-10">"{analysis.summary}"</p>
          </section>
        )}

        <footer className="pt-12 flex justify-between items-end border-t border-slate-200 mt-10">
          <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest">
            Documento gerado eletronicamente em {new Date().toLocaleString('pt-BR')} via SWM Failure Analysis System
          </div>
          <div className="w-64 border-t border-slate-900 text-center pt-2">
            <p className="text-[9px] font-black uppercase tracking-widest mb-1 text-slate-400">Assinatura do Responsável</p>
            <p className="text-xs font-black text-slate-900">{analysis.responsible || 'Engenheiro Responsável'}</p>
            <p className="text-[8px] font-bold text-slate-400">{analysis.area || 'Setor Técnico'}</p>
          </div>
        </footer>
      </div>

      {/* Interface Principal (Oculta em Impressão) */}
      <div className="no-print h-full flex flex-col">
        <header className="bg-slate-900 text-white shadow-lg h-16 md:h-20 flex-shrink-0 z-50">
          <div className="max-w-7xl mx-auto px-4 md:px-6 h-full flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 w-9 h-9 rounded-lg flex items-center justify-center shadow-md">
                <i className="fas fa-industry text-base"></i>
              </div>
              <div>
                <h1 className="font-black text-sm md:text-base tracking-tight uppercase leading-none truncate max-w-[150px] sm:max-w-none">Análise de Falhas SWM Brasil</h1>
                <p className="text-[8px] text-blue-400 font-black tracking-widest uppercase mt-0.5">Engenharia e Confiabilidade</p>
              </div>
            </div>
            <nav className="flex gap-2 font-black uppercase tracking-widest text-[9px] md:text-[10px]">
              <button 
                onClick={startNewAnalysis} 
                className={`px-4 py-2 rounded-xl transition-all ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-lg scale-105' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
              >
                Novo
              </button>
              <button onClick={() => setCurrentStep(StepId.HISTORY)} className={`px-4 py-2 rounded-xl transition-all ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-white'}`}>Histórico</button>
              <button onClick={() => setCurrentStep(StepId.DASHBOARD)} className={`px-4 py-2 rounded-xl transition-all ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-white'}`}>Dashboard</button>
            </nav>
          </div>
        </header>

        {currentStep < StepId.DASHBOARD && (
          <nav className="bg-white border-b flex-shrink-0 z-40 overflow-x-auto no-scrollbar shadow-sm">
            <div className="max-w-7xl mx-auto px-4 md:px-6 py-4 flex items-center justify-between gap-4 min-w-[700px] md:min-w-0">
              {STEPS.map((step, idx) => (
                <React.Fragment key={step.id}>
                  <button onClick={() => setCurrentStep(step.id)} className={`flex flex-col items-center gap-1 transition-all flex-shrink-0 ${currentStep === step.id ? 'opacity-100' : 'opacity-30 hover:opacity-100'}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-[10px] transition-all ${currentStep === step.id ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500'}`}>
                      {currentStep > step.id ? <i className="fas fa-check"></i> : step.icon}
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-wider ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
                  </button>
                  {idx < STEPS.length - 1 && <div className={`flex-1 h-px rounded-full ${currentStep > idx ? 'bg-blue-600' : 'bg-slate-100'}`}></div>}
                </React.Fragment>
              ))}
            </div>
          </nav>
        )}

        <main className="flex-1 flex flex-col overflow-hidden relative">
          <div id="step-scroll-container" className="flex-1 overflow-y-auto px-4 py-6 md:px-8">
            <div className="max-w-7xl mx-auto">
              <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 md:p-10 mb-20">
                {renderStepContent()}
              </div>
            </div>
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="absolute bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-slate-100 p-4 md:p-6 z-50">
              <div className="max-w-7xl mx-auto flex items-center justify-between">
                <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center gap-2 text-slate-400 font-black uppercase text-[10px] hover:text-slate-900 disabled:opacity-20 transition-all px-4 py-2">
                  <i className="fas fa-arrow-left"></i> Voltar
                </button>
                <div className="flex gap-2">
                  <button onClick={saveDraft} className="hidden sm:block text-slate-500 bg-slate-50 hover:bg-slate-100 px-6 py-3 rounded-xl font-bold text-[10px] uppercase tracking-widest border border-slate-200">Salvar Rascunho</button>
                  {currentStep < StepId.VERIFICATION ? (
                    <button onClick={handleNext} className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-3.5 rounded-xl font-black uppercase text-[10px] shadow-lg shadow-blue-200 transition-all flex items-center gap-3">
                      Próximo <i className="fas fa-arrow-right"></i>
                    </button>
                  ) : (
                    <button onClick={finalizeAnalysis} className="bg-slate-900 hover:bg-black text-white px-10 py-3.5 rounded-xl font-black uppercase text-[10px] shadow-lg transition-all">Finalizar Relatório</button>
                  )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa, IshikawaCategory } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [validationErrors, setValidationErrors] = useState<{ step: string, errors: string[] }[]>([]);
  const [showValidationModal, setShowValidationModal] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const validateAllSteps = (): { step: string, errors: string[] }[] => {
    const allErrors: { step: string, errors: string[] }[] = [];

    const step1Errors: string[] = [];
    if (!analysis.area.trim()) step1Errors.push("Área / Setor");
    if (!analysis.equipment.trim()) step1Errors.push("Nome do Equipamento");
    if (!analysis.tag.trim()) step1Errors.push("Tag do Ativo");
    if (!analysis.description.trim()) step1Errors.push("Descrição do problema");
    if (step1Errors.length > 0) allErrors.push({ step: "1. Identificação Geral", errors: step1Errors });

    const step2Errors: string[] = [];
    if (!analysis.what.trim()) step2Errors.push("O QUE aconteceu");
    if (!analysis.where.trim()) step2Errors.push("ONDE ocorreu");
    if (!analysis.when.trim()) step2Errors.push("QUANDO ocorreu");
    if (!analysis.how.trim()) step2Errors.push("COMO foi percebido");
    if (step2Errors.length > 0) allErrors.push({ step: "2. Entendendo o Problema (5W1H)", errors: step2Errors });

    const step3Errors: string[] = [];
    if (!analysis.symptom.trim()) step3Errors.push("Sintoma observado");
    if (step3Errors.length > 0) allErrors.push({ step: "3. Detalhamento", errors: step3Errors });

    const step4Errors: string[] = [];
    if (!analysis.whys[0].trim()) step4Errors.push("1º Porquê fundamental");
    if (!analysis.rootCause.trim()) step4Errors.push("Causa Raiz fundamental");
    if (step4Errors.length > 0) allErrors.push({ step: "4. Matriz dos 5 Porquês", errors: step4Errors });

    const step6Errors: string[] = [];
    if (analysis.actions.length === 0) {
      step6Errors.push("Nenhuma ação cadastrada");
    } else {
      if (analysis.actions.some(a => !a.description.trim())) step6Errors.push("Ações sem descrição");
      if (analysis.actions.some(a => !a.responsible.trim())) step6Errors.push("Ações sem responsável");
    }
    if (step6Errors.length > 0) allErrors.push({ step: "6. Plano de Ação", errors: step6Errors });

    const step7Errors: string[] = [];
    if (analysis.reoccurred === null) step7Errors.push("Informar se a falha voltou a ocorrer");
    if (step7Errors.length > 0) allErrors.push({ step: "7. Verificação e Padronização", errors: step7Errors });

    return allErrors;
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasSignificantData = analysis.equipment.trim() !== '' || 
                               analysis.description.trim() !== '' || 
                               analysis.area.trim() !== '';

    if (hasSignificantData && currentStep < StepId.DASHBOARD) {
      if (!confirm("Deseja iniciar uma NOVA análise? Os dados atuais não salvos serão perdidos.")) return;
    }

    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
  };

  const finalizeAnalysis = () => {
    const allStepErrors = validateAllSteps();
    if (allStepErrors.length > 0) {
      setValidationErrors(allStepErrors);
      setShowValidationModal(true);
      return;
    }

    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const saveDraft = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    alert("Rascunho salvo com sucesso no histórico!");
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const simulateFullAnalysis = () => {
    const demoData: Analysis = {
      ...getInitialState(),
      area: "Produção / Celulose",
      equipment: "Refinador de Ajuste MP3",
      tag: "REF-302-B",
      failureDate: new Date().toISOString().split('T')[0],
      shift: "B - Noturno",
      responsible: "Eng. Ricardo Silva",
      description: "Parada súbita do motor principal do refinador durante a rampa de carga, ocasionando desarme do disjuntor de proteção térmica por sobrecarga.",
      what: "Desarme do motor principal por sobrecorrente.",
      where: "Mancal traseiro do motor de 500cv.",
      when: "Durante o aumento de pressão na câmara de refino (85% de carga).",
      who: "Operador de Painel Sr. João Santos.",
      howMuch: "4 horas de produção perdida (aprox. 120 toneladas de polpa).",
      how: "Alarme sonoro seguido de parada instantânea.",
      symptom: "Fumaça leve e cheiro de queimado no compartimento do motor.",
