            onClick={onNew}
            className="bg-blue-600 text-white text-[11px] font-black uppercase tracking-widest px-8 py-4.5 rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 flex items-center justify-center gap-3 order-last sm:order-first"
