            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
            <input 
              type="text"
              placeholder="Buscar tag, nome ou ID..."
              className="w-full pl-12 pr-5 py-4.5 bg-slate-100 border-none rounded-2xl text-base md:text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-inner min-h-[56px] font-medium"
