              {areas.map(area => <option key={area} value={area}>{area}</option>)}
            </select>
            <i className="fas fa-chevron-down absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none"></i>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-5" role="list">
        {filteredHistory.length > 0 ? (
          filteredHistory.map(item => (
            <div key={item.id} className="bg-white border border-slate-100 rounded-[32px] p-6 md:p-8 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 hover:shadow-xl transition-all group animate-slideUp">
              <div className="flex items-center gap-6 w-full">
                <div className="w-16 h-16 rounded-[24px] bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0 border border-blue-100/50 shadow-inner group-hover:bg-blue-600 group-hover:text-white transition-all">
                  <i className="fas fa-file-invoice text-2xl"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mb-1">
                    <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-lg uppercase tracking-widest">{item.id}</span>
                    <time dateTime={item.failureDate} className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(item.failureDate).toLocaleDateString('pt-BR')}</time>
                  </div>
                  <h3 className="text-xl font-black text-slate-800 leading-tight truncate group-hover:text-blue-600 transition-colors">{item.equipment || "Equipamento s/ Nome"}</h3>
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">
                    {item.area || "Sem Área"} <span className="text-slate-200 mx-2" aria-hidden="true">|</span> <span className="text-slate-400 font-black">{item.tag || "Sem Tag"}</span>
                  </p>
