{
  "name": "Análise de Falhas SWM Brasil - Engenharia de Manutenção",
  "description": "A high-performance web application for industrial failure analysis using PDCA, 5W2H, 5 Whys, and Ishikawa diagrams, featuring AI-powered insights.",
  "requestFramePermissions": []
}

import React, { useState, useEffect } from 'react';
import { Analysis, StepId, Action, Ishikawa, IshikawaCategory } from './types';
import { STEPS, TIPS } from './constants';
import IshikawaComponent from './components/IshikawaComponent';
import Dashboard from './components/Dashboard';
import HistoryView from './components/HistoryView';
import { generateSummary, suggestRootCause } from './services/geminiService';

const INITIAL_ISHIKAWA: Ishikawa = {
  machine: { causes: [], attachments: [] },
  method: { causes: [], attachments: [] },
  material: { causes: [], attachments: [] },
  manpower: { causes: [], attachments: [] },
  measurement: { causes: [], attachments: [] },
  environment: { causes: [], attachments: [] },
};

const getInitialState = (): Analysis => ({
  id: 'AN-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
  area: '',
  equipment: '',
  tag: '',
  failureDate: new Date().toISOString().split('T')[0],
  shift: '',
  responsible: '',
  description: '',
  what: '',
  where: '',
  when: '',
  who: '',
  howMuch: '',
  how: '',
  symptom: '',
  condition: '',
  history: '',
  frequency: 'Eventual',
  whys: ['', '', '', '', ''],
  rootCause: '',
  ishikawa: INITIAL_ISHIKAWA,
  actions: [],
  reoccurred: null,
  effectivenessEvidence: '',
  needsRevision: false,
  needsTraining: false,
});

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<StepId>(StepId.IDENTIFICATION);
  const [analysis, setAnalysis] = useState<Analysis>(getInitialState());
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [validationErrors, setValidationErrors] = useState<{ step: string, errors: string[] }[]>([]);
  const [showValidationModal, setShowValidationModal] = useState(false);

  useEffect(() => {
    if (currentStep < StepId.DASHBOARD) {
      localStorage.setItem('swm_draft_analysis', JSON.stringify(analysis));
    }
  }, [analysis, currentStep]);

  const updateAnalysis = (data: Partial<Analysis>) => {
    setAnalysis(prev => ({ ...prev, ...data }));
  };

  const validateAllSteps = (): { step: string, errors: string[] }[] => {
    const allErrors: { step: string, errors: string[] }[] = [];

    const step1Errors: string[] = [];
    if (!analysis.area.trim()) step1Errors.push("Área / Setor");
    if (!analysis.equipment.trim()) step1Errors.push("Nome do Equipamento");
    if (!analysis.tag.trim()) step1Errors.push("Tag do Ativo");
    if (!analysis.description.trim()) step1Errors.push("Descrição do problema");
    if (step1Errors.length > 0) allErrors.push({ step: "1. Identificação Geral", errors: step1Errors });

    const step2Errors: string[] = [];
    if (!analysis.what.trim()) step2Errors.push("O QUE aconteceu");
    if (!analysis.where.trim()) step2Errors.push("ONDE ocorreu");
    if (!analysis.when.trim()) step2Errors.push("QUANDO ocorreu");
    if (!analysis.how.trim()) step2Errors.push("COMO foi percebido");
    if (step2Errors.length > 0) allErrors.push({ step: "2. Entendendo o Problema (5W1H)", errors: step2Errors });

    const step3Errors: string[] = [];
    if (!analysis.symptom.trim()) step3Errors.push("Sintoma observado");
    if (step3Errors.length > 0) allErrors.push({ step: "3. Detalhamento", errors: step3Errors });

    const step4Errors: string[] = [];
    if (!analysis.whys[0].trim()) step4Errors.push("1º Porquê fundamental");
    if (!analysis.rootCause.trim()) step4Errors.push("Causa Raiz fundamental");
    if (step4Errors.length > 0) allErrors.push({ step: "4. Matriz dos 5 Porquês", errors: step4Errors });

    const step6Errors: string[] = [];
    if (analysis.actions.length === 0) {
      step6Errors.push("Nenhuma ação cadastrada");
    } else {
      if (analysis.actions.some(a => !a.description.trim())) step6Errors.push("Ações sem descrição");
      if (analysis.actions.some(a => !a.responsible.trim())) step6Errors.push("Ações sem responsável");
    }
    if (step6Errors.length > 0) allErrors.push({ step: "6. Plano de Ação", errors: step6Errors });

    const step7Errors: string[] = [];
    if (analysis.reoccurred === null) step7Errors.push("Informar se a falha voltou a ocorrer");
    if (step7Errors.length > 0) allErrors.push({ step: "7. Verificação e Padronização", errors: step7Errors });

    return allErrors;
  };

  const handleNext = () => {
    if (currentStep < StepId.VERIFICATION) {
      setCurrentStep(prev => prev + 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (currentStep > StepId.IDENTIFICATION) {
      setCurrentStep(prev => prev - 1);
      document.getElementById('step-scroll-container')?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startNewAnalysis = () => {
    const hasSignificantData = analysis.equipment.trim() !== '' || 
                               analysis.description.trim() !== '' || 
                               analysis.area.trim() !== '';

    if (hasSignificantData && currentStep < StepId.DASHBOARD) {
      if (!confirm("Deseja iniciar uma NOVA análise? Os dados atuais não salvos serão perdidos.")) return;
    }

    setAnalysis(getInitialState());
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(false);
  };

  const finalizeAnalysis = () => {
    const allStepErrors = validateAllSteps();
    if (allStepErrors.length > 0) {
      setValidationErrors(allStepErrors);
      setShowValidationModal(true);
      return;
    }

    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    localStorage.removeItem('swm_draft_analysis');
    setCurrentStep(StepId.HISTORY);
    setShowSummary(false);
  };

  const saveDraft = () => {
    const historyRaw = localStorage.getItem('analysis_history');
    const history: Analysis[] = historyRaw ? JSON.parse(historyRaw) : [];
    const existingIndex = history.findIndex(h => h.id === analysis.id);
    const updatedAnalysis = { ...analysis, lastUpdated: new Date().toISOString() };
    if (existingIndex > -1) { history[existingIndex] = updatedAnalysis; } else { history.push(updatedAnalysis); }
    localStorage.setItem('analysis_history', JSON.stringify(history));
    alert("Rascunho salvo com sucesso no histórico!");
  };

  const loadFromHistory = (loadedAnalysis: Analysis) => {
    setAnalysis(loadedAnalysis);
    setCurrentStep(StepId.IDENTIFICATION);
    setShowSummary(!!loadedAnalysis.summary);
  };

  const deleteFromHistory = (id: string) => {
    if (!confirm("Excluir esta análise permanentemente?")) return;
    const historyRaw = localStorage.getItem('analysis_history');
    if (!historyRaw) return;
    const history: Analysis[] = JSON.parse(historyRaw);
    const updated = history.filter(h => h.id !== id);
    localStorage.setItem('analysis_history', JSON.stringify(updated));
    setCurrentStep(StepId.HISTORY);
  };

  const addAction = () => {
    const newAction: Action = { id: Date.now().toString(), description: '', type: 'Corretiva', responsible: '', dueDate: '', status: 'Aberta' };
    updateAnalysis({ actions: [newAction, ...analysis.actions] });
  };

  const updateAction = (id: string, data: Partial<Action>) => {
    const updated = analysis.actions.map(a => a.id === id ? { ...a, ...data } : a);
    updateAnalysis({ actions: updated });
  };

  const removeAction = (id: string) => {
    updateAnalysis({ actions: analysis.actions.filter(a => a.id !== id) });
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingSummary(true);
    const summary = await generateSummary(analysis);
    updateAnalysis({ summary });
    setIsGeneratingSummary(false);
    setShowSummary(true);
  };

  const handleSuggestCause = async () => {
    const cause = await suggestRootCause(analysis);
    updateAnalysis({ rootCause: cause });
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const renderStepContent = () => {
    const inputClasses = "w-full border-slate-200 bg-white text-slate-900 rounded-xl px-4 py-3.5 text-base md:text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none border transition-all shadow-sm placeholder:text-slate-400 min-h-[48px]";

    switch (currentStep) {
      case StepId.IDENTIFICATION:
        return (
          <div className="space-y-6 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b pb-4">
               <div>
                  <h2 className="text-xl font-bold text-slate-800">1. Identificação Geral</h2>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-0.5">Ativo e Contexto</p>
               </div>
               <button onClick={() => setAnalysis(getInitialState())} className="w-full sm:w-auto bg-slate-100 hover:bg-slate-200 text-slate-700 text-[10px] font-black uppercase tracking-widest px-5 py-3 rounded-xl border border-slate-200 transition-all shadow-sm flex items-center justify-center gap-2">
                  <i className="fas fa-eraser"></i> Limpar Tudo
               </button>
            </header>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Área / Setor <span className="text-red-500" aria-hidden="true">*</span></label>
                <input type="text" value={analysis.area} onChange={e => updateAnalysis({ area: e.target.value })} className={inputClasses} placeholder="Ex: Produção" aria-required="true" />
              </div>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Equipamento <span className="text-red-500" aria-hidden="true">*</span></label>
                <input type="text" value={analysis.equipment} onChange={e => updateAnalysis({ equipment: e.target.value })} className={inputClasses} placeholder="Ex: Bomba de recalque" aria-required="true" />
              </div>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Tag do Ativo <span className="text-red-500" aria-hidden="true">*</span></label>
                <input type="text" value={analysis.tag} onChange={e => updateAnalysis({ tag: e.target.value })} className={inputClasses} placeholder="Ex: B-001" aria-required="true" />
              </div>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Data da Falha <span className="text-red-500" aria-hidden="true">*</span></label>
                <div className="relative">
                  <input type="date" value={analysis.failureDate} onChange={e => updateAnalysis({ failureDate: e.target.value })} className={`${inputClasses} pl-11`} aria-required="true" />
                  <i className="fas fa-calendar-alt absolute left-4 top-1/2 -translate-y-1/2 text-blue-500 pointer-events-none"></i>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Turno</label>
                <input type="text" value={analysis.shift} onChange={e => updateAnalysis({ shift: e.target.value })} className={inputClasses} placeholder="Ex: B - Noturno" />
              </div>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Responsável</label>
                <input type="text" value={analysis.responsible} onChange={e => updateAnalysis({ responsible: e.target.value })} className={inputClasses} placeholder="Seu nome" />
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Descrição do Problema <span className="text-red-500" aria-hidden="true">*</span></label>
              <textarea value={analysis.description} onChange={e => updateAnalysis({ description: e.target.value })} className={`${inputClasses} h-32 md:h-40 resize-none`} placeholder="Relate o ocorrido tecnicamente..." aria-required="true" />
            </div>
          </div>
        );

      case StepId.W5H1:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">2. Entendendo o Problema (5W1H)</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
              {[
                { field: 'what', label: 'O QUE aconteceu?', required: true, icon: 'fa-circle-question' },
                { field: 'where', label: 'ONDE ocorreu?', required: true, icon: 'fa-location-dot' },
                { field: 'when', label: 'QUANDO ocorreu?', required: true, icon: 'fa-clock' },
                { field: 'who', label: 'QUEM estava envolvido?', required: false, icon: 'fa-user-group' },
                { field: 'howMuch', label: 'QUANTO impacto?', required: false, icon: 'fa-chart-line' },
                { field: 'how', label: 'COMO percebido?', required: true, icon: 'fa-eye' },
              ].map((item) => (
                <div key={item.field} className="space-y-1.5">
                  <label className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">
                    <i className={`fas ${item.icon} text-blue-500/50`}></i>
                    {item.label} {item.required && <span className="text-red-500">*</span>}
                  </label>
                  <textarea value={(analysis as any)[item.field]} onChange={e => updateAnalysis({ [item.field]: e.target.value })} className={`${inputClasses} h-24 resize-none`} />
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.DETAILS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">3. Detalhamento</h2>
            <div className="space-y-6">
              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Sintoma Observado <span className="text-red-500">*</span></label>
                <input type="text" value={analysis.symptom} onChange={e => updateAnalysis({ symptom: e.target.value })} className={inputClasses} placeholder="Ex: Vibração acima de 5mm/s" />
              </div>

              <div className="space-y-3">
                <span className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Frequência da Falha</span>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  {['Eventual', 'Recorrente', 'Crônica'].map(f => (
                    <button key={f} onClick={() => updateAnalysis({ frequency: f as any })} className={`flex items-center justify-center p-4 rounded-xl border-2 transition-all font-bold text-sm min-h-[56px] ${analysis.frequency === f ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}>
                      {f}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Condições no Momento</label>
                <textarea value={analysis.condition} onChange={e => updateAnalysis({ condition: e.target.value })} className={`${inputClasses} h-24 resize-none`} placeholder="Ex: Alta umidade, motor operando em sobrecarga..." />
              </div>

              <div className="space-y-1.5">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider">Histórico Recente</label>
                <textarea value={analysis.history} onChange={e => updateAnalysis({ history: e.target.value })} className={`${inputClasses} h-24 resize-none`} placeholder="Relate intervenções anteriores..." />
              </div>
            </div>
          </div>
        );

      case StepId.FIVE_WHYS:
        return (
          <div className="space-y-8 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b pb-4">
              <h2 className="text-xl font-bold text-slate-800">4. Investigação (5 Porquês)</h2>
              <button onClick={handleSuggestCause} className="w-full sm:w-auto bg-slate-900 text-white font-black px-6 py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest hover:bg-black">
                <i className="fas fa-robot"></i> Sugerir com IA
              </button>
            </header>
            <div className="space-y-5">
              {analysis.whys.map((why, idx) => (
                <div key={idx} className="flex gap-4 items-start">
                  <div className="w-10 h-10 rounded-full bg-blue-600 text-white flex items-center justify-center font-black text-sm shrink-0 mt-1 shadow-md shadow-blue-100">
                    {idx + 1}
                  </div>
                  <div className="flex-1 space-y-1">
                    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Por quê?</label>
                    <textarea value={why} onChange={e => {
                        const newWhys = [...analysis.whys];
                        newWhys[idx] = e.target.value;
                        updateAnalysis({ whys: newWhys });
                      }} className={`${inputClasses} h-20 resize-none`} placeholder={idx === 0 ? "Ação imediata ou efeito direto..." : "Opcional..."} />
                  </div>
                </div>
              ))}
            </div>
            <div className="p-6 bg-blue-900 rounded-[32px] text-white shadow-xl">
              <label className="block text-[10px] font-black uppercase mb-3 opacity-60 tracking-widest">Causa Raiz Fundamental <span className="text-blue-400" aria-hidden="true">*</span></label>
              <input type="text" value={analysis.rootCause} onChange={e => updateAnalysis({ rootCause: e.target.value })} className="w-full bg-white/10 text-white rounded-2xl p-4 font-bold border border-white/20 outline-none text-lg focus:bg-white/20 transition-all placeholder:text-white/20" placeholder="Conclusão final da investigação..." />
            </div>
          </div>
        );

      case StepId.ISHIKAWA:
        return <IshikawaComponent analysis={analysis} updateAnalysis={updateAnalysis} />;

      case StepId.ACTIONS:
        return (
          <div className="space-y-6 animate-fadeIn">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b pb-4">
              <h2 className="text-xl font-bold text-slate-800">6. Plano de Ação <span className="text-blue-500 font-medium text-xs ml-2">Mín. 1 ação obrigatória</span></h2>
              <button onClick={addAction} className="w-full sm:w-auto bg-blue-600 text-white text-[10px] font-black px-6 py-3.5 rounded-xl shadow-lg shadow-blue-200 transition-all uppercase tracking-widest hover:bg-blue-700">
                <i className="fas fa-plus mr-2"></i> Nova Ação
              </button>
            </header>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
              {analysis.actions.length === 0 && (
                <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-100 rounded-[32px]">
                   <i className="fas fa-clipboard-list text-4xl text-slate-100 mb-4"></i>
                   <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Nenhuma ação planejada</p>
                </div>
              )}
              {analysis.actions.map((action) => (
                <div key={action.id} className="bg-slate-50 border border-slate-200 rounded-3xl p-5 md:p-6 space-y-4 relative animate-slideUp">
                  <div className="flex items-center justify-between">
                    <div className="flex flex-wrap gap-2">
                      {(['Corretiva', 'Preventiva', 'Melhoria'] as const).map(type => (
                        <button key={type} onClick={() => updateAction(action.id, { type })} className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-tighter transition-all ${action.type === type ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-400 border border-slate-100'}`}>
                          {type}
                        </button>
                      ))}
                    </div>
                    <button onClick={() => removeAction(action.id)} className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-red-500 transition-colors bg-white border border-slate-100 rounded-xl hover:shadow-sm" aria-label="Remover ação">
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </div>
                  <textarea value={action.description} onChange={e => updateAction(action.id, { description: e.target.value })} className="w-full bg-white border border-slate-100 rounded-2xl p-4 text-sm font-medium resize-none h-24 outline-none focus:ring-2 focus:ring-blue-500" placeholder="Descreva a ação de bloqueio..." />
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest ml-1">Responsável</label>
                      <input type="text" value={action.responsible} onChange={e => updateAction(action.id, { responsible: e.target.value })} className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Nome do encarregado" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest ml-1">Prazo Final</label>
                      <input type="date" value={action.dueDate} onChange={e => updateAction(action.id, { dueDate: e.target.value })} className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {(['Aberta', 'Em andamento', 'Concluída'] as const).map(status => (
                      <button key={status} onClick={() => updateAction(action.id, { status })} className={`flex-1 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-tighter border-2 transition-all ${action.status === status ? (status === 'Concluída' ? 'bg-green-600 border-green-600 text-white' : status === 'Em andamento' ? 'bg-amber-500 border-amber-500 text-white' : 'bg-slate-900 border-slate-900 text-white') : 'bg-white text-slate-300 border-slate-50'}`}>
                        {status}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case StepId.VERIFICATION:
        return (
          <div className="space-y-8 animate-fadeIn">
            <h2 className="text-xl font-bold border-b pb-4 text-slate-800">7. Verificação e Padronização</h2>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-6 md:p-8 rounded-[32px] border border-slate-100 shadow-sm space-y-6">
                <div className="space-y-4">
                  <h3 className="font-black text-slate-800 uppercase text-[10px] tracking-widest">A falha voltou a ocorrer? <span className="text-red-500" aria-hidden="true">*</span></h3>
                  <div className="flex gap-4">
                    <button onClick={() => updateAnalysis({ reoccurred: true })} className={`flex-1 py-5 border-2 rounded-2xl font-black text-sm transition-all flex flex-col items-center gap-1 ${analysis.reoccurred === true ? 'bg-red-600 border-red-600 text-white shadow-lg' : 'bg-white text-slate-300 border-slate-50'}`}>
                      <i className="fas fa-thumbs-down text-lg"></i> SIM
                    </button>
                    <button onClick={() => updateAnalysis({ reoccurred: false })} className={`flex-1 py-5 border-2 rounded-2xl font-black text-sm transition-all flex flex-col items-center gap-1 ${analysis.reoccurred === false ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'bg-white text-slate-300 border-slate-50'}`}>
                      <i className="fas fa-thumbs-up text-lg"></i> NÃO
                    </button>
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Evidências de Eficácia</label>
                  <textarea value={analysis.effectivenessEvidence} onChange={e => updateAnalysis({ effectivenessEvidence: e.target.value })} className={inputClasses + " h-32 resize-none"} placeholder="Quais os indicadores de melhoria?" />
                </div>
              </div>

              <div className="bg-white p-6 md:p-8 rounded-[32px] border border-slate-100 shadow-sm flex flex-col gap-5">
                <h3 className="font-black text-slate-800 uppercase text-[10px] tracking-widest">Ações Finais e Exportação</h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  <button onClick={handleGenerateSummary} disabled={isGeneratingSummary} className="bg-slate-900 text-white font-black py-4.5 rounded-2xl shadow-lg flex items-center justify-center gap-3 text-[11px] uppercase tracking-widest hover:bg-black transition-all">
                    {isGeneratingSummary ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-brain"></i>}
                    Resumo IA
                  </button>
                  <button onClick={handlePrintPDF} className="bg-blue-600 text-white font-black py-4.5 rounded-2xl shadow-lg flex items-center justify-center gap-3 text-[11px] uppercase tracking-widest hover:bg-blue-700 transition-all">
                    <i className="fas fa-file-pdf"></i> PDF Completo
                  </button>
                </div>
                <div className="space-y-3 pt-4 border-t border-slate-50">
                  <button onClick={() => updateAnalysis({ needsRevision: !analysis.needsRevision })} className={`w-full flex items-center gap-4 p-4 rounded-2xl border-2 transition-all ${analysis.needsRevision ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-50'}`}>
                    <div className={`w-6 h-6 rounded flex items-center justify-center shrink-0 border-2 transition-all ${analysis.needsRevision ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-200'}`}>
                      {analysis.needsRevision && <i className="fas fa-check text-[10px]"></i>}
                    </div>
                    <span className="text-sm font-bold text-slate-700 text-left">Revisar procedimento técnico</span>
                  </button>
                  <button onClick={() => updateAnalysis({ needsTraining: !analysis.needsTraining })} className={`w-full flex items-center gap-4 p-4 rounded-2xl border-2 transition-all ${analysis.needsTraining ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-50'}`}>
                    <div className={`w-6 h-6 rounded flex items-center justify-center shrink-0 border-2 transition-all ${analysis.needsTraining ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-200'}`}>
                      {analysis.needsTraining && <i className="fas fa-check text-[10px]"></i>}
                    </div>
                    <span className="text-sm font-bold text-slate-700 text-left">Necessita treinamento da equipe</span>
                  </button>
                </div>
              </div>
            </div>
            {showSummary && analysis.summary && (
              <div className="p-8 bg-blue-900 text-white rounded-[40px] shadow-2xl animate-slideUp relative overflow-hidden">
                <i className="fas fa-quote-left absolute top-6 left-6 text-6xl opacity-10"></i>
                <h2 className="text-xl font-black mb-4 flex items-center gap-3 relative z-10"><i className="fas fa-robot text-blue-400"></i> Parecer da IA</h2>
                <p className="text-base italic leading-relaxed opacity-95 relative z-10 font-medium">"{analysis.summary}"</p>
              </div>
            )}
          </div>
        );

      case StepId.DASHBOARD: return <Dashboard />;
      case StepId.HISTORY: return <HistoryView onLoad={loadFromHistory} onDelete={deleteFromHistory} onNew={startNewAnalysis} />;
      default: return null;
    }
  };

  return (
    <div className="h-screen flex flex-col bg-[#F8FAFC] overflow-hidden">
      {showValidationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-fadeIn" role="alert" aria-modal="true">
          <div className="bg-white w-full max-w-lg rounded-[32px] shadow-2xl overflow-hidden animate-slideUp">
            <div className="bg-red-600 p-6 text-white flex items-center justify-between">
              <div className="flex items-center gap-4">
                <i className="fas fa-exclamation-triangle text-2xl"></i>
                <h3 className="font-black uppercase tracking-widest text-sm">Pendências de Preenchimento</h3>
              </div>
              <button onClick={() => setShowValidationModal(false)} className="w-10 h-10 flex items-center justify-center text-white hover:opacity-60" aria-label="Fechar"><i className="fas fa-times"></i></button>
            </div>
            <div className="p-8">
              <p className="text-slate-600 text-sm font-medium mb-6 leading-relaxed">Não é possível finalizar sem completar os seguintes campos:</p>
              <div className="space-y-6 mb-8 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar">
                {validationErrors.map((group, i) => (
                  <div key={i} className="space-y-3 border-l-4 border-slate-100 pl-4 py-1">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{group.step}</h4>
                    <div className="flex flex-wrap gap-2">
                      {group.errors.map((err, j) => (
                        <span key={j} className="inline-flex items-center gap-2 text-red-600 text-[10px] font-bold bg-red-50 px-3 py-1.5 rounded-full border border-red-100">
                          {err}
                        </span>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
              <button onClick={() => setShowValidationModal(false)} className="w-full bg-slate-900 text-white py-4.5 rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-xl transition-all hover:bg-black active:scale-95">
                Entendi, vou revisar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* PDF PRINT LAYOUT (Hidden on UI) */}
      <div className="print-only bg-white p-8 text-slate-900 font-sans">
        <header className="flex justify-between items-end border-b-4 border-slate-900 pb-8 mb-10">
          <div>
            <h1 className="text-3xl font-black uppercase">Relatório de Análise de Falha</h1>
            <p className="text-blue-600 font-bold uppercase tracking-widest text-xs">Análise de Falhas SWM Brasil - Engenharia de Manutenção</p>
          </div>
          <div className="text-right">
             <p className="text-[10px] font-black text-slate-400 uppercase">Protocolo</p>
             <p className="text-xl font-black">{analysis.id}</p>
          </div>
        </header>

        <section className="grid grid-cols-2 gap-x-12 gap-y-6 bg-slate-50 p-8 rounded-3xl border border-slate-200 mb-8 break-inside-avoid">
           <div><p className="text-[9px] font-black text-slate-400 uppercase">Equipamento</p><p className="text-base font-black">{analysis.equipment || '—'}</p></div>
           <div><p className="text-[9px] font-black text-slate-400 uppercase">Tag / Ativo</p><p className="text-base font-black">{analysis.tag || '—'}</p></div>
           <div><p className="text-[9px] font-black text-slate-400 uppercase">Área</p><p className="text-base font-bold">{analysis.area || '—'}</p></div>
           <div><p className="text-[9px] font-black text-slate-400 uppercase">Data Ocorrência</p><p className="text-base font-bold">{analysis.failureDate || '—'}</p></div>
        </section>

        <section className="mb-10">
          <h2 className="text-lg font-black border-l-4 border-slate-900 pl-4 uppercase mb-4">Investigação Detalhada</h2>
          <div className="space-y-6">
            <div className="bg-white p-6 border rounded-2xl">
              <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Descrição da Falha</p>
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{analysis.description || '—'}</p>
            </div>
            <div className="grid grid-cols-3 gap-4">
               <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="text-[8px] font-black text-slate-400 uppercase">Sintoma</p>
                  <p className="text-xs font-bold">{analysis.symptom || '—'}</p>
               </div>
               <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="text-[8px] font-black text-slate-400 uppercase">Frequência</p>
                  <p className="text-xs font-bold">{analysis.frequency}</p>
               </div>
               <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="text-[8px] font-black text-slate-400 uppercase">Turno</p>
                  <p className="text-xs font-bold">{analysis.shift || '—'}</p>
               </div>
            </div>
          </div>
        </section>

        <section className="mb-10 break-inside-avoid">
          <h2 className="text-lg font-black border-l-4 border-slate-900 pl-4 uppercase mb-4">Causa Raiz (5 Porquês)</h2>
          <div className="space-y-4 mb-6">
            {analysis.whys.map((w, i) => w.trim() && (
              <div key={i} className="flex gap-4 items-center">
                <span className="w-6 h-6 rounded-full bg-slate-900 text-white flex items-center justify-center text-[10px] font-black">{i+1}</span>
                <p className="text-sm font-semibold">{w}</p>
              </div>
            ))}
          </div>
          <div className="bg-blue-900 text-white p-8 rounded-3xl">
             <p className="text-[9px] font-black uppercase opacity-60 mb-1">Causa Raiz Fundamental</p>
             <p className="text-2xl font-black">{analysis.rootCause || 'NÃO IDENTIFICADA'}</p>
          </div>
        </section>

        <section className="mb-10 page-break-before">
          <h2 className="text-lg font-black border-l-4 border-slate-900 pl-4 uppercase mb-4">Plano de Bloqueio</h2>
          <table className="w-full text-left border-collapse border border-slate-200">
             <thead className="bg-slate-900 text-white text-[10px] font-black uppercase">
                <tr>
                   <th className="p-4 border-r border-slate-800">Ação Corretiva/Preventiva</th>
                   <th className="p-4 border-r border-slate-800">Responsável</th>
                   <th className="p-4">Prazo</th>
                </tr>
             </thead>
             <tbody className="text-xs font-semibold">
                {analysis.actions.map(a => (
                  <tr key={a.id} className="border-b border-slate-100">
                    <td className="p-4">{a.description}</td>
                    <td className="p-4">{a.responsible}</td>
                    <td className="p-4">{a.dueDate}</td>
                  </tr>
                ))}
             </tbody>
          </table>
        </section>

        <footer className="mt-20 pt-10 border-t border-slate-200 flex justify-between items-end">
           <div className="text-[8px] font-black text-slate-300 uppercase tracking-widest">Gerado em {new Date().toLocaleString('pt-BR')}</div>
           <div className="w-64 border-t-2 border-slate-900 text-center pt-2">
              <p className="text-[9px] font-black uppercase">{analysis.responsible || 'Responsável Técnico'}</p>
              <p className="text-[8px] font-bold text-slate-400">Assinatura Digital</p>
           </div>
        </footer>
      </div>

      {/* WEB UI */}
      <div className="no-print h-full flex flex-col">
        <header className="bg-slate-900 text-white shadow-xl h-16 md:h-20 flex-shrink-0 z-50">
          <div className="max-w-7xl mx-auto px-4 md:px-6 h-full flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg shadow-blue-900/40">
                <i className="fas fa-microchip text-lg"></i>
              </div>
              <div className="hidden sm:block">
                <h1 className="font-black text-base tracking-tight uppercase leading-none">Análise de Falhas SWM Brasil</h1>
                <p className="text-[8px] text-blue-400 font-black tracking-widest uppercase mt-1">Engenharia de Manutenção</p>
              </div>
            </div>
            <nav className="flex gap-1 sm:gap-3 bg-white/5 p-1 rounded-2xl">
              <button onClick={startNewAnalysis} className={`px-4 py-2.5 rounded-xl transition-all font-black uppercase text-[10px] tracking-wider ${currentStep < StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}>Novo</button>
              <button onClick={() => setCurrentStep(StepId.HISTORY)} className={`px-4 py-2.5 rounded-xl transition-all font-black uppercase text-[10px] tracking-wider ${currentStep === StepId.HISTORY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}>Histórico</button>
              <button onClick={() => setCurrentStep(StepId.DASHBOARD)} className={`px-4 py-2.5 rounded-xl transition-all font-black uppercase text-[10px] tracking-wider ${currentStep === StepId.DASHBOARD ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}>Dash</button>
            </nav>
          </div>
        </header>

        {currentStep < StepId.DASHBOARD && (
          <nav className="bg-white border-b flex-shrink-0 z-40 overflow-x-auto no-scrollbar shadow-sm" aria-label="Passos da análise">
            <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between gap-6 min-w-max">
              {STEPS.map((step, idx) => (
                <React.Fragment key={step.id}>
                  <button onClick={() => setCurrentStep(step.id)} className={`flex flex-col items-center gap-2 transition-all px-2 ${currentStep === step.id ? 'scale-110 opacity-100' : 'opacity-30 hover:opacity-60'}`} aria-current={currentStep === step.id ? 'step' : undefined}>
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs transition-all ${currentStep === step.id ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'bg-slate-100 text-slate-500'}`}>
                      {currentStep > step.id ? <i className="fas fa-check"></i> : step.icon}
                    </div>
                    <span className={`text-[9px] font-black uppercase tracking-widest ${currentStep === step.id ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
                  </button>
                  {idx < STEPS.length - 1 && <div className={`w-12 h-1 rounded-full ${currentStep > idx ? 'bg-blue-600' : 'bg-slate-100'}`} aria-hidden="true"></div>}
                </React.Fragment>
              ))}
            </div>
          </nav>
        )}

        <main id="main-content" className="flex-1 flex flex-col overflow-hidden relative">
          <div id="step-scroll-container" className="flex-1 overflow-y-auto px-4 py-6 md:px-8 custom-scrollbar">
            <div className="max-w-7xl mx-auto">
              <div className="bg-white rounded-[32px] shadow-2xl shadow-slate-200/50 border border-slate-100 p-6 md:p-12 mb-28">
                {renderStepContent()}
              </div>
            </div>
          </div>

          {currentStep < StepId.DASHBOARD && (
            <div className="absolute bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-slate-100 p-5 md:p-8 z-50">
              <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
                <button onClick={handleBack} disabled={currentStep === StepId.IDENTIFICATION} className="flex items-center justify-center gap-2 text-slate-400 font-black uppercase text-[11px] hover:text-slate-900 disabled:opacity-20 transition-all px-5 py-4 min-h-[56px] min-w-[120px]">
                  <i className="fas fa-arrow-left"></i> Voltar
                </button>
                <div className="flex gap-3 flex-1 sm:flex-initial">
                  <button onClick={saveDraft} className="hidden sm:flex items-center justify-center text-slate-600 bg-slate-100 hover:bg-slate-200 px-8 py-4 rounded-2xl font-black text-[11px] uppercase tracking-widest border border-slate-200 min-h-[56px]">Salvar Rascunho</button>
                  {currentStep < StepId.VERIFICATION ? (
                    <button onClick={handleNext} className="flex-1 sm:flex-initial bg-blue-600 hover:bg-blue-700 text-white px-12 py-4.5 rounded-2xl font-black uppercase text-[11px] shadow-2xl shadow-blue-200 transition-all flex items-center justify-center gap-3 min-h-[56px]">
                      Próximo <i className="fas fa-arrow-right"></i>
                    </button>
                  ) : (
                    <button onClick={finalizeAnalysis} className="flex-1 sm:flex-initial bg-slate-900 hover:bg-black text-white px-12 py-4.5 rounded-2xl font-black uppercase text-[11px] shadow-2xl transition-all min-h-[56px]">Finalizar Relatório</button>
                  )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;
